/* 問題バンク⑥：商学部・過去問論点準拠 396問（2006-2026）
   実際の過去問で問われた論点に基づき、問い方はオリジナルで作問。本文複製なし。*/
const QUESTION_BANK6 = [
  {"id": "q6000", "field": "古代", "difficulty": 2, "type": "choice", "question": "3世紀、邪馬台国の女王として魏に朝貢し、「親魏倭王」の称号と金印・銅鏡100枚などを授けられた人物はどれか。", "choices": ["卑弥呼", "壱与(台与)", "神功皇后", "持衰", "難升米"], "answer": 0, "modelAnswer": "", "explanation": "卑弥呼は邪馬台国の女王で、鬼道(呪術)によって国を統治し、239年に魏の皇帝に使いを送って「親魏倭王」の称号と金印紫綬・銅鏡100枚などを授かったと『魏志』倭人伝に記されている。彼女の死後、一時混乱が生じたが、一族の壱与が女王となって再びまとまったとされる。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6001", "field": "古代", "difficulty": 3, "type": "choice", "question": "大和政権下で、大臣(おおおみ)として代々世襲的に国政の中心を担った氏はどれか。", "choices": ["蘇我氏", "物部氏", "大伴氏", "中臣氏", "葛城氏"], "answer": 0, "modelAnswer": "", "explanation": "大和政権では臣・連などの姓を与えられた有力氏族の首長が大臣・大連に任じられて国政を主導した。蘇我氏は大臣として、物部氏・大伴氏は大連として勢力を振るい、6世紀末には蘇我馬子が物部守屋を滅ぼして権勢を強めた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6002", "field": "古代", "difficulty": 2, "type": "short", "question": "603年に聖徳太子が定めた、氏族単位ではなく個人の才能や功績に応じて位階を与える制度を何というか。", "choices": [], "answer": "冠位十二階", "modelAnswer": "冠位十二階", "explanation": "冠位十二階は、従来の氏姓による世襲的な地位継承を改め、徳・仁・礼・信・義・智の6段階をそれぞれ大小に分けた計12階の冠位を個人に与える制度で、有力豪族の首長を天皇中心の秩序に組み込む狙いがあった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6003", "field": "古代", "difficulty": 3, "type": "choice", "question": "大宝律令によって整えられた中央官制において、太政官と並んで祭祀を司った官庁はどれか。", "choices": ["神祇官", "治部省", "民部省", "式部省", "中務省"], "answer": 0, "modelAnswer": "", "explanation": "大宝律令下の中央官制は二官八省からなり、行政全般を統轄する太政官と、祭祀を司る神祇官の二官が並立して置かれた。これは大化改新以来進められた中央集権的な律令国家体制の到達点であった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6004", "field": "古代", "difficulty": 4, "type": "short", "question": "律令官人の子(五位以上)や孫(三位以上)が、父祖の位階に応じて一定の位階を自動的に与えられる制度を何というか。", "choices": [], "answer": "蔭位の制", "modelAnswer": "蔭位の制", "explanation": "蔭位の制は、五位以上の官人の子、三位以上の官人の孫が21歳に達すると、父祖の位階に応じた位を与えられる制度であり、貴族の特権的地位が世襲されていく仕組みを支えた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6005", "field": "古代", "difficulty": 2, "type": "choice", "question": "摂関政治の全盛期を築き、4人の娘を次々に天皇の后妃とし絶大な権勢を振るった人物はどれか。", "choices": ["藤原道長", "藤原基経", "藤原良房", "藤原時平", "藤原忠平"], "answer": 0, "modelAnswer": "", "explanation": "藤原道長は4人の娘を天皇の后妃とし、「この世をば わが世とぞ思ふ」の歌に象徴される絶大な権勢を築いた。子の頼通とともに約半世紀にわたり摂関政治の全盛期を現出した。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6006", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "白河上皇に始まる院政は、譲位した上皇が院庁を拠点として実権を握る統治形態であり、上皇の身辺警護のために北面の武士も組織された。この記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "1086年、白河天皇は幼少の堀河天皇に譲位した後も上皇として実権を握り院政を開始した。院庁が置かれて院宣・院庁下文が政治を動かし、上皇の身辺警護のために北面の武士も組織された。院政は鳥羽・後白河へと継承され、平氏台頭の基盤ともなった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6007", "field": "中世", "difficulty": 2, "type": "choice", "question": "1232年、執権北条泰時が御家人の権利義務や所領相続の基準を定めるために制定した法典はどれか。", "choices": ["御成敗式目", "建武式目", "公事方御定書", "分国法", "禁中並公家諸法度"], "answer": 0, "modelAnswer": "", "explanation": "御成敗式目(貞永式目)は源頼朝以来の武家社会の慣習・道徳に基づいて制定された最初の武家法で、公正な裁判基準を明文化することで御家人社会の秩序維持を図った。同法には所領の知行年紀に関する規定なども含まれていた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6008", "field": "中世", "difficulty": 3, "type": "short", "question": "1297年、幕府が困窮した御家人を救済するために発令し、御家人が売却・質入れした所領の無償返却などを定めた法令を何というか。", "choices": [], "answer": "永仁の徳政令", "modelAnswer": "永仁の徳政令", "explanation": "元寇後の恩賞不足や貨幣経済の浸透、分割相続の繰り返しなどにより困窮した御家人を救うため、幕府は1297年に永仁の徳政令を発し、御家人が売却・質入れした所領を無償で取り戻せるとした。しかし効果は一時的で、かえって経済的混乱を招いた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6009", "field": "社会経済", "difficulty": 3, "type": "short", "question": "室町時代、日本海海運の拠点として若狭の小浜とともに栄えた越前国の港はどこか。", "choices": [], "answer": "敦賀", "modelAnswer": "敦賀", "explanation": "敦賀は越前国の港で、若狭の小浜とともに日本海海運の重要拠点として栄え、畿内と北陸・蝦夷地方面を結ぶ物資の集散地となった。日本海の廻船問屋を通じて各地の産物が畿内へ運ばれた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6010", "field": "中世", "difficulty": 3, "type": "choice", "question": "近江国堅田の本福寺を中心に一揆を展開した、蓮如の布教により勢力を拡大した仏教宗派はどれか。", "choices": ["浄土真宗(一向宗)", "浄土宗", "日蓮宗(法華宗)", "時宗", "天台宗"], "answer": 0, "modelAnswer": "", "explanation": "蓮如の精力的な布教活動により近江・北陸などで勢力を拡大した浄土真宗(一向宗)は、農民・国人・坊主らが結びついた一向一揆の母体となった。堅田の本福寺はその近江における拠点の一つであった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6011", "field": "社会経済", "difficulty": 2, "type": "short", "question": "織田信長が城下町の商業発展を図るため、座の特権を廃止して自由な商取引を認めた政策を何というか。", "choices": [], "answer": "楽市・楽座", "modelAnswer": "楽市・楽座", "explanation": "織田信長は安土などの城下町で楽市・楽座令を出し、座の独占的特権を廃止して新興商人の自由な営業を認めることで、城下町の商業繁栄と経済統制の強化を図った。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6012", "field": "外交史", "difficulty": 3, "type": "choice", "question": "江戸幕府が当初ポルトガル船に適用し、1631年には中国船にも適用を広げた、輸入生糸を特定商人仲間に一括購入させる制度はどれか。", "choices": ["糸割符制度", "朱印船貿易制度", "勘合貿易制度", "南蛮貿易制度", "俵物貿易制度"], "answer": 0, "modelAnswer": "", "explanation": "糸割符制度は特定の商人仲間(糸割符仲間)に輸入生糸を一括購入させ、価格統制と貿易利潤の国内還元を図る制度で、当初ポルトガル船に適用されたのち1631年に中国船にも及んだ。中国船は糸割符制度を嫌って長崎を避け他の港に入港することもあった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6013", "field": "外交史", "difficulty": 3, "type": "short", "question": "新井白石が1715年、金銀の海外流出を防ぐために長崎貿易の貿易額・船数を制限して定めた法令を何というか。", "choices": [], "answer": "海舶互市新例", "modelAnswer": "海舶互市新例", "explanation": "海舶互市新例(長崎新令・正徳新例)は、金銀の海外流出を防ぐため中国船・オランダ船の貿易額や来航船数を制限した法令で、新井白石の正徳の治の一環として発令された。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6014", "field": "外交史", "difficulty": 3, "type": "choice", "question": "1609年、対馬藩主宗氏が朝鮮との間に結び、釜山の倭館を窓口に貿易を再開した条約はどれか。", "choices": ["己酉約条", "日朝修好条規", "日朝通商章程", "江華条約", "甲申条約"], "answer": 0, "modelAnswer": "", "explanation": "己酉約条は対馬藩主宗氏が朝鮮との間で結んだ条約で、釜山に倭館を置き対馬藩を窓口として貿易を再開することを定めた。これにより江戸時代を通じて朝鮮との交流(朝鮮通信使の来日など)が継続した。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6015", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "1897年に制定された貨幣法により、日本は日清戦争の賠償金を準備金として金本位制を採用し、円の対外的信用が高まった。この記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "日清戦争の賠償金を準備金として、1897年に貨幣法が制定され金本位制が確立した。これにより円の対外信用が高まり、先進資本主義国からの資本導入が容易になった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6016", "field": "外交史", "difficulty": 4, "type": "essay", "question": "1905年に締結されたポーツマス条約で日本が獲得した権益の内容を、以下の語句をすべて用いて40字以内で説明せよ。なお、句読点も1字として計算せよ。 語句：韓国 旅順・大連 南満州鉄道", "choices": [], "answer": "", "modelAnswer": "日本は韓国における指導権、旅順・大連の租借権、南満州鉄道の利権を獲得した。", "explanation": "ポーツマス条約はアメリカ大統領セオドア=ローズヴェルトの斡旋により締結され、日本は韓国における指導・監督権、旅順・大連の租借権、南満州の鉄道利権、樺太南部などを獲得した。ただし賠償金は得られず、これに不満を持つ民衆が日比谷焼打ち事件を起こした。採点観点は韓国指導権・旅順大連租借権・南満州鉄道利権の3点が盛り込まれているかどうかである。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6017", "field": "外交史", "difficulty": 3, "type": "short", "question": "1915年、第一次世界大戦のさなかに日本が中国の袁世凱政権に突きつけ、山東省の旧ドイツ権益継承や南満州権益の強化などを要求した文書を何というか。", "choices": [], "answer": "二十一ヵ条の要求", "modelAnswer": "二十一ヵ条の要求", "explanation": "二十一ヵ条の要求は、山東省の旧ドイツ権益の継承、南満州・東部内蒙古における権益強化などを含み、袁世凱政権はその大部分を受諾した。これは中国における排日運動を激化させる要因となった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6018", "field": "近代", "difficulty": 3, "type": "choice", "question": "1931年9月、関東軍が南満州鉄道の線路を爆破し、これを中国側の仕業として軍事行動を開始するきっかけとなった事件はどれか。", "choices": ["柳条湖事件", "盧溝橋事件", "張作霖爆殺事件", "済南事件", "西安事件"], "answer": 0, "modelAnswer": "", "explanation": "関東軍参謀の石原莞爾らは柳条湖で南満州鉄道の線路を爆破し(柳条湖事件)、これを中国軍の行為として軍事行動を開始した。政府の不拡大方針を無視して戦線は拡大し、満州事変から満州国建国へと至った。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6019", "field": "現代", "difficulty": 2, "type": "short", "question": "1955年、左右に分裂していた社会党の統一に対抗する形で保守合同により結成された政党を何というか。", "choices": [], "answer": "自由民主党", "modelAnswer": "自由民主党", "explanation": "1955年、左右に分裂していた日本社会党が統一されると、これに対抗して自由党と日本民主党が合同し自由民主党が結成された。以後、自民党と社会党が対峙する「55年体制」が長く続くことになった。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6020", "field": "現代", "difficulty": 3, "type": "essay", "question": "池田勇人内閣が掲げた「国民所得倍増計画」について、その内容を35字以内で説明せよ。なお、句読点も1字として計算せよ。", "choices": [], "answer": "", "modelAnswer": "今後10年間で国民所得を2倍にすることを目標とした経済成長計画。", "explanation": "池田内閣は安保闘争後の政治的混乱を収拾するため「寛容と忍耐」を掲げつつ、今後10年間で国民所得を2倍にするという国民所得倍増計画を打ち出し、高度経済成長を後押しした。この時期には東海道新幹線の建設や東京オリンピックの開催準備も進められた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6021", "field": "外交史", "difficulty": 3, "type": "short", "question": "土佐の漁民で1841年に漂流しアメリカ船に救助され、帰国後は幕末に通訳・航海士として活躍した人物は誰か。", "choices": [], "answer": "中浜万次郎(ジョン万次郎)", "modelAnswer": "中浜万次郎(ジョン万次郎)", "explanation": "中浜万次郎は漂流後アメリカで教育を受け、1854年に帰国した。1860年の日米修好通商条約批准のための遣米使節に際しては軍艦咸臨丸に乗り込み、通訳・航海士として太平洋横断に貢献した。同船には後に江戸城無血開城に尽力する幕臣勝海舟も艦長格として乗船していた。（商学部2006年で問われた論点）", "source": "2006", "faculty": "商学部"},
  {"id": "q6040", "field": "古代", "difficulty": 2, "type": "choice", "question": "672年、天智天皇の死後、皇位継承をめぐって大友皇子と大海人皇子との間で起こった内乱はどれか。", "choices": ["壬申の乱", "乙巳の変", "磐井の乱", "治承・寿永の乱", "応天門の変"], "answer": 0, "modelAnswer": "", "explanation": "壬申の乱は天智天皇の子大友皇子と、天智の弟大海人皇子との間で起きた皇位継承をめぐる内乱である。近江大津宮の大友皇子は敗れ、東国豪族の支持を得た大海人皇子が勝利して即位し天武天皇となった。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6041", "field": "古代", "difficulty": 3, "type": "short", "question": "740年、大宰少弐であった人物が、時の政権(橘諸兄・玄昉・吉備真備ら)への不満から九州で起こした反乱を何というか。", "choices": [], "answer": "藤原広嗣の乱", "modelAnswer": "藤原広嗣の乱", "explanation": "藤原広嗣は大宰少弐として左遷された不満から、玄昉・吉備真備の排除を求めて九州で挙兵したが、政府軍に鎮圧され殺害された。この混乱の中、聖武天皇は恭仁京など都を転々と移した。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6042", "field": "古代", "difficulty": 3, "type": "short", "question": "764年、道鏡を除こうとして反乱を起こし、近江で討たれた人物は誰か(恵美押勝とも呼ばれる)。", "choices": [], "answer": "藤原仲麻呂", "modelAnswer": "藤原仲麻呂", "explanation": "藤原仲麻呂(恵美押勝)は孝謙太上天皇の信任を得た道鏡の台頭に危機感を強め挙兵したが、失敗して近江で討たれた(恵美押勝の乱)。この後、道鏡の権勢はさらに強まり、太政大臣禅師・法王にまで昇った。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6043", "field": "古代", "difficulty": 2, "type": "choice", "question": "桓武天皇のもとで胆沢城を築かせ、征夷大将軍として蝦夷討伐に大きな戦果を挙げた人物はどれか。", "choices": ["坂上田村麻呂", "文室綿麻呂", "大伴家持", "藤原緒嗣", "菅野真道"], "answer": 0, "modelAnswer": "", "explanation": "坂上田村麻呂は征夷大将軍として蝦夷の族長阿弖流為を帰順させるなど大きな戦果を挙げ、胆沢城・志波城を築いて律令国家の東北支配を進めた。その後、桓武天皇は「軍事と造作」の一つである征夷の継続を断念した。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6044", "field": "古代", "difficulty": 3, "type": "choice", "question": "10世紀、関東で反乱を起こし坂東諸国を占領して「新皇」を自称した人物はどれか。", "choices": ["平将門", "藤原純友", "平忠常", "安倍頼時", "源義家"], "answer": 0, "modelAnswer": "", "explanation": "平将門は関東で反乱を起こし坂東諸国を占領して「新皇」を自称したが、平貞盛・藤原秀郷らに討たれた。同時期、西国では藤原純友が瀬戸内海で反乱を起こしており、両者をあわせて承平・天慶の乱と呼ぶ。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6045", "field": "外交史", "difficulty": 3, "type": "short", "question": "1019年、九州北部沿岸に女真族と考えられる勢力が来襲し、藤原隆家らが撃退した事件を何というか。", "choices": [], "answer": "刀伊の入寇", "modelAnswer": "刀伊の入寇", "explanation": "刀伊の入寇は、女真族とみられる集団が壱岐・対馬を襲い九州北部に来襲した事件で、大宰権帥であった藤原隆家が在地の武士を指揮して撃退した。藤原隆家はこの戦いの傷がもとで大宰府で没したと伝えられる。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6046", "field": "古代", "difficulty": 3, "type": "short", "question": "11世紀後半、奥羽で勢力を拡大した清原氏の内紛に源義家が介入して収めた戦乱を何というか。", "choices": [], "answer": "後三年合戦", "modelAnswer": "後三年合戦", "explanation": "前九年合戦で安倍氏を滅ぼした清原氏は奥羽で勢力を拡大したが、その後内紛が起こり、源義家が介入してこれを鎮めた(後三年合戦)。以後、清原氏の子孫は奥州藤原氏として平泉を中心に栄えたが、のちに源頼朝によって滅ぼされた。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6047", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "1221年の承久の乱に敗れた後鳥羽上皇は隠岐に配流され、幕府は京都に六波羅探題を新設して朝廷監視と西国支配を強化した。この記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "承久の乱に敗れた後鳥羽上皇は隠岐に配流され、仲恭天皇に代えて後堀河天皇が擁立された。幕府は京都に六波羅探題を新設し、朝廷監視と西国支配を強化するとともに、上皇方の所領には多くの新補地頭が任命された。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6048", "field": "中世", "difficulty": 4, "type": "short", "question": "鎌倉幕府後期、得宗(北条氏嫡流)の家臣である御内人が実権を握った政治体制を何というか。", "choices": [], "answer": "得宗専制政治", "modelAnswer": "得宗専制政治", "explanation": "元寇後、御家人社会の窮乏や北条氏への権力集中が進み、得宗の家臣である御内人(内管領平頼綱など)が幕政を主導する得宗専制政治が確立した。霜月騒動で有力御家人安達泰盛が滅ぼされたのはその象徴的な事件である。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6049", "field": "中世", "difficulty": 4, "type": "essay", "question": "1185年に源頼朝が朝廷から認められた地方支配のしくみについて、以下の語句をすべて用いて35字以内で説明せよ。なお、句読点も1字として計算せよ。 語句：守護 地頭 国ごと", "choices": [], "answer": "", "modelAnswer": "国ごとに守護、荘園・公領ごとに地頭を任命する権利を得た。", "explanation": "1185年、源頼朝は文治の勅許により国ごとに守護、荘園・公領ごとに地頭を設置する権利を朝廷に認めさせた。これにより東国だけでなく全国に及ぶ軍事支配・経済基盤が整い、鎌倉幕府の全国政権化が進んだ。採点観点は守護・地頭の設置単位が国ごと・荘園公領ごとと正しく書き分けられているかである。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6050", "field": "中世", "difficulty": 3, "type": "short", "question": "1392年、足利義満の斡旋によって南朝の後亀山天皇が北朝の後小松天皇に神器を譲る形で実現した出来事を何というか。", "choices": [], "answer": "南北朝の合体", "modelAnswer": "南北朝の合体", "explanation": "足利義満は3代将軍として幕府権力を確立し、1392年には南朝の後亀山天皇が北朝の後小松天皇に神器を譲る形で南北朝の合体を実現し、長く続いた分裂状態を終わらせた。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6051", "field": "文化史", "difficulty": 3, "type": "choice", "question": "足利義満が北山に営んだ山荘に建立され、1層が寝殿造、2層が和様の仏堂造、3層が禅宗様式という3つの様式を重ねた建築物はどれか。", "choices": ["金閣", "銀閣", "飛雲閣", "東求堂", "慈照寺観音殿"], "answer": 0, "modelAnswer": "", "explanation": "金閣は足利義満が営んだ北山山荘(のちの鹿苑寺)の中核建築で、1層が寝殿造、2層が和様の仏堂造、3層が禅宗様式という異なる様式を重ねた点に特徴があり、公家文化と武家文化・禅宗文化の融合を象徴する北山文化を代表する建築である。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6052", "field": "社会経済", "difficulty": 3, "type": "short", "question": "5代将軍徳川綱吉が発した、動物の殺生・虐待禁止や捨て子の禁止などを内容とする一連の法令を総称して何というか。", "choices": [], "answer": "生類憐みの令", "modelAnswer": "生類憐みの令", "explanation": "生類憐みの令は犬をはじめとする動物の殺生・虐待を禁じ、捨て子の禁止も含む一連の法令の総称で、綱吉の民衆統制策の延長上にあると同時に、動物愛護思想の広がりや肉食忌避の風潮にも影響した。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6053", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "江戸時代後期に普及し、それまでの扱箸に比べて脱穀の効率を大きく向上させた農具はどれか。", "choices": ["千歯扱き", "唐箕", "踏車", "備中鍬", "石包丁"], "answer": 0, "modelAnswer": "", "explanation": "千歯扱きは17世紀後期以降に普及した脱穀用農具で、それまで用いられていた扱箸に比べて格段に作業効率を高め、新田開発による耕地拡大とあわせて農業生産力の向上に寄与した。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6054", "field": "社会経済", "difficulty": 3, "type": "short", "question": "豊臣秀吉が1588年に発令し、農民から武器を没収して一揆を防止しようとした法令を何というか。", "choices": [], "answer": "刀狩令", "modelAnswer": "刀狩令", "explanation": "刀狩令は農民の武器所持を禁じて兵農分離を進めるとともに、没収した刀は方広寺大仏建立の釘・かすがいに用いるとの名目で示された。武力による自力救済を否定し、百姓は農業耕作に専念すべきだと説いた法令である。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6055", "field": "文化史", "difficulty": 3, "type": "short", "question": "1880年代、フランス法を中心とした教育を行い、現在の明治大学の前身となった私立法律学校を何というか。", "choices": [], "answer": "明治法律学校", "modelAnswer": "明治法律学校", "explanation": "1880年代、法律を学べる私立学校の開設が相次ぎ、それぞれ特定の国の法学の影響を強く受けていた。明治法律学校はフランス法教育を中心とし、現在の明治大学の前身となった。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6056", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "明治政府が発した神仏分離令は、神道と仏教の分離を意図したものであったが、これが全国的な廃仏毀釈運動を引き起こす一因となった。この記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "明治政府は神仏分離令を出して神道と仏教を分離しようとしたが、これが全国的な廃仏毀釈運動を引き起こし、仏教は一時大きな打撃を受けた。その後、島地黙雷らの努力により仏教は近代化を進め国民生活に定着していった。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6057", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "1882年に設立され、以後銀行券の発行業務を独占することになった中央銀行はどれか。", "choices": ["日本銀行", "横浜正金銀行", "日本勧業銀行", "日本興業銀行", "第一国立銀行"], "answer": 0, "modelAnswer": "", "explanation": "国立銀行条例のもとで設立された多数の国立銀行が独自の銀行券を発行していたが、1882年に日本銀行が設立されて発券業務を独占し、1883年の条例再改正で国立銀行は発券を行わない普通銀行へ転換した。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6058", "field": "社会経済", "difficulty": 4, "type": "short", "question": "1927年、大蔵大臣の失言をきっかけに銀行の取り付け騒ぎが全国に広がった経済混乱を何というか。", "choices": [], "answer": "金融恐慌", "modelAnswer": "金融恐慌", "explanation": "1927年、片岡直温蔵相の失言をきっかけに銀行の経営不安が表面化し、取り付け騒ぎが全国に広がった(昭和金融恐慌)。震災手形の処理をめぐる混乱もその一因で、若槻礼次郎内閣は総辞職に追い込まれた。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6059", "field": "近代", "difficulty": 3, "type": "short", "question": "天皇機関説を唱え、統治権は法人としての国家に属し天皇はその最高機関として行使するという学説を展開した憲法学者は誰か。", "choices": [], "answer": "美濃部達吉", "modelAnswer": "美濃部達吉", "explanation": "美濃部達吉は『憲法撮要』などで天皇機関説を唱え、統治権は法人としての国家に属し天皇はその最高機関として行使するという学説を展開した。大正デモクラシー期には憲法学説上有力化し、統帥権等を利用して勢力拡大を図る軍に対する議会の抑制の理論的支柱となった。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6060", "field": "近代", "difficulty": 4, "type": "essay", "question": "1925年に成立した普通選挙法と、同年に制定された治安維持法との関係について、35字以内で説明せよ。なお、句読点も1字として計算せよ。", "choices": [], "answer": "", "modelAnswer": "有権者急増による社会主義運動の広がりを警戒し、同時に治安維持法を制定した。", "explanation": "加藤高明内閣のもとで1925年に普通選挙法が成立し、直接国税による制限が撤廃され25歳以上の男子すべてに衆議院議員の選挙権が与えられた。有権者の急増にともなう社会主義運動の伸張を警戒し、国体の変革または私有財産制度の否認を目的とする結社を取り締まる治安維持法が同時に制定された。採点観点は有権者増加と社会主義運動への警戒、治安維持法との同時制定という因果関係が示せているかである。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6061", "field": "現代", "difficulty": 4, "type": "short", "question": "1949年、GHQの指示のもとで銀行家ドッジが実施した、単一為替レートの設定などを含む財政金融引き締め政策を何というか。", "choices": [], "answer": "ドッジ・ライン", "modelAnswer": "ドッジ・ライン", "explanation": "ドッジ・ラインは超均衡予算の編成や1ドル=360円の単一為替レート設定などを内容とし、経済安定九原則の実施を徹底することでインフレを収束させ日本経済の自立を図った政策である。同時期にはシャウプ勧告に基づく税制改革も行われた。（商学部2007年で問われた論点）", "source": "2007", "faculty": "商学部"},
  {"id": "q6080", "field": "古代", "difficulty": 3, "type": "choice", "question": "『魏志』倭人伝によれば、女王国が諸国を検察するために伊都国に置いたとされる官職はどれか。", "choices": ["一大率", "大夫", "持衰", "国造", "太守"], "answer": 0, "modelAnswer": "", "explanation": "一大率は女王卑弥呼が伊都国に置いた官で、諸国を検察し諸国から恐れられたと『魏志』倭人伝に記されている。中国の刺史のような監察機能を持っていたと考えられている。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6081", "field": "古代", "difficulty": 3, "type": "short", "question": "8世紀、皇室の財政収入を目的として、天皇の勅旨によって開墾が奨励された田地を何というか。", "choices": [], "answer": "勅旨田", "modelAnswer": "勅旨田", "explanation": "勅旨田は天皇の勅旨によって開発された田地で、皇室の財源確保を目的とし、公地公民制の原則を崩す要因の一つとなった。延喜の荘園整理令ではこの勅旨田も規制の対象とされた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6082", "field": "古代", "difficulty": 2, "type": "short", "question": "平安京の左京・右京に置かれ、市司が監督にあたった官設の商業施設を何というか。", "choices": [], "answer": "東市・西市", "modelAnswer": "東市・西市", "explanation": "平安京には左京・右京にそれぞれ官設の市(東市・西市)が置かれ、市司がこれを監督して物価の調整などにあたった。地方から運脚によって京進された物資の一部もここで放出された。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6083", "field": "文化史", "difficulty": 3, "type": "short", "question": "平安京や諸国の市の付近で念仏を広め、「市聖」と呼ばれた僧は誰か。", "choices": [], "answer": "空也", "modelAnswer": "空也", "explanation": "空也は平安中期に諸国を遍歴して念仏を広め、市中で貧者や病者の救済にもあたったことから「市聖」「阿弥陀聖」と呼ばれた。その事績は後世の仏教説話集にも取り上げられている。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6084", "field": "外交史", "difficulty": 3, "type": "choice", "question": "10世紀初め、中国で唐が滅亡した後、五代十国の分裂を経て中国を統一した王朝はどれか。", "choices": ["宋", "高麗", "遼(契丹)", "金", "元"], "answer": 0, "modelAnswer": "", "explanation": "唐は907年に滅亡し、五代十国の分裂期を経て960年に宋(北宋)が建国され中国を統一した。東アジアではこの時期、新羅の滅亡と高麗の成立などもあり、周辺諸国が大きく変動する時代となった。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6085", "field": "外交史", "difficulty": 3, "type": "short", "question": "平清盛が日宋貿易を推進するため修築し、瀬戸内海航路と結びつけた摂津国の港を何というか。", "choices": [], "answer": "大輪田泊", "modelAnswer": "大輪田泊", "explanation": "平清盛は日宋貿易を推進するため、摂津の大輪田泊を修築して瀬戸内海航路と結びつけ、貿易船の往来を活発化させた。これにより宋銭や陶磁器が大量に輸入され、日本の貨幣経済にも大きな影響を与えた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6086", "field": "中世", "difficulty": 2, "type": "short", "question": "1232年に北条泰時が制定した、51箇条からなる武家最初の成文法を何というか。", "choices": [], "answer": "御成敗式目(貞永式目)", "modelAnswer": "御成敗式目(貞永式目)", "explanation": "御成敗式目は51箇条からなり、源頼朝以来の先例や武家社会の慣習・道徳に基づいて制定された。公平な裁判基準を明文化することを目的とし、後の室町・戦国期の武家法にも影響を与えた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6087", "field": "中世", "difficulty": 4, "type": "short", "question": "1350年から52年にかけて、足利直義と執事高師直の対立を発端に室町幕府内部で起こった内乱を何というか。", "choices": [], "answer": "観応の擾乱", "modelAnswer": "観応の擾乱", "explanation": "観応の擾乱は足利直義と高師直の対立に端を発し、やがて足利尊氏・直義兄弟の争いに発展した内乱で、南朝方も巻き込みながら長期化し、室町幕府の権力構造に大きな影響を与えた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6088", "field": "中世", "difficulty": 4, "type": "short", "question": "室町幕府が、荘園・公領の年貢の半分を軍費として守護に徴収させることを認めた法令を何というか。", "choices": [], "answer": "半済令", "modelAnswer": "半済令", "explanation": "半済令は当初近江・美濃・尾張などの特定国において観応の擾乱期の軍事的必要から出されたが、次第に全国的・恒久的なものとなり、守護が荘園・公領を侵食して守護大名化する経済的基盤となった。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6089", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "応仁の乱は細川勝元と山名持豊(宗全)の対立を背景に発生し、この戦乱を通じて下剋上の風潮が強まった。この記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "応仁の乱は細川勝元(東軍)と山名持豊(西軍)の対立に将軍家・畠山氏・斯波氏の家督争いが絡んで1467年に勃発し、京都は戦火で荒廃した。この戦乱を通じて下剋上の風潮が強まり、戦国時代へと移行していく契機となった。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6090", "field": "社会経済", "difficulty": 3, "type": "short", "question": "江戸時代、下総国の名主で、藩主の苛政を将軍に直訴し、後世義民として顕彰された人物として伝えられるのは誰か。", "choices": [], "answer": "佐倉惣五郎(木内惣五郎)", "modelAnswer": "佐倉惣五郎(木内惣五郎)", "explanation": "佐倉惣五郎は下総佐倉藩領の名主で、藩主堀田氏の苛政を将軍に直訴して領民を救ったが処刑されたと伝えられる。史実としての一次史料は乏しいものの、近世後期には義民伝承として広まり、歌舞伎などの題材にもなった。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6091", "field": "文化史", "difficulty": 3, "type": "short", "question": "出雲の阿国が創始したとされる、踊りや歌を交えた芸能に始まり、後に成人男性中心の芸能として発展した近世の演劇を何というか。", "choices": [], "answer": "歌舞伎", "modelAnswer": "歌舞伎", "explanation": "歌舞伎は「傾く(かぶく)」という異様な風体を意味する語を語源とし、出雲の阿国が創始したかぶき踊りに始まるとされる。当初の女歌舞伎・若衆歌舞伎は風紀上の理由で幕府に禁止され、成人男性による野郎歌舞伎へと発展した。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6092", "field": "文化史", "difficulty": 3, "type": "short", "question": "江戸時代後期、古典の実証的研究を通じて日本古来の精神を明らかにしようとした学問を何というか。", "choices": [], "answer": "国学", "modelAnswer": "国学", "explanation": "国学は賀茂真淵・本居宣長らによって発展した学問で、儒教・仏教渡来以前の日本固有の精神を古典研究から明らかにしようとした。江戸後期には村役人や豪農など地域有力者にも広く受容された。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6093", "field": "社会経済", "difficulty": 3, "type": "short", "question": "江戸時代末期、困窮した民衆が豪農・豪商を打ちこわしの対象とし、一揆勢が「世直し大明神」と呼ばれることもあった一揆を何というか。", "choices": [], "answer": "世直し一揆", "modelAnswer": "世直し一揆", "explanation": "世直し一揆は幕末の社会不安の中で頻発した民衆蜂起で、困窮した百姓や都市民が豪農・豪商を打ちこわしの対象とし、一揆勢が「世直し大明神」と称えられることもあった。これは後の自由民権運動にもつながる民衆の政治的自覚の一端とされる。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6094", "field": "外交史", "difficulty": 3, "type": "short", "question": "1871年、条約改正の予備交渉などを目的として岩倉具視を全権大使として欧米に派遣された使節団を何というか。", "choices": [], "answer": "岩倉使節団", "modelAnswer": "岩倉使節団", "explanation": "岩倉具視を全権大使とする岩倉使節団は、大久保利通・木戸孝允らを副使とし、女子留学生も含めて欧米に派遣されたが、条約改正の予備交渉は不調に終わった。使節団帰国後、太陽暦の採用など近代化政策が加速した。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6095", "field": "外交史", "difficulty": 3, "type": "short", "question": "1891年、来日中のロシア皇太子ニコライが滋賀県大津で警備の巡査に襲われ負傷し、外相青木周蔵が引責辞任する事態となった事件を何というか。", "choices": [], "answer": "大津事件", "modelAnswer": "大津事件", "explanation": "大津事件はロシア皇太子ニコライが滋賀県大津で巡査津田三蔵に襲撃された事件で、政府はロシアとの関係悪化を恐れ大審院に圧力をかけたが、児島惟謙の対応により司法の独立が守られた。外相青木周蔵はこの事態の責任を取り辞職した。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6096", "field": "外交史", "difficulty": 3, "type": "short", "question": "1894年、外務大臣として日英通商航海条約を締結し、領事裁判権の撤廃(法権回復)を実現した人物は誰か。", "choices": [], "answer": "陸奥宗光", "modelAnswer": "陸奥宗光", "explanation": "陸奥宗光は第2次伊藤博文内閣の外相として日英通商航海条約を締結し、領事裁判権の撤廃という長年の懸案を実現した。同条約は日清戦争開戦直前の調印であり、他の欧米諸国とも同内容の条約が結ばれ、1899年の条約実施により法権回復が果たされた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6097", "field": "外交史", "difficulty": 4, "type": "short", "question": "1905年、日露戦争後に締結され、韓国の外交権を接収して統監府の設置を定めた条約を何というか。", "choices": [], "answer": "第2次日韓協約", "modelAnswer": "第2次日韓協約", "explanation": "第2次日韓協約(乙巳条約)により韓国は外交権を接収され保護国化されるとともに、漢城に統監府が置かれ伊藤博文が初代統監に就いた。これに先立つ第1次日韓協約(1904年)では日本推薦の財政・外交顧問を置くことが強制されていた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6098", "field": "近代", "difficulty": 4, "type": "short", "question": "大日本帝国憲法の起草にあたり、伊藤博文がウィーンで君主権の強い立憲君主制の理論を学んだドイツ人国法学者は誰か。", "choices": [], "answer": "シュタイン(ローレンツ・フォン・シュタイン)", "modelAnswer": "シュタイン(ローレンツ・フォン・シュタイン)", "explanation": "伊藤博文は憲法調査のため渡欧し、ウィーン大学のシュタインやベルリン大学のグナイストらからドイツ流の国法学を学び、君主権の強い立憲君主制を志向する大日本帝国憲法の起草に反映させた。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6099", "field": "外交史", "difficulty": 3, "type": "choice", "question": "1895年、日清戦争の講和条約で日本が獲得した遼東半島の返還をロシア・ドイツ・フランスが求めた出来事はどれか。", "choices": ["三国干渉", "九カ国条約", "日英同盟", "二十一ヵ条要求", "ポーツマス条約"], "answer": 0, "modelAnswer": "", "explanation": "三国干渉によって日本は遼東半島を清国に返還せざるを得なくなった。その数年後、ロシアは自ら旅順・大連を租借し、ドイツは膠州湾を、フランスは広州湾をそれぞれ租借するなど、列強による中国分割が進んだ。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6100", "field": "近代", "difficulty": 3, "type": "short", "question": "1937年7月、北京郊外で日中両軍が衝突し、日中戦争の発端となった事件を何というか。", "choices": [], "answer": "盧溝橋事件", "modelAnswer": "盧溝橋事件", "explanation": "盧溝橋事件は北京郊外の盧溝橋付近で日中両軍が衝突した事件で、近衛文麿内閣は当初不拡大方針を示したものの軍部強行派の圧力で戦線を拡大し、宣戦布告のないまま日中戦争が長期化する契機となった。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6101", "field": "現代", "difficulty": 4, "type": "essay", "question": "第二次世界大戦後にGHQが実施した財閥解体の方法について、以下の語句をすべて用いて35字以内で説明せよ。なお、句読点も1字として計算せよ。 語句：持株会社 株式 没収", "choices": [], "answer": "", "modelAnswer": "財閥家族や持株会社の株式を没収し、一般に売却して所有を分散させた。", "explanation": "持株会社整理委員会は、財閥家族や持株会社から株式を没収し、それを一般に売却・移管することで株式所有の分散を図る機関として設置された。GHQはこれにより日本の軍事的冒険主義の経済的基盤とみなした財閥の資本的支配網の解体を進めた。採点観点は株式の没収と一般への売却による所有分散という因果関係が示せているかである。（商学部2008年で問われた論点）", "source": "2008", "faculty": "商学部"},
  {"id": "q6120", "field": "古代", "difficulty": 3, "type": "short", "question": "743年に発布され、それまでの三世一身法に代わって開墾地の永年私有を認めた法令を何というか。", "choices": [], "answer": "墾田永年私財法", "explanation": "743年(天平15年)、聖武天皇のもとで墾田永年私財法が発布された。三世一身法(723年)による期限付きの墾田私有では開墾が進まなかったことを受け、身分に応じた面積制限のもとで墾田の永年私有を認めたものである。これにより貴族・寺社・地方豪族による開墾が進んで初期荘園成立の契機となった一方、公地公民制は実質的に崩れていった。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "墾田永年私財法"},
  {"id": "q6121", "field": "古代", "difficulty": 4, "type": "choice", "question": "桓武天皇の政治に関する記述として誤っているものを1つ選べ。", "choices": ["平城京から長岡京へ、ついで平安京へと二度遷都を行った", "国司交替の不正を監督する勘解由使を新設した", "軍団を廃止し郡司の子弟らを健児とする兵制へ転換した", "弟の早良親王を廃太子とし、その怨霊を鎮めるため崇道天皇の号を追贈した", "造都事業の中心を担ったのは藤原仲麻呂であった"], "answer": 4, "explanation": "桓武天皇は平城京から長岡京、さらに平安京へと遷都し、勘解由使の設置や健児制への転換など律令制の立て直しを進めた。弟の早良親王は長岡京造営中の事件に連座して廃太子・配流となり、その死後に怨霊として恐れられたため崇道天皇と追号された。造都事業で中心的役割を果たしたのは藤原種継らであり、藤原仲麻呂は桓武天皇の即位以前、764年の乱で滅んだ人物であるため誤り。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6122", "field": "文化史", "difficulty": 3, "type": "short", "question": "桓武天皇の時代に編纂され、六国史の中で『日本書紀』に次いで2番目に位置づけられる編年体の勅撰国史は何か。", "choices": [], "answer": "続日本紀", "explanation": "『続日本紀』は文武天皇から桓武天皇初期までを扱う編年体の勅撰史書で、六国史の第2番目にあたる。桓武朝で完成し、菅野真道らが編纂に関わった。奈良時代の政治・仏教政策を知るための基本史料である。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "続日本紀"},
  {"id": "q6123", "field": "古代", "difficulty": 2, "type": "truefalse", "question": "平城京には南北に朱雀大路が通り、都の中央部には官営の東市・西市が置かれて商業活動の場となっていた。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "平城京は唐の長安城にならった条坊制の都城で、都を左京・右京に分ける朱雀大路が南北に通っていた。市司の管理のもとで東市・西市が設けられ、官人や庶民の物資交換の場となった。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6124", "field": "中世", "difficulty": 3, "type": "short", "question": "1086年に堀河天皇に譲位した後、上皇として院庁を拠点に政治の実権を握り、院政を開始した人物は誰か。", "choices": [], "answer": "白河上皇(白河天皇)", "explanation": "白河天皇は1086年に幼少の堀河天皇に譲位し、みずからは上皇(治天の君)として院庁で政務を行う院政を開始した。院庁下文や院宣が国政に強い効力をもつようになり、荘園整理のための記録荘園券契所も院政期に設置された。摂関家に代わり天皇家が実権を握るこの政治形態は鳥羽・後白河へと継承された。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "白河上皇(白河天皇)"},
  {"id": "q6125", "field": "古代", "difficulty": 4, "type": "choice", "question": "藤原道長に関する記述として正しいものを1つ選べ。", "choices": ["関白に就任し、その地位から政務を主導した", "娘の彰子を村上天皇の中宮とした", "日記『御堂関白記』を著した", "平等院鳳凰堂を建立した", "安和の変で源高明を失脚させた首謀者であった"], "answer": 2, "explanation": "藤原道長は生涯関白には就任せず、内覧や摂政の地位から権力をふるった。娘の彰子は一条天皇の中宮であり、村上天皇の時代は道長の生誕以前にあたるため誤り。平等院鳳凰堂は子の頼通の建立であり、安和の変(969年)も道長がまだ幼少の時期の出来事である。道長自身が著した日記が『御堂関白記』であり、これが正しい。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6126", "field": "文化史", "difficulty": 3, "type": "short", "question": "鎌倉時代初期、天台座主を務めた慈円が著し、「道理」の観念によって歴史の推移を解釈しようとした史論書は何か。", "choices": [], "answer": "愚管抄", "explanation": "『愚管抄』は慈円が承久の乱直前の時期に著した歴史書で、神代から順徳天皇の代までを扱う。摂関家出身で九条兼実を兄にもつ慈円は、末法思想とは異なる「道理」という観念で歴史の展開を説明しようとした点に特色がある。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "愚管抄"},
  {"id": "q6127", "field": "中世", "difficulty": 4, "type": "short", "question": "1536年、京都で勢力を強めた法華一揆と延暦寺(山門)の衆徒が衝突し、京都の日蓮宗寺院が焼き払われた事件を何というか。", "choices": [], "answer": "天文法華の乱", "explanation": "京都の町衆を中心に広まった法華一揆は自治的な勢力として力を強めたが、これを危険視した延暦寺の衆徒らに1536年攻撃され、洛中の日蓮宗寺院の多くが焼失した。天文法華の乱と呼ばれるこの事件は、宗教勢力どうしの武力衝突として戦国期京都の情勢を示す事例である。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "天文法華の乱"},
  {"id": "q6128", "field": "外交史", "difficulty": 4, "type": "choice", "question": "次のa~dの出来事を年代の古い順に並べたものとして正しいものはどれか。\na 種子島に鉄砲が伝来した　b 大内氏が滅亡し勘合貿易が断絶した　c 三浦の乱が起きた　d ザビエルが鹿児島に上陸した", "choices": ["c→a→d→b", "a→c→d→b", "c→a→b→d", "d→c→a→b", "a→d→c→b"], "answer": 0, "explanation": "三浦の乱(対馬・朝鮮間の貿易をめぐる事件)は1510年、種子島への鉄砲伝来は1543年、ザビエルによるキリスト教伝来は1549年、大内氏滅亡による勘合貿易断絶は1551年である。したがって年代順はc→a→d→bとなる。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6129", "field": "近世", "difficulty": 2, "type": "short", "question": "1637年、領主の重税と圧政、キリシタン弾圧への反発から肥前島原と肥後天草で百姓らが蜂起した一揆を何というか。", "choices": [], "answer": "島原の乱(島原・天草一揆)", "explanation": "島原藩主松倉勝家、天草を領した唐津藩の寺沢堅高の苛政やキリシタン弾圧への反発から、1637年に天草四郎(益田時貞)を首領として百姓が蜂起した。乱後、松倉勝家は斬首、寺沢氏も後に改易となるなど、幕府は大名の失政に厳しい処分をくだし、以後禁教・鎖国体制を強化した。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "島原の乱(島原・天草一揆)"},
  {"id": "q6130", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸幕府がキリスト教徒を摘発・統制するために用いた手段として当てはまらないものを1つ選べ。", "choices": ["絵踏", "寺請制度", "宗門改", "足高の制", "五人組による相互監視"], "answer": 3, "explanation": "絵踏・寺請制度・宗門改・五人組はいずれもキリスト教禁制や民衆統制のための仕組みである。足高の制は徳川吉宗が享保の改革で実施した、在職中のみ不足石高を加増する人材登用制度であり、禁教政策とは関係がない。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6131", "field": "近世", "difficulty": 4, "type": "choice", "question": "鎖国政策が完成に向かう過程で起きた次のa~dの出来事を年代順に並べたものとして正しいものはどれか。\na 平戸のオランダ商館が長崎出島に移転した　b ポルトガル船の来航が禁止された　c 島原の乱がおこった　d 平戸のイギリス商館が閉鎖された", "choices": ["d→c→b→a", "c→d→a→b", "a→b→c→d", "d→c→a→b", "c→a→b→d"], "answer": 0, "explanation": "イギリス商館の閉鎖は1623年、島原の乱は1637~38年、ポルトガル船来航禁止は1639年、平戸のオランダ商館の出島移転は1641年である。よって正しい順序はd→c→b→aとなる。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6132", "field": "近代", "difficulty": 2, "type": "truefalse", "question": "1867年12月の王政復古の大号令では、摂政・関白や将軍職が廃止されるとともに、総裁・議定・参与からなる三職が新たに設置された。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "王政復古の大号令は1867年12月9日に発せられ、幕府や摂関制度を廃止して天皇親政の体制を宣言した。新たに総裁・議定・参与の三職が置かれ、総裁には有栖川宮熾仁親王が就任、議定には皇族・公家・有力諸侯が、参与には諸藩の実務家らが任じられた。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6133", "field": "近代", "difficulty": 3, "type": "short", "question": "1868年閏4月、副島種臣・福岡孝弟らが起草し、アメリカの制度を参考に三権分立の体裁を取り入れた新政府の統治組織を定めた文書は何か。", "choices": [], "answer": "政体書", "explanation": "政体書は五箇条の誓文の趣旨を具体化するため1868年に制定され、太政官への権力集中を図りつつも、立法・行政・司法の三権分立やアメリカ流の官吏互選制などを取り入れた点に特徴があった。しかし実情に合わず、1869年の版籍奉還にともなう官制改革で改められた。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "政体書"},
  {"id": "q6134", "field": "近代", "difficulty": 5, "type": "essay", "question": "1873年から始まる地租改正によって、課税の基準および納税方法はそれまでとどう変わったか。40字以内で説明せよ。", "choices": [], "answer": "", "modelAnswer": "課税基準が収穫高から地価に変わり、豊凶に関係なく地価の3%を土地所有者が現金で納めることとなった。", "explanation": "地租改正は、それまで収穫高(石高)を基準に米などで納めていた年貢にかわり、地券に基づく地価を課税基準とし、税率を地価の3%として土地所有者に金納させる制度であった。これにより政府は豊凶に左右されない安定した財政収入を確保できるようになったが、農民の実質的負担は江戸期とあまり変わらず、地租改正反対一揆が頻発し、1877年に税率は2.5%へ引き下げられた。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部"},
  {"id": "q6135", "field": "近代", "difficulty": 3, "type": "choice", "question": "1870年代の士族反乱に関する記述として誤っているものを1つ選べ。", "choices": ["1874年、佐賀では江藤新平を擁して佐賀の乱が起きた", "1876年、熊本では敬神党(神風連)が廃刀令に反発して挙兵した", "1876年、福岡では秋月の乱が不平士族によって起こされた", "1876年、山口では前原一誠らが萩の乱を起こした", "1877年、鹿児島では大久保利通を擁して西南戦争が起きた"], "answer": 4, "explanation": "西南戦争(1877年)は鹿児島の私学校生らが西郷隆盛を首領として起こした最大の士族反乱であり、大久保利通ではない。佐賀の乱・神風連の乱・秋月の乱・萩の乱はいずれも1874~76年に起きた士族反乱として正しい。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6136", "field": "近代", "difficulty": 3, "type": "short", "question": "1881年、開拓使官有物払下げ問題を契機に、国会開設の時期をめぐる政府内対立から大隈重信が下野した政変を何というか。", "choices": [], "answer": "明治十四年の政変", "explanation": "大隈重信はイギリス流の議院内閣制導入と早期の国会開設を主張していたが、開拓使官有物払下げ事件で世論の批判が高まったことを契機に、伊藤博文らと対立し1881年に参議を罷免された。政府は同時に国会開設の勅諭を出し、1890年の国会開設を約束した。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "明治十四年の政変"},
  {"id": "q6137", "field": "外交史", "difficulty": 3, "type": "short", "question": "1890年、山県有朋が首相として初の帝国議会で施政方針演説を行った際、主権線とともに防衛すべきと説いた、隣接する朝鮮半島を念頭に置いた概念を何というか。", "choices": [], "answer": "利益線", "explanation": "山県有朋は主権線(国境)を守るだけでなく、それと安危が密接に関わる隣接地域である利益線(主に朝鮮半島)の防衛が国家の独立自衛に不可欠であると論じ、軍備拡張の必要性を訴えた。この考え方は日清戦争に至る対外政策の理論的支柱となった。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "利益線"},
  {"id": "q6138", "field": "近代", "difficulty": 3, "type": "choice", "question": "1901年に結成された日本最初の社会主義政党、社会民主党の結成に関わった人物として当てはまらないものを1つ選べ。", "choices": ["幸徳秋水", "堺利彦", "片山潜", "安部磯雄", "伊藤博文"], "answer": 4, "explanation": "社会民主党は1901年、幸徳秋水・堺利彦・片山潜・安部磯雄・木下尚江・河上清らによって結成されたが、治安警察法に基づき結成直後に禁止された。伊藤博文は当時の元老・政治家であり社会主義運動とは無関係である。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6139", "field": "近代", "difficulty": 3, "type": "short", "question": "日露戦争開戦前、キリスト教徒の立場から戦争絶対廃止論を主張し、『萬朝報』などに非戦論を発表したキリスト教思想家は誰か。", "choices": [], "answer": "内村鑑三", "explanation": "内村鑑三は日露非戦論者として、戦争そのものを人を殺す大罪悪であるとして絶対的に否定する論陣を張った。日本的キリスト教の独立を志向し、開戦論に転じた『萬朝報』を退社した後も、幸徳秋水・堺利彦らとともに非戦論を唱え続けた。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "内村鑑三"},
  {"id": "q6140", "field": "外交史", "difficulty": 4, "type": "choice", "question": "1905年のポーツマス条約の内容として誤っているものを1つ選べ。", "choices": ["韓国に対する日本の指導・監督権を認めさせた", "ロシアが満州に持っていた鉄道利権を日本に譲渡させた", "ロシアが持っていた旅順・大連の租借権を日本に譲渡させた", "北緯50度以南の樺太とその付属諸島を日本に譲渡させた", "多額の賠償金をロシアに支払わせることに成功した"], "answer": 4, "explanation": "ポーツマス条約では韓国指導権の承認、南満州鉄道利権と旅順・大連租借権の譲渡、樺太南半の割譲、沿海州漁業権の承認などが定められたが、賠償金は一切得られなかった。これに不満を持った国民により日比谷焼打事件が起きた。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6141", "field": "社会経済", "difficulty": 3, "type": "short", "question": "1911年に制定され、日本で最初の労働者保護法として、幼年労働者の就労制限や女子の深夜業禁止などを定めた法律は何か。", "choices": [], "answer": "工場法", "explanation": "日清・日露戦争後の産業発展にともない工場労働者の過酷な労働条件が問題化する中、1911年に工場法が制定された。資本家の反対もあり適用範囲は限定的で、施行も1916年まで遅れたが、日本最初の労働者保護立法として位置づけられる。（商学部2009年で問われた論点）", "source": "2009", "faculty": "商学部", "modelAnswer": "工場法"},
  {"id": "q6160", "field": "古代", "difficulty": 3, "type": "short", "question": "仏教公伝の年代について、『日本書紀』の552年説に対し現在有力視されている538年説の根拠となっている史料は何か。", "choices": [], "answer": "上宮聖徳法王帝説(や元興寺縁起)", "explanation": "仏教公伝の時期には552年説(『日本書紀』)と538年説の2説があるが、『上宮聖徳法王帝説』や『元興寺縁起』の記述などから538年説が有力視されている。当時の百済は聖明王のもとで新羅の圧迫を受けており、倭国からの軍事支援の見返りとして仏教・経典が伝えられたと考えられている。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "上宮聖徳法王帝説(や元興寺縁起)"},
  {"id": "q6161", "field": "文化史", "difficulty": 2, "type": "truefalse", "question": "推古天皇の時代、蘇我氏によって飛鳥寺(法興寺)が、聖徳太子(厩戸皇子)によって斑鳩の地に法隆寺が建立された。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "6世紀末~7世紀初め、蘇我馬子は飛鳥の地に日本最初の本格的伽藍をもつ飛鳥寺を建立し、聖徳太子は斑鳩宮に隣接して法隆寺(斑鳩寺)を建立した。両寺は飛鳥文化を代表する仏教建築であり、法隆寺は現存する世界最古の木造建築群として知られる。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6162", "field": "古代", "difficulty": 3, "type": "short", "question": "聖武天皇が741年に発した詔に基づき諸国に建立された、僧寺と尼寺からなる寺院を総称して何と呼ぶか。", "choices": [], "answer": "国分寺(国分僧寺・国分尼寺)", "explanation": "聖武天皇は疫病の流行や社会不安のなか、仏教の力による国家鎮護を図り、741年の国分寺建立の詔で諸国に国分僧寺・国分尼寺の建立を命じた。国分僧寺は金光明最勝王経、国分尼寺は法華経をそれぞれ思想的根拠とし、総国分寺は東大寺、総国分尼寺は法華寺とされた。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "国分寺(国分僧寺・国分尼寺)"},
  {"id": "q6163", "field": "文化史", "difficulty": 3, "type": "choice", "question": "興福寺の阿修羅像に関する説明として正しいものを1つ選べ。", "choices": ["奈良時代を代表する乾漆造の仏像である", "平安時代初期の密教彫刻を代表する", "筋骨たくましい忿怒の姿で表される", "銅を素材とした鋳造仏である", "東大寺に伝来した仏像である"], "answer": 0, "explanation": "阿修羅像は興福寺に伝わる奈良時代の乾漆像で、少年のような繊細な三面六臂の姿で知られる。もとはインド神話の戦闘神であったが、日本では仏法を守護する八部衆の一つとして穏やかな表情で表現される点が特徴である。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6164", "field": "文化史", "difficulty": 3, "type": "truefalse", "question": "最澄は空海と同じ804年の遣唐使船で入唐し、帰国後には比叡山に延暦寺を開いて天台宗を広めた。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "最澄は804年に空海と同じ遣唐使船で入唐して天台の教えを学び、帰国後、比叡山に延暦寺を開いて天台宗を広めた。最澄は南都仏教の伝統的な戒壇に対抗して大乗戒壇の設立を目指し、死後にそれが勅許された。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6165", "field": "文化史", "difficulty": 2, "type": "short", "question": "空海が嵯峨天皇から下賜され、真言密教の根本道場とした京都の寺院はどこか。", "choices": [], "answer": "東寺(教王護国寺)", "explanation": "空海は最澄と同じ804年に入唐して密教を学び、帰国後は高野山に金剛峰寺を開くとともに、嵯峨天皇から東寺(教王護国寺)を下賜されて真言密教の中心とした。また綜芸種智院を設けて庶民教育にも尽力した。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "東寺(教王護国寺)"},
  {"id": "q6166", "field": "文化史", "difficulty": 3, "type": "short", "question": "日本古来の神祇信仰と仏教が融合する神仏習合の中で、後に唱えられるようになった、仏や菩薩が仮に神の姿となって現れるとする説を何というか。", "choices": [], "answer": "本地垂迹説", "explanation": "神仏習合は奈良時代から進行し、寺院に鎮守社が祀られたり神前読経が行われたりした。平安時代以降には、仏・菩薩が衆生救済のため仮に神の姿をとって現れるとする本地垂迹説が広まり、神と仏を対応づける信仰が定着していった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "本地垂迹説"},
  {"id": "q6167", "field": "文化史", "difficulty": 3, "type": "short", "question": "平安京の市中で民衆に念仏を勧め、「市聖」と呼ばれた10世紀の僧は誰か。", "choices": [], "answer": "空也", "explanation": "空也は10世紀、社会不安が広がるなかで京の市中を歩き、念仏を唱えて死者を弔い、民衆に念仏往生の教えを説いた。市聖・阿弥陀聖とも呼ばれ、民間への浄土教普及に大きな役割を果たした。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "空也"},
  {"id": "q6168", "field": "文化史", "difficulty": 3, "type": "short", "question": "985年、源信が著し、極楽往生のよりどころを示して貴族社会に浄土信仰を広めるきっかけとなった書物は何か。", "choices": [], "answer": "往生要集", "explanation": "源信(恵心僧都)は『往生要集』で地獄と極楽のありさまを説き、念仏による往生の方法を体系的に示した。この書は貴族の間に浄土信仰を広め、藤原道長・頼通父子による法成寺・平等院鳳凰堂建立など、死後の往生を願う寺院建立の思想的背景となった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "往生要集"},
  {"id": "q6169", "field": "古代", "difficulty": 4, "type": "short", "question": "藤原道長が晩年、極楽往生を願って建立した寺院は何か。", "choices": [], "answer": "法成寺", "explanation": "藤原道長は浄土信仰に篤く帰依し、晩年には壮麗な阿弥陀堂を中心とする法成寺を建立した。子の頼通が建立した平等院鳳凰堂とあわせて、摂関期貴族の浄土信仰と国風文化を代表する遺構として知られる。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "法成寺"},
  {"id": "q6170", "field": "中世", "difficulty": 3, "type": "short", "question": "1180年、平清盛打倒を諸国の源氏に呼びかけ、源頼朝や木曽義仲らの挙兵のきっかけとなった、後白河法皇の皇子による文書を何というか。", "choices": [], "answer": "(以仁王の)令旨", "explanation": "1180年、以仁王は源頼政と結んで平氏打倒の令旨を諸国の源氏に発した。挙兵計画自体は宇治で敗死して失敗したが、この令旨をきっかけに源頼朝・木曽義仲をはじめ各地の反平氏勢力が挙兵し、治承・寿永の内乱が本格化した。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "(以仁王の)令旨"},
  {"id": "q6171", "field": "中世", "difficulty": 4, "type": "choice", "question": "平清盛に関する記述として誤っているものを1つ選べ。", "choices": ["娘徳子を高倉天皇に嫁がせ、安徳天皇の外戚として権勢をふるった", "摂津国大輪田泊を修築し日宋貿易の振興を図った", "摂津国福原への遷都を強行した", "武士として初めて太政大臣に就任した", "保元の乱で叔父の忠正と協力し崇徳上皇方を破った"], "answer": 4, "explanation": "平清盛は保元の乱(1156年)で後白河天皇方につき、崇徳上皇方についた叔父の平忠正とは敵対し、乱後には忠正を処刑した。清盛は日宋貿易振興のため大輪田泊を修築し、1167年には武士として初めて太政大臣となり、娘徳子を高倉天皇の中宮として安徳天皇の外戚となるなど権勢を極めた。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6172", "field": "外交史", "difficulty": 4, "type": "choice", "question": "足利義満が始めた日明貿易(勘合貿易)に関する記述として誤っているものを1つ選べ。", "choices": ["日本からの国書は明への朝貢、明からの返礼という形式をとった", "日本からの輸出品には刀剣や硫黄などがあった", "明からは洪武通宝・永楽通宝などの銅銭が大量にもたらされた", "貿易にかかる日本からの運搬費・明側での滞在費とも日本側がすべて負担した", "足利義満の死後、その子足利義持によって一時中断された"], "answer": 3, "explanation": "日明貿易は明への朝貢とそれに対する返礼という形式をとり、日本からは刀剣・硫黄などが、明からは銅銭や生糸・陶磁器などがもたらされた。経費については日本からの運搬費は日本側負担、明に滞在する使節の滞在費は明側負担という分担であり、日本側がすべて負担したわけではない。また義満の死後、明を蔑視する立場から子の足利義持がこの貿易を一時中断した。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6173", "field": "近世", "difficulty": 3, "type": "short", "question": "老中松平定信が飢饉対策として各大名に一定量の米穀を蓄えさせた政策を何というか。", "choices": [], "answer": "囲米(の制)", "explanation": "松平定信は天明の飢饉の教訓を踏まえ、寛政の改革において各大名に石高1万石につき50石を目安に米穀を蓄えさせる囲米を命じた。あわせて江戸町人には七分積金による備蓄を求めるなど、飢饉に備えた社会政策を進めた。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "囲米(の制)"},
  {"id": "q6174", "field": "近世", "difficulty": 3, "type": "short", "question": "1790年、松平定信が幕府の学問所において朱子学以外の学問の講義を禁じた政策を何というか。", "choices": [], "answer": "寛政異学の禁", "explanation": "寛政異学の禁は、幕府の官学である林家の学問所(のちの昌平坂学問所)における朱子学以外の講義を禁じたもので、あわせて学問吟味という試験制度も設けられた。諸藩の藩校には強制されなかったが、幕府による思想統制の一環として位置づけられる。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "寛政異学の禁"},
  {"id": "q6175", "field": "近世", "difficulty": 5, "type": "essay", "question": "天明の飢饉が江戸時代の政治にどのような影響を及ぼしたか、「田沼意次」「松平定信」の語句を用いて40字以内で説明せよ。", "choices": [], "answer": "", "modelAnswer": "飢饉による打ちこわしで田沼意次が失脚し、かわって松平定信が寛政の改革を主導した。", "explanation": "天明の飢饉による深刻な社会不安と、それに続く江戸・大坂での打ちこわしは、商業重視政策への批判とあいまって老中田沼意次失脚の一因となった。かわって老中となった松平定信は、飢饉への反省から囲米などの備荒政策を含む寛政の改革を進めた。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部"},
  {"id": "q6176", "field": "近代", "difficulty": 4, "type": "choice", "question": "松方正義による財政政策に関する記述として誤っているものを1つ選べ。", "choices": ["緊縮財政と紙幣整理により通貨価値の安定を図った(松方デフレ)", "1882年に日本銀行を設立し銀兌換銀行券を発行させた", "緊縮政策により米・繭などの価格が下落し、農村は深刻な不況に陥った", "1897年に貨幣法を制定し金本位制を確立した", "デフレ政策の結果、物価は上昇し都市の資本家が大きな打撃を受けた"], "answer": 4, "explanation": "松方正義は緊縮財政と紙幣整理によりデフレ政策(松方財政)を進め、1882年には日本銀行を設立して銀兌換銀行券を発行させ通貨価値を安定させた。この結果、米・繭などの価格は下落して農村は深刻な不況(松方デフレ)に陥り、多くの自作農が土地を手放して小作化した。物価が上昇したわけではなく、この点が誤りである。なお1897年には貨幣法により金本位制が確立された。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6177", "field": "社会経済", "difficulty": 2, "type": "short", "question": "古河市兵衛が経営した栃木県の銅山から流出した鉱毒が渡良瀬川流域の農地に深刻な被害を与え、衆議院議員田中正造が解決に奔走した公害事件を何というか。", "choices": [], "answer": "足尾鉱毒事件", "explanation": "足尾銅山の採掘量増加にともない鉱毒が渡良瀬川に流出し、流域の農地・漁業に甚大な被害を及ぼした。被害農民は再三政府に救済を求めたが弾圧を受け、衆議院議員田中正造は議員を辞して天皇へ直訴を試みるなど、日本における公害問題の原点として記憶される事件となった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "足尾鉱毒事件"},
  {"id": "q6178", "field": "近代", "difficulty": 4, "type": "short", "question": "1882年、福島県令三島通庸が進めた道路建設への抵抗を契機に、立憲改進党幹部で県会議長の河野広中らが検挙された自由民権運動の激化事件を何というか。", "choices": [], "answer": "福島事件", "explanation": "福島県令三島通庸は会津地方などへの道路建設を農民に過重な負担で強行しようとし、これに反対する自由民権運動家や農民を弾圧した。県会議長河野広中ら民権派幹部は内乱陰謀の罪で検挙・投獄され、この事件はその後の加波山事件など自由民権運動激化事件の先駆けとなった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "福島事件"},
  {"id": "q6179", "field": "近代", "difficulty": 4, "type": "choice", "question": "民法典論争(法典論争)に関する記述として誤っているものを1つ選べ。", "choices": ["民法(旧民法)の起草にはフランス人ボアソナードが関わった", "この民法はふつう旧民法と呼ばれている", "帝国大学の穂積八束は「民法出デテ忠孝亡ブ」と主張し施行に反対した", "商法についても同時に施行が延期された", "法典施行の延期は第1次大隈内閣のときに決定された"], "answer": 4, "explanation": "民法典論争では、フランス人ボアソナードが起草に関与した民法(旧民法)をめぐり、家族道徳の観点から穂積八束らが施行に反対し、商法の施行もあわせて延期された。この施行延期が決定されたのは第1次大隈内閣ではなく第1次松方正義内閣の時であった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6180", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "原敬は華族でも藩閥出身でもない衆議院議員として初めて首相となり、選挙人の納税資格を引き下げ小選挙区制を導入したが、男子普通選挙の実現には応じなかった。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "原敬内閣は本格的な政党内閣として国民の期待を集めたが、選挙人資格を直接国税3円以上に引き下げ小選挙区制を導入するにとどまり、野党が求めた男子普通選挙の実現には時期尚早として応じなかった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6181", "field": "社会経済", "difficulty": 3, "type": "short", "question": "1923年の関東大震災の後、決済不能となった手形の処理をめぐる不安が金融システムを不安定化させ、1927年の金融恐慌の遠因となったこの震災関連の手形を何というか。", "choices": [], "answer": "震災手形", "explanation": "関東大震災により経済機能が集中する首都圏が壊滅的被害を受けたため、政府は日本銀行に震災の影響を受けた手形(震災手形)を特別に割り引かせて決済を猶予した。しかし決済は進まず「財界の癌」として残り続け、1927年にその処理法案審議の過程で銀行の経営不安が露呈し、金融恐慌を引き起こす一因となった。（商学部2010年で問われた論点）", "source": "2010", "faculty": "商学部", "modelAnswer": "震災手形"},
  {"id": "q6200", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文時代の人々が定住生活を営むために築いた、地面を掘り下げて柱を立て屋根をふいた住居を何というか。", "choices": [], "answer": "竪穴住居(竪穴式住居)", "explanation": "縄文時代の人々は狩猟・漁労・採集を基本としながら定住的な生活を営み、地面を円形や方形に掘り下げて柱を立て、屋根をふいた竪穴住居に居住した。三内丸山遺跡などの大規模集落からは、クリの管理栽培やマメ類の利用など、初歩的な栽培に近い活動もうかがえる。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "竪穴住居(竪穴式住居)"},
  {"id": "q6201", "field": "古代", "difficulty": 2, "type": "short", "question": "佐賀県の遺跡で検出された水田跡などから、北部九州で稲作を中心とする新しい文化が始まったことが確認されている。この文化を何というか。", "choices": [], "answer": "弥生文化", "explanation": "縄文時代末期、朝鮮半島から伝わった水稲耕作を基盤とする新しい文化が北部九州から西日本へと急速に広まり、弥生文化と呼ばれた。佐賀県の菜畑遺跡などで検出された水田跡は、この文化の初期の様相を伝える重要な遺構である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "弥生文化"},
  {"id": "q6202", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "3世紀の倭国の様子を伝える中国の歴史書『魏志』倭人伝には、女王卑弥呼が呪術によって人心を掌握し、その死後には大規模な墳丘が築かれて多数の殉葬者が出たと記されている。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "『魏志』倭人伝には、鬼道(呪術)によって民衆の心をとらえた女王卑弥呼が邪馬台国を中心とする小国連合を統治していたこと、また卑弥呼の死後に大きな墳丘が造られ、100人余りの奴婢が殉葬されたことなどが記されている。倭人伝は当時の倭の社会・政治状況を知る貴重な史料である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6203", "field": "古代", "difficulty": 4, "type": "choice", "question": "古墳文化の前期(3世紀後半~4世紀)の特徴として正しいものを1つ選べ。", "choices": ["巨大な前方後円墳が畿内を中心に築造され始めた", "埴輪は人物・動物埴輪が主流であった", "埋葬施設は横穴式石室が一般的であった", "朝鮮半島の影響で馬具や須恵器が多量に副葬された", "追葬のための羨道が玄室に設けられた"], "answer": 0, "explanation": "古墳文化前期には、大和を中心に瀬戸内海沿岸から近畿にかけて前方後円墳が出現し、その立地・墳形・埋葬施設・副葬品などの共通性からヤマト王権の存在が想定されている。前期の埋葬施設は竪穴式石室が中心で、副葬品も呪術的な鏡や玉類が多く、埴輪も円筒埴輪が主流であった。人物・動物埴輪や横穴式石室、馬具・須恵器の副葬は中期以降に一般化する特徴である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6204", "field": "古代", "difficulty": 3, "type": "short", "question": "ヤマト王権が国内の諸勢力を統合しながら東アジア情勢に対応し、7世紀末から8世紀初めにかけて完成させた、天皇を中心とする中央集権的な統治の法体系を何というか。", "choices": [], "answer": "律令(律令制度)", "explanation": "ヤマト王権は古墳時代を通じて国内諸勢力を服属させ、6世紀以降は仏教の受容や大陸文物の摂取を進めながら、激動する東アジア情勢の中で中央集権化を図った。大化改新以降の一連の改革を経て、701年の大宝律令によって律令に基づく国家体制が確立した。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "律令(律令制度)"},
  {"id": "q6205", "field": "文化史", "difficulty": 3, "type": "choice", "question": "聖徳太子が秦河勝に授けたと伝えられる、朝鮮半島系の様式をもつ仏像として知られるものはどれか。1つ選べ。", "choices": ["飛鳥寺釈迦如来像", "法隆寺夢殿救世観音像", "広隆寺半跏思惟像", "法隆寺阿弥陀三尊像", "中宮寺半跏思惟像"], "answer": 2, "explanation": "広隆寺半跏思惟像は、聖徳太子が渡来系氏族の秦氏の族長であった秦河勝に授けたと伝えられる仏像で、朝鮮半島(新羅系とされる)の影響を受けた造形様式をもつことで知られる。飛鳥文化における渡来人・渡来系氏族の役割を示す代表例である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6206", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "律令制度のもとでは神祇官と太政官がともに設置されたが、実際の政務を統括する太政官の方が神祇官よりも上位に位置づけられていた。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "律令の官制では祭祀を担当する神祇官と一般政務を統括する太政官が並置されたが、序列としては太政官が上位に置かれた。太政官のもとには八省が属し、太政大臣・左右大臣・大納言などが政務を統轄する一方、非違を監察する弾正台は太政官の指揮下に置かれた。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6207", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "保元の乱(1156年)は、崇徳上皇と後白河天皇の対立に摂関家内部の争いがからんで起こり、平清盛や源義朝ら武士の実力によって決着した。", "choices": ["正しい", "誤っている"], "answer": 0, "explanation": "保元の乱は皇位継承をめぐる崇徳上皇・後白河天皇の対立に、摂関家の忠通・頼長兄弟の対立が結びついて発生し、双方が動員した平清盛・源義朝ら武士の軍事力によって後白河方が勝利した。この乱を境に、武士が中央政界の政争を左右する存在として台頭した。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6208", "field": "中世", "difficulty": 3, "type": "short", "question": "1221年、後鳥羽上皇が北条義時追討の院宣を発して起こした戦乱を何というか。", "choices": [], "answer": "承久の乱", "explanation": "後鳥羽上皇は幕府の実権を握る執権北条義時の追討を諸国の武士に呼びかけ承久の乱を起こしたが、北条政子の呼びかけで結束した幕府軍に短期間で鎮圧された。乱後、幕府は京都に六波羅探題を置き、朝廷監視と西国統治を強化するとともに、上皇方の所領を没収して新補地頭を任命するなど、幕府優位の体制を確立した。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "承久の乱"},
  {"id": "q6209", "field": "文化史", "difficulty": 3, "type": "short", "question": "南朝の重臣として東国に赴き、南朝の正統性を主張するために『神皇正統記』を著した人物は誰か。", "choices": [], "answer": "北畠親房", "explanation": "北畠親房は後醍醐天皇に仕えた南朝の重臣で、南朝方の劣勢を挽回するため東国に下向した。その間に、神代から続く皇位継承の正統性を説く『神皇正統記』を著し、あわせて有職故実書『職原抄』も著した。子の北畠顕家も南朝方の武将として活躍した。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "北畠親房"},
  {"id": "q6210", "field": "中世", "difficulty": 4, "type": "short", "question": "1485年、山城国で国人や土民が一致して両畠山軍の撤退を求め、以後8年間にわたり自治的な支配を行った出来事を何というか。", "choices": [], "answer": "山城の国一揆", "explanation": "応仁の乱後も山城国で対陣を続けていた畠山政長・畠山義就両軍に対し、国人・土民が一致して撤退を要求し、これに応じさせた。以後、国人らは月行事を定めて自治的な支配を行い、山城の国一揆と呼ばれるこの体制は約8年間続いた。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "山城の国一揆"},
  {"id": "q6211", "field": "中世", "difficulty": 4, "type": "choice", "question": "応仁の乱に関する記述として誤っているものを1つ選べ。", "choices": ["8代将軍足利義政の後継者問題が対立の一因となった", "細川勝元と山名持豊(宗全)がそれぞれ東軍・西軍を率いた", "戦乱は主に京都を中心に展開し、地方には波及しなかった", "戦乱により幕府の権威は失墜し、下剋上の風潮が広がった", "戦乱は東西両軍の和睦によって一応の終息をみた"], "answer": 2, "explanation": "応仁の乱(1467~77年)は将軍家や有力守護家の家督争いに、細川勝元(東軍)と山名持豊(西軍)の対立がからんで発生し、主戦場となった京都は荒廃した。戦乱は在京していた守護大名の分国にも波及し、諸国の武士の動員や下国を通じて地方における下剋上の風潮を全国的に広げる契機となった。したがって「地方には波及しなかった」は誤りである。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6212", "field": "文化史", "difficulty": 3, "type": "short", "question": "杉田玄白が晩年に、蘭学がおこり発展してきた経緯を回想して著した書物を何というか。", "choices": [], "answer": "蘭学事始", "explanation": "『蘭学事始』は杉田玄白が1815年に脱稿した回想録で、前野良沢らとともに刑場で人体解剖(腑分け)に立ち会い、オランダ語の解剖書の正確さに感銘を受けて翻訳を決意した経緯や、蘭学草創期の苦労を伝える貴重な史料である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "蘭学事始"},
  {"id": "q6213", "field": "文化史", "difficulty": 3, "type": "truefalse", "question": "杉田玄白・前野良沢らは、刑場での腑分けに立ち会った際、持参したオランダ語の解剖書の図が実際の人体の構造と全く異なっていたことに驚き、旧来の説の正しさを再確認した。", "choices": ["正しい", "誤っている"], "answer": 1, "explanation": "杉田玄白・前野良沢らは骨ケ原での腑分けに立ち会い、持参した『ターヘル・アナトミア』の図が実際の人体の構造と寸分違わないことに驚嘆した。これはむしろ旧来の五臓六腑説などとは相違するものであり、この経験が『解体新書』翻訳の大きな動機となった。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6214", "field": "外交史", "difficulty": 4, "type": "choice", "question": "江戸時代における幕府とオランダとの関係についての説明として正しいものを1つ選べ。", "choices": ["将軍・国王の代替わりごとに慶賀使・謝恩使が日本に派遣された", "日本に関税自主権のない不平等条約が結ばれていた", "冊封体制のなかで朝貢貿易が行われた", "幕府の統制のもと、長崎でオランダ風説書が提出された", "勘合符を使った勘合貿易が行われた"], "answer": 3, "explanation": "鎖国体制下でも長崎の出島を通じてオランダとの交易は継続され、オランダ商館長は海外情勢を記したオランダ風説書を幕府に提出することが義務づけられていた。慶賀使・謝恩使は琉球から、朝貢・冊封関係は主に中国・朝鮮との関係にあたり、勘合貿易は室町期の日明貿易であって、いずれもオランダとの関係とは異なる。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6215", "field": "文化史", "difficulty": 3, "type": "short", "question": "本居宣長が大成し、儒教や仏教が伝来する以前の日本古来の精神を探ろうとした学問を何というか。", "choices": [], "answer": "国学", "explanation": "国学は『古事記』『万葉集』などの古典研究を通じて日本固有の精神を明らかにしようとする学問で、賀茂真淵を経て本居宣長が『古事記伝』によって大成した。国学や水戸学に基づく尊王論は、幕末には尊王攘夷論の思想的基盤の一つとなり、下級武士や豪農層に支持された。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "国学"},
  {"id": "q6216", "field": "近代", "difficulty": 3, "type": "short", "question": "明治初期、大学南校などで教鞭をとった、アメリカ人宣教師で教頭も務めたお雇い外国人は誰か。", "choices": [], "answer": "フルベッキ", "explanation": "明治初期の大学南校では、諸藩から選ばれた貢進生らが学び、米人フルベッキが教頭として教育にあたった。フルベッキは長崎で宣教のかたわら英語や諸学を教え、多くの人材の育成に貢献したお雇い外国人の代表例である。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "フルベッキ"},
  {"id": "q6217", "field": "近代", "difficulty": 3, "type": "short", "question": "1890年、天皇制国家における国民道徳の基本を示すものとして発布され、井上毅らが起草に関わった勅語を何というか。", "choices": [], "answer": "教育勅語(教育ニ関スル勅語)", "explanation": "教育勅語は1890年、明治天皇の名で発布され、忠君愛国を核とする国民道徳の基本を示した。起草には法制官僚の井上毅や儒学者元田永孚らが関わり、井上毅は憲法起草にも参与し、後に枢密院議長も務めるなど、明治国家体制の基礎づくりに深く関与した。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "教育勅語(教育ニ関スル勅語)"},
  {"id": "q6218", "field": "近代", "difficulty": 4, "type": "short", "question": "日清戦争前後、産業界の実力を養うため工業・商業・農業に従事する者への実業教育の普及を目的として公布された勅令を何というか。", "choices": [], "answer": "実業学校令", "explanation": "文部大臣であった井上毅は日清戦争前後の実業教育の重要性を認識し、その組織整備のため実業学校令を公布した。施行直前には全国で20校ほどにすぎなかった実業学校は、その後まもなく百数十校に急増するという顕著な発展を遂げた。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "実業学校令"},
  {"id": "q6219", "field": "社会経済", "difficulty": 4, "type": "choice", "question": "第一次世界大戦期の日本経済に関する記述として誤っているものを1つ選べ。", "choices": ["ヨーロッパ諸国の後退に乗じ綿織物のアジア市場輸出が拡大した", "アメリカ向けの生糸輸出が増加した", "世界的な船舶不足を背景に海運業・造船業が空前の好況を迎えた", "大戦景気を通じて日本は債務国から債権国に転じた", "電力事業は停滞し、依然として蒸気力が工業原動力の中心であり続けた"], "answer": 4, "explanation": "第一次世界大戦期には船舶不足による海運・造船ブーム、アジア市場での綿製品輸出拡大、対米生糸輸出の増加などにより大戦景気が生じ、日本は債務国から債権国に転じた。あわせて電力事業の発展もみられ、工業原動力は蒸気力から電力へと転換が進んだため、「電力事業は停滞した」とする記述は誤りである。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": ""},
  {"id": "q6220", "field": "社会経済", "difficulty": 3, "type": "short", "question": "1927年、震災手形の処理法案審議の過程で銀行の経営不安が表面化し、若槻礼次郎内閣が総辞職に追い込まれる事態を招いた経済危機を何というか。", "choices": [], "answer": "金融恐慌", "explanation": "1927年、震災手形処理法案の議会審議中に片岡直温蔵相の失言などから取付け騒ぎが拡大し、鈴木商店に対する巨額の不良債権を抱えた台湾銀行の救済緊急勅令案が枢密院で否決されたことで、若槻礼次郎内閣は総辞職に追い込まれた。これが金融恐慌であり、後継の田中義一内閣は3週間のモラトリアム(支払猶予令)を発して鎮静化を図った。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部", "modelAnswer": "金融恐慌"},
  {"id": "q6221", "field": "社会経済", "difficulty": 5, "type": "essay", "question": "1949年に来日した銀行家ドッジの指導のもとで実施された一連の経済政策(ドッジ=ライン)が日本経済に与えた影響について、「インフレは」から始まる一文で、40字以内で説明せよ。", "choices": [], "answer": "", "modelAnswer": "インフレは収束したが、超緊縮財政により深刻な不況を招き、失業者が増大した。", "explanation": "ドッジ=ラインは超均衡予算の編成や単一為替レート(1ドル=360円)の設定などにより、戦後の激しいインフレーションを収束させることに成功した。しかし急激な緊縮政策は深刻な不況(安定恐慌)を招き、中小企業の倒産や失業者の増大をもたらした。朝鮮戦争にともなう特需景気によって、日本経済はようやくこの不況から脱することになる。（商学部2011年で問われた論点）", "source": "2011", "faculty": "商学部"},
  {"id": "q6240", "field": "古代", "difficulty": 3, "type": "short", "question": "810年、平城太上天皇が藤原仲成・薬子の勧めにより平城京への再遷都と重祚を図ったが、嵯峨天皇方に鎮圧されたこの政変を何と呼ぶか。", "choices": [], "answer": "薬子の変（平城太上天皇の変）", "modelAnswer": "薬子の変（平城太上天皇の変）", "explanation": "嵯峨天皇は蔵人所を設置して情報を統制し、坂上田村麻呂らの軍事力で乱を鎮圧した。平城太上天皇は出家し、藤原薬子は自殺、仲成は処刑された。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6241", "field": "古代", "difficulty": 3, "type": "choice", "question": "842年、皇太子であった人物が謀反の密告を受けて廃され、藤原良房が実権を強めるきっかけとなった政変で、廃された皇太子は誰か。", "choices": ["恒貞親王", "惟喬親王", "阿保親王", "道康親王", "有智子内親王"], "answer": 0, "modelAnswer": "", "explanation": "承和の変では淳和天皇の子・恒貞親王が皇太子を廃され、伴健岑・橘逸勢が配流された。これにより仁明天皇の子・道康親王（後の文徳天皇）が皇太子となり、藤原良房の外戚としての地位が強化された。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6242", "field": "古代", "difficulty": 3, "type": "short", "question": "866年、応天門への放火事件を口実に伴善男らの他氏勢力を排除し、藤原良房が人臣として初めて正式に摂政に任じられる契機となった事件を何というか。", "choices": [], "answer": "応天門の変", "modelAnswer": "応天門の変", "explanation": "応天門の変では大納言伴善男が放火犯として流罪となり、伴・紀氏など古代からの有力氏族が没落した。これにより藤原氏の他氏排斥が進み、藤原良房は清和天皇の摂政として権力を確立した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6243", "field": "古代", "difficulty": 4, "type": "truefalse", "question": "藤原基経は、応天門の変後に即位した光孝天皇の下で政務を代行する地位に就き、次の宇多天皇の代に正式に「関白」の詔を受けた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原基経は884年に光孝天皇を擁立して事実上の関白としての地位を確立し、887年、宇多天皇の即位にあたって正式に関白に任じられた（その直後に阿衡の紛議が起きている）。摂関政治確立の重要な画期である。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6244", "field": "古代", "difficulty": 3, "type": "choice", "question": "嵯峨天皇の治世に編纂された、律令の施行細則を集成した最初の格式は何か。", "choices": ["弘仁格式", "貞観格式", "延喜格式", "類聚三代格", "令義解"], "answer": 0, "modelAnswer": "", "explanation": "弘仁格式は嵯峨天皇の勅により編纂された最初の格式で、その後の貞観格式・延喜格式とあわせて三代格式と呼ばれる。律令の補足・改正規定である「格」と施行細則である「式」から成る。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6245", "field": "古代", "difficulty": 2, "type": "choice", "question": "嵯峨天皇の時代に新設され、令の規定にない令外官として都の治安維持や訴訟・裁判を担った官職は何か。", "choices": ["検非違使", "蔵人頭", "勘解由使", "按察使", "押領使"], "answer": 0, "modelAnswer": "", "explanation": "検非違使は嵯峨天皇の代に設置された令外官で、当初は京中の治安維持を担ったが、次第に裁判権も掌握し、令制官司である弾正台や刑部省の職掌を吸収していった。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6246", "field": "中世", "difficulty": 3, "type": "short", "question": "1185年、源頼朝が源義経・行家追討を名目に、後白河法皇から国ごとの守護、荘園・公領ごとの地頭の設置を認められた出来事を何と呼ぶか。", "choices": [], "answer": "文治の勅許", "modelAnswer": "文治の勅許", "explanation": "頼朝は弟義経の逮捕を口実に、諸国への守護、荘園・公領への地頭の設置権を朝廷から認めさせた。この文治の勅許により鎌倉幕府の全国的な軍事・警察機構の基礎が築かれた。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6247", "field": "中世", "difficulty": 4, "type": "truefalse", "question": "源頼朝は1190年に上洛した際、右近衛大将に任じられたが、まもなくこの職を辞任した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "頼朝は1190年の上洛時に権大納言・右近衛大将に任じられたが、鎌倉に戻るためすぐに両職を辞任した。征夷大将軍の宣下を受けたのは1192年、後白河法皇の死後のことである。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6248", "field": "中世", "difficulty": 2, "type": "short", "question": "1333年に鎌倉幕府を滅ぼした後醍醐天皇が開始した、天皇親政による新しい政治を何と呼ぶか。", "choices": [], "answer": "建武の新政", "modelAnswer": "建武の新政", "explanation": "後醍醐天皇は摂政・関白を置かず、記録所や雑訴決断所を設けて親政を行った。延喜・天暦の治を理想としたが、公家中心の政策は武士の不満を招き、足利尊氏の離反により短期間で崩壊した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6249", "field": "中世", "difficulty": 3, "type": "choice", "question": "1336年、足利尊氏が今後の政治方針を示すために制定した17か条からなる法典は何か。", "choices": ["建武式目", "御成敗式目", "建武年間記", "公事方御定書", "分国法"], "answer": 0, "modelAnswer": "", "explanation": "建武式目は足利尊氏が幕府開設にあたり、是円ら法律家の意見を踏まえて定めた政治方針で、幕府所在地の選定や倹約・法秩序の重視などを内容とする。室町幕府の性格を示す基本文書である。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6250", "field": "近世", "difficulty": 2, "type": "choice", "question": "1582年、京都の本能寺に滞在していた織田信長を家臣が急襲し自害に追い込んだ事件を何と呼ぶか。", "choices": ["本能寺の変", "桶狭間の戦い", "山崎の戦い", "賤ヶ岳の戦い", "清洲会議"], "answer": 0, "modelAnswer": "", "explanation": "本能寺の変は明智光秀が織田信長を襲撃し自害させた事件。光秀はその後まもなく山崎の戦いで羽柴（豊臣）秀吉に敗れて敗死した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6251", "field": "近世", "difficulty": 4, "type": "essay", "question": "江戸時代の「士農工商」という語は、実際にはどのような性格の区分として用いられることが多かったか、身分と職分の観点から説明せよ。", "choices": [], "answer": "", "modelAnswer": "「士農工商」は支配・被支配という身分の上下関係というより、社会における職分（役割分担）を示す語として用いられることが多く、特に被支配身分であった農工商の側が、自らの職分の重要性を強調する文脈で持ち出されることが多かった。", "explanation": "近世の身分制は武士身分の内部にも序列があり、武士以外はみな「庶人」として一括される観念も存在した。士農工商は必ずしも厳密な上下の身分秩序ではなく、職業に基づく区分として理解する必要がある。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6252", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "江戸時代、長崎に置かれたオランダ商館は、オランダ東インド会社の日本支店としての性格を持っていた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "長崎出島のオランダ商館はオランダ東インド会社（VOC）の日本における拠点であり、商館長（カピタン）が交代で来日し、江戸参府を行って将軍に謁見した。中国とは異なり、オランダとの貿易は公認の管理貿易であった。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6253", "field": "近世", "difficulty": 3, "type": "short", "question": "1615年、江戸幕府が天皇・公家の行動を規制するために制定した法令は何か。", "choices": [], "answer": "禁中並公家諸法度", "modelAnswer": "禁中並公家諸法度", "explanation": "禁中並公家諸法度は徳川家康の命により金地院崇伝らが起草し、天皇の学問専念や公家の席次、紫衣勅許の制限などを定めた。これにより幕府は朝廷統制の法的根拠を確立した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6254", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "江戸時代、死牛馬の処理に従事する人々への差別意識は、「えた」という呼称によって表された。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "江戸時代の賤民身分のうち、死牛馬処理や皮革加工などに従事した人々は「えた」と呼ばれて差別された。賤民身分には他に物乞いや芸能を生業とする「非人」なども含まれた。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6255", "field": "文化史", "difficulty": 3, "type": "choice", "question": "幕末、佐賀藩主鍋島閑叟が招いた蘭学者で、長崎で鳴滝塾を開いたことで知られる人物は誰か。", "choices": ["シーボルト", "高野長英", "緒方洪庵", "渡辺崋山", "杉田玄白"], "answer": 0, "modelAnswer": "", "explanation": "シーボルトはオランダ商館の医師として来日し、長崎に鳴滝塾を開いて高野長英ら多くの門下生を育てた。帰国の際に日本地図を持ち出そうとして発覚し、国外追放処分となった（シーボルト事件）。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6256", "field": "近代", "difficulty": 2, "type": "choice", "question": "幕末に『西洋事情』を著し、明治期には『学問のすゝめ』の執筆や『時事新報』の創刊、慶應義塾の運営を行った人物は誰か。", "choices": ["福沢諭吉", "中村正直", "西周", "森有礼", "加藤弘之"], "answer": 0, "modelAnswer": "", "explanation": "福沢諭吉は幕末に幕府使節に随行して欧米を視察し『西洋事情』を著した。明治期には『学問のすゝめ』『文明論之概略』を執筆し、1882年に『時事新報』を創刊するなど、近代思想の普及に大きく貢献した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6257", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "江戸城は勝海舟と西郷隆盛の交渉により無血開城されたが、その後も奥羽越列藩同盟や榎本武揚らの抵抗が続き、戊辰戦争は箱館五稜郭の戦いをもって終結した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "鳥羽・伏見の戦いに敗れた幕府は大政奉還後も抵抗を続けたが、江戸城は無血開城された。その後、奥羽越列藩同盟が抗戦し、最終的に榎本武揚が箱館五稜郭で降伏したことで戊辰戦争は終結した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6258", "field": "外交史", "difficulty": 3, "type": "short", "question": "井上馨外務卿（のち外務大臣）が条約改正交渉を進める中で採用した、鹿鳴館に象徴される極端な西洋文化受容の外交・社交政策を何と呼ぶか。", "choices": [], "answer": "欧化政策（欧化主義）", "modelAnswer": "欧化政策（欧化主義）", "explanation": "井上馨は条約改正実現のため鹿鳴館を建設し、舞踏会を催すなど極端な欧化政策をとったが、外国人判事の任用を認める改正案の内容が国権侵害であると批判され、政府内外から強い反発を受け交渉は失敗に終わった。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6259", "field": "近代", "difficulty": 3, "type": "choice", "question": "明治期、新島襄が京都に開設し、後に大学へと発展した私立学校はどれか。", "choices": ["同志社英学校", "専修学校", "日本法律学校", "明治法律学校", "女子英学塾"], "answer": 0, "modelAnswer": "", "explanation": "新島襄はアメリカ留学の経験を生かし、キリスト教主義に基づく同志社英学校を京都に開設した。これは後に同志社大学となった。同時期には専修学校（専修大学）、明治法律学校（明治大学）なども設立され、私立高等教育機関が発展した。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6260", "field": "外交史", "difficulty": 5, "type": "essay", "question": "1920年代後半の浜口雄幸内閣が推進した外交・軍縮政策の内容と、それに対する国内の批判の論点を説明せよ。", "choices": [], "answer": "", "modelAnswer": "浜口雄幸内閣は幣原喜重郎らの協調外交路線を継承し、ロンドン海軍軍縮会議に参加して補助艦保有量を制限する条約に調印した。これに対し野党や海軍軍令部などは、政府が軍令部の同意を得ずに兵力量を決定したことは天皇の統帥権を侵すものであると激しく攻撃した（統帥権干犯問題）。", "explanation": "ロンドン海軍軍縮条約は国際協調と軍縮を進めるものであったが、統帥権干犯問題として政治問題化し、浜口首相は右翼青年に狙撃されるなど、国家主義的風潮の高まりを招く一因となった。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6261", "field": "近代", "difficulty": 3, "type": "short", "question": "満州国建国を認めない国際連盟の勧告に反発し、日本が国際連盟からの脱退を通告した年（西暦）は何年か。", "choices": [], "answer": "1933年", "modelAnswer": "1933年", "explanation": "リットン調査団の報告に基づき国際連盟が満州国承認の撤回を求める勧告案を採択すると、日本は1933年3月に脱退を通告し、国際的孤立を深めていった。斎藤実内閣の時期の出来事である。（商学部2012年で問われた論点）", "source": "2012", "faculty": "商学部"},
  {"id": "q6280", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "埼玉県稲荷山古墳から出土した鉄剣の銘文には、被葬者の先祖の名が刻まれている。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "稲荷山古墳出土鉄剣には「ヲワケ」を名乗る人物が先祖の系譜とともに、大王への奉仕を記した銘文が刻まれており、ヤマト政権の支配拡大やウジの系譜意識を示す貴重な資料である。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6281", "field": "古代", "difficulty": 3, "type": "short", "question": "熊本県江田船山古墳から出土した鉄刀の銘文に見える大王の名は、一般に記紀のどの天皇に比定されるか。", "choices": [], "answer": "雄略天皇", "modelAnswer": "雄略天皇", "explanation": "江田船山古墳出土鉄刀の銘文には「獲加多支鹵大王」の名が刻まれており、埼玉県稲荷山古墳出土鉄剣の銘文とも共通することから、雄略天皇に比定されている。ヤマト政権の支配が九州から関東まで及んでいたことを示す。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6282", "field": "文化史", "difficulty": 3, "type": "choice", "question": "東大寺正倉院に伝わる宝物として適切でないものはどれか。", "choices": ["天寿国繡帳", "螺鈿紫檀五絃琵琶", "漆胡瓶", "瑠璃杯", "鳥毛立女屛風"], "answer": 0, "modelAnswer": "", "explanation": "天寿国繡帳は聖徳太子の妃が太子を偲んで作らせたとされる刺繡で、中宮寺に伝わる。正倉院には螺鈿紫檀五絃琵琶、漆胡瓶、瑠璃杯、鳥毛立女屛風など、シルクロードを通じた国際色豊かな宝物が伝わっている。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6283", "field": "古代", "difficulty": 4, "type": "truefalse", "question": "平城京は唐の長安城を模範として造営された条坊制の都城であり、藤原京はそれに先立つ日本初の本格的な都城として営まれた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原京は持統天皇によって営まれた日本最初の本格的な条坊制都城であるが、唐の長安城を明確に模したのはむしろ平城京とされる。藤原京は中国古代の周礼にみられる理念的な都城プランに近いとする説が有力である。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6284", "field": "古代", "difficulty": 3, "type": "choice", "question": "主に使用済みの紙に漆が染み込んで残った文書で、律令時代の地方行政の実態を伝える資料は何か。", "choices": ["漆紙文書", "木簡", "正倉院文書", "延喜式", "風土記"], "answer": 0, "modelAnswer": "", "explanation": "漆紙文書は、漆器の蓋紙などに使われた反故紙に漆が浸み込んで腐らずに残ったもので、地方官衙跡から多数発見されている。木簡とともに、文献史料を補う貴重な考古資料である。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6285", "field": "中世", "difficulty": 2, "type": "short", "question": "1156年、崇徳上皇と後白河天皇の対立に藤原氏の内紛や源平の武士団が結びついて起こった争乱を何と呼ぶか。", "choices": [], "answer": "保元の乱", "modelAnswer": "保元の乱", "explanation": "保元の乱では後白河天皇方が勝利し、崇徳上皇は讃岐に配流された。この乱を機に武士が中央政界における実力を示すこととなり、平清盛や源義朝の政治的地位が向上した。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6286", "field": "中世", "difficulty": 3, "type": "short", "question": "1441年、播磨守護赤松満祐が室町幕府将軍を自邸に招いて謀殺した事件を何と呼ぶか。", "choices": [], "answer": "嘉吉の乱（嘉吉の変）", "modelAnswer": "嘉吉の乱（嘉吉の変）", "explanation": "嘉吉の乱では将軍足利義教が赤松満祐に謀殺された。将軍権力の弱体化と幕府権威の動揺を象徴する事件となった。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6287", "field": "文化史", "difficulty": 3, "type": "truefalse", "question": "大和猿楽四座の一つである観世座から出た観阿弥・世阿弥父子は、将軍足利義満の保護を受けて能を大成した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "観阿弥・世阿弥は大和猿楽の観世座の出身で、足利義満の庇護のもとで猿楽能を洗練させた。世阿弥は『風姿花伝』などの能楽論書を著し、能を芸術的に大成させた。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6288", "field": "中世", "difficulty": 3, "type": "choice", "question": "1428年、近江の馬借の蜂起をきっかけに京都近郊の農民が徳政を求めて蜂起し、柳生の徳政碑文に刻まれた一揆は何か。", "choices": ["正長の徳政一揆", "嘉吉の徳政一揆", "播磨の土一揆", "山城の国一揆", "加賀の一向一揆"], "answer": 0, "modelAnswer": "", "explanation": "正長の徳政一揆は将軍の代替わりに際し、近江坂本の馬借の蜂起をきっかけに畿内一帯に広がった土一揆で、柳生の徳政碑文には当地の負い目（借金）の破棄が刻まれている。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6289", "field": "文化史", "difficulty": 4, "type": "short", "question": "室町時代の公家・学者で、将軍足利義尚に政治の心得を説いた『樵談治要』を著した人物は誰か。", "choices": [], "answer": "一条兼良", "modelAnswer": "一条兼良", "explanation": "一条兼良は摂関家出身の学者で、有職故実や古典に通じ、『花鳥余情』などの注釈書のほか、9代将軍足利義尚に対して政治意見書『樵談治要』を著し、土一揆への対処法などを説いた。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6290", "field": "近世", "difficulty": 3, "type": "choice", "question": "津藩主藤堂高虎が後継者に宛てた家訓において重んじられた、武士としての心構えとして正しいものはどれか。", "choices": ["仁義礼智信の重視と文武両道の精進", "石高に応じた軍役の厳格な履行のみ", "参勤交代の励行のみ", "キリスト教の禁止のみ", "朝廷儀礼の習得のみ"], "answer": 0, "modelAnswer": "", "explanation": "藤堂高虎の家訓では、弓鉄砲馬術などの武芸を怠らないことに加え、仁義礼智信という儒教的徳目や文武両道の心がけが説かれており、戦国武将から太平の世を治める近世大名への意識の転換がうかがえる。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6291", "field": "近世", "difficulty": 2, "type": "choice", "question": "江戸時代の村の運営を担った、名主（庄屋）・組頭・百姓代からなる村役人を総称して何というか。", "choices": ["村方三役", "五人組", "本百姓", "地方三役", "村請制"], "answer": 0, "modelAnswer": "", "explanation": "村方三役（村役人）は名主・組頭・百姓代からなり、年貢の徴収や村内の行政を担った。村の自治的運営を支える仕組みであり、村請制のもとで年貢納入の責任も負った。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6292", "field": "近世", "difficulty": 2, "type": "choice", "question": "相模国出身で、荒廃した農村の復興にあたり報徳仕法を実践し、後に幕府の農政にも関わった人物は誰か。", "choices": ["二宮尊徳", "大原幽学", "田中丘隅", "大蔵永常", "宮崎安貞"], "answer": 0, "modelAnswer": "", "explanation": "二宮尊徳（金次郎）は勤労と倹約による農村復興策（報徳仕法）を各地で実践し、その手腕が幕府に認められて天保期以降幕府御普請役として登用された。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6293", "field": "近代", "difficulty": 5, "type": "essay", "question": "1888年の市制町村制、1890年の府県制・郡制の制定は、明治政府の地方統治にどのような意義を持ったか、「地方自治」という語を用いて説明せよ。", "choices": [], "answer": "", "modelAnswer": "市制町村制や府県制・郡制の制定は、府県・郡・市町村を三階級の自治団体とすることで地方自治及び分権の原則を実施し、地方人民に地方自活の責任を負わせるとともに公務への習熟を促し、立憲制の基礎を固めるものであった。", "explanation": "これらの地方制度整備には、山県有朋が中心となり、プロイセン人顧問モッセの助言を得ながら進められた。地方自治の育成は憲法体制を支える基盤として位置づけられた。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6294", "field": "近代", "difficulty": 3, "type": "choice", "question": "大日本帝国憲法の条項として正しいものはどれか。", "choices": ["天皇ハ帝国議会ノ協賛ヲ以テ立法権ヲ行フ", "内閣総理大臣ハ国務各大臣ヲ任免ス", "衆議院ノ議決ハ貴族院ニ優越ス", "天皇ハ内閣ノ輔弼ニヨリ統治権ヲ行使ス", "国民ハ法律ノ範囲内ニ於テ自由権ヲ有ス"], "answer": 0, "modelAnswer": "", "explanation": "大日本帝国憲法第5条は「天皇ハ帝国議会ノ協賛ヲ以テ立法権ヲ行フ」と定める。天皇は統治権の総攬者であり、内閣は各国務大臣が個別に天皇を輔弼する体制であった。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6295", "field": "外交史", "difficulty": 3, "type": "truefalse", "question": "下関条約により清国は朝鮮の独立を承認するとともに、遼東半島・台湾・澎湖諸島を日本に割譲した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "下関条約（1895年）では清国の朝鮮に対する宗主権放棄（朝鮮の独立確認）、遼東半島・台湾・澎湖諸島の割譲、賠償金2億両の支払いなどが定められた。ただし遼東半島は三国干渉により清国に返還された。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6296", "field": "社会経済", "difficulty": 4, "type": "essay", "question": "1912年に結成された友愛会が、1919年、1921年と改組を重ねて日本労働総同盟に至るまでの変遷を説明せよ。", "choices": [], "answer": "", "modelAnswer": "1912年に鈴木文治らによって労資協調主義の立場で結成された友愛会は、労働運動の高まりの中で1919年に大日本労働総同盟友愛会と改称して労働組合の全国的連合体へと再編され、1921年にはさらに日本労働総同盟と改称して、階級闘争主義的な性格を強めた全国組織となった。", "explanation": "友愛会は当初、労資協調を掲げる修養団体的性格が強かったが、第一次世界大戦期の労働運動の高揚を背景に、次第に労働組合としての実質を強め、日本労働総同盟として労働運動の中心組織に成長した。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6297", "field": "近代", "difficulty": 2, "type": "short", "question": "1918年、シベリア出兵を見越した米の投機的買占めなどによる米価高騰を背景に、富山県の主婦らの行動を発端として全国に広がった騒擾事件を何と呼ぶか。", "choices": [], "answer": "米騒動", "modelAnswer": "米騒動", "explanation": "米騒動は米価高騰に苦しんだ民衆が米屋や富商を襲撃するなどして全国に波及した騒擾で、寺内正毅内閣は軍隊を出動させて鎮圧したが、責任を問われて総辞職に追い込まれた。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6298", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "1922年、賀川豊彦や杉山元治郎らが中心となって結成した、全国的な小作農民の組合はどれか。", "choices": ["日本農民組合", "労働農民党", "農地委員会", "農会", "産業組合"], "answer": 0, "modelAnswer": "", "explanation": "第一次世界大戦後の農村不況の中、小作料引き下げを求める小作争議が頻発し、1922年には賀川豊彦・杉山元治郎らにより日本農民組合が結成され、小作農民の権利拡張運動を全国的に組織した。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6299", "field": "文化史", "difficulty": 4, "type": "essay", "question": "1920年代のプロレタリア文学の展開と、満州事変以後に生じた「転向文学」への変化について説明せよ。", "choices": [], "answer": "", "modelAnswer": "1921年創刊の『種蒔く人』などを舞台に、労働者の生活に根ざした作品を描くプロレタリア文学運動が展開し、徳永直の『太陽のない街』などが代表作となった。しかし満州事変を契機に国家によるナショナリズムの高揚と弾圧が強まると、社会主義から離脱する「転向」が広がり、島木健作らの転向文学が生まれた。", "explanation": "プロレタリア文学は労働運動・社会主義運動の高揚と連動して展開したが、治安維持法による弾圧と国家主義の強まりの中で急速に衰退し、思想的な「転向」を主題とする文学へと変化していった。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6300", "field": "近代", "difficulty": 3, "type": "short", "question": "1935年、貴族院議員でもあった憲法学者が唱えた学説が国体に反するとして激しく非難され、政府がこれを否認する声明を出すに至った学説論争を何と呼ぶか。", "choices": [], "answer": "天皇機関説事件（国体明徴問題）", "modelAnswer": "天皇機関説事件（国体明徴問題）", "explanation": "美濃部達吉の天皇機関説は天皇を国家の最高機関とする憲法学説として定説とされていたが、軍部・右翼から国体に反すると非難され、岡田啓介内閣は国体明徴声明を出してこれを否認した。美濃部は貴族院議員を辞職した。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6301", "field": "現代", "difficulty": 5, "type": "essay", "question": "1970年代前半に生じた「ドル・ショック（円切り上げ）」と「オイル・ショック」が、日本経済に与えた影響についてそれぞれ説明せよ。", "choices": [], "answer": "", "modelAnswer": "ドル・ショック（円切り上げ）は円高により日本製品の国際競争力を低下させる一方、オイル・ショックは原油価格の急騰を通じて生産コストを押し上げ、両者はともに高度経済成長を支えてきた内需拡大の構造に打撃を与え、日本経済を低成長時代へと転換させた。", "explanation": "1971年のニクソン・ショックによる円切り上げと1973年の第1次石油危機は、いずれも外生的なショックとして日本経済を直撃し、内需依存の高度成長から安定成長への移行を促した。（商学部2013年で問われた論点）", "source": "2013", "faculty": "商学部"},
  {"id": "q6320", "field": "古代", "difficulty": 3, "type": "short", "question": "『魏志』倭人伝に、邪馬台国の女王が「よく衆を惑わす」祭祀・呪術的な力を用いて統治したと記されている。この呪術的な統治手法を指す語を漢字二字で答えよ。", "choices": [], "answer": "鬼道", "modelAnswer": "鬼道", "explanation": "『魏志』倭人伝には卑弥呼が「鬼道を事とし、能く衆を惑わす」と記されており、司祭者的な性格を持つ王が呪術によって政治を行っていた古代の権力形成のあり方を示している。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6321", "field": "古代", "difficulty": 2, "type": "truefalse", "question": "6世紀、百済から仏教が伝えられた際、その受容をめぐって蘇我氏と物部氏の間で争いが生じた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "『日本書紀』によれば欽明天皇の時代に百済の聖明王から仏像・経典が伝えられたとされる（伝来年代には諸説ある）。仏教の受容に積極的な蘇我氏と、これに反対する物部氏との対立は、最終的に蘇我氏の勝利に終わった。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6322", "field": "古代", "difficulty": 2, "type": "short", "question": "聖徳太子が604年に定めたとされ、豪族に対して仏教の尊重や官人としての心得を説いた法令は何か。", "choices": [], "answer": "憲法十七条（十七条憲法）", "modelAnswer": "憲法十七条（十七条憲法）", "explanation": "憲法十七条は「篤く三宝を敬へ」と仏教への帰依を説くとともに、和を尊ぶことや天皇への服従など、官人・豪族の心得を示した。仏教が政治理念に組み込まれ、権力と結びついていく過程を示す史料である。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6323", "field": "古代", "difficulty": 2, "type": "choice", "question": "聖武天皇が741年、国家の安泰を仏教の力で図るために諸国に建立を命じた寺院は何か。", "choices": ["国分寺・国分尼寺", "四天王寺", "東大寺", "法隆寺", "大安寺"], "answer": 0, "modelAnswer": "", "explanation": "聖武天皇は国分寺建立の詔を発し、諸国に国分寺・国分尼寺の建立を命じるとともに、都には総国分寺として東大寺と大仏を造営させた。仏教による鎮護国家思想を体現する政策である。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6324", "field": "文化史", "difficulty": 3, "type": "choice", "question": "奈良時代に大寺院で研究された仏教教学の宗派、いわゆる南都六宗に含まれないものはどれか。", "choices": ["浄土宗", "三論宗", "法相宗", "律宗", "華厳宗"], "answer": 0, "modelAnswer": "", "explanation": "南都六宗は三論宗・成実宗・法相宗・倶舎宗・華厳宗・律宗の6つで、いずれも奈良時代の学問仏教として研究された。浄土宗は平安末期に法然が開いた鎌倉新仏教の一つであり、南都六宗には含まれない。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6325", "field": "中世", "difficulty": 3, "type": "short", "question": "南北朝時代から室町時代にかけて、地方の有力武士が血縁や地縁を根拠に結成した自律的な集団を何と呼ぶか。", "choices": [], "answer": "国人一揆", "modelAnswer": "国人一揆", "explanation": "国人一揆は地方の有力武士（国人）たちが一族一揆や地縁的な一揆を形成し、紛争解決や領主への対抗などのために共同で行動したもので、毛利氏など戦国大名の家臣団統制にも影響を与えた。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6326", "field": "中世", "difficulty": 4, "type": "essay", "question": "戦国時代、毛利氏の家臣団統制文書に見られる、家臣が「逃散」を行った場合の扱いについて説明せよ。", "choices": [], "answer": "", "modelAnswer": "毛利氏の家臣団統制文書では、家臣が逃散に及んだ場合、その内容を主君に注進した上で、その内は堪忍（我慢）して主君の下知に任せるべきことが定められており、家臣の自律的行動をある程度許容しつつも最終的には主君の裁定に服させる仕組みが示されている。", "explanation": "戦国大名は家臣団の自律性を一定程度残しながらも、主君への服属を強めていった。分国法の甲州法度之次第では逃散への対応がより厳格化し、理由を問わず処罰する規定に発展している。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6327", "field": "中世", "difficulty": 3, "type": "short", "question": "武田氏が定めた分国法で、家臣の逃散などを理由を問わず処罰すると定めた法典は何か。", "choices": [], "answer": "甲州法度之次第（信玄家法）", "modelAnswer": "甲州法度之次第（信玄家法）", "explanation": "甲州法度之次第は武田信玄が制定した分国法で、家臣の逃散を理由の如何を問わず処罰することを定めるなど、毛利氏の家臣団統制文書に比べてより主君の権限を強化した内容となっている。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6328", "field": "中世", "difficulty": 4, "type": "choice", "question": "応永年間（1394-1428年）に将軍足利持氏に背いて討たれた、鎌倉公方を補佐する関東管領はだれか。", "choices": ["上杉禅秀", "上杉謙信", "上杉憲実", "畠山政長", "土岐康行"], "answer": 0, "modelAnswer": "", "explanation": "上杉禅秀（氏憲）は関東管領であったが鎌倉公方足利持氏と対立し反乱を起こした（上杉禅秀の乱）が、幕府の支援を得た持氏方に討たれた。関東地方における幕府と鎌倉府の緊張関係を示す事件である。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6329", "field": "中世", "difficulty": 3, "type": "choice", "question": "毛利輝元が豊臣政権下で得た地位として正しいものはどれか。", "choices": ["小早川隆景の死後に大老とされた", "関ヶ原の戦いで東軍の盟主となった", "フランシスコ゠ザビエルを厚遇した", "織田信長に降伏して中国8か国を安堵された", "安芸国守護の家に生まれた"], "answer": 0, "modelAnswer": "", "explanation": "毛利輝元は豊臣政権下で五大老の一人となり、小早川隆景の死後にその地位を継いで大老に列した。関ヶ原の戦いでは西軍の盟主に擁立されたが、実際の指揮は行わず、戦後に領地を大幅に削減された。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6330", "field": "近世", "difficulty": 4, "type": "essay", "question": "江戸時代の百姓が土地を担保に借金をした際にみられた「無年季的請け戻し慣行」とはどのような慣行か説明せよ。", "choices": [], "answer": "", "modelAnswer": "借金の際に定められた返済期限（年季）が過ぎても、借りた元金さえ返済すれば、担保として貸し主に移動していた土地の権利を、いつでも元の持ち主が取り戻すことができるとする慣行であり、土地は個人の私有物ではないという観念を背景に、村社会全体で広く受け入れられていた。", "explanation": "この慣行は貧富の差の拡大に一定の歯止めをかけるセーフティネットとして機能した一方、幕府や藩が発令した法ではなく村社会の慣行として存在した点に特徴がある。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6331", "field": "近世", "difficulty": 2, "type": "choice", "question": "田畑を担保に入れる契約により登録され、年貢割り付けのもとになる台帳は何か。", "choices": ["検地帳", "宗門人別帳", "五人組帳", "過去帳", "出開帳"], "answer": 0, "modelAnswer": "", "explanation": "検地帳は田畑の面積・等級・耕作者名などを登録した台帳であり、年貢を賦課する際の基本台帳となった。質入れなどによる土地の権利移動があっても、検地帳の記載が年貢徴収の基礎とされた。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6332", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸幕府の直轄地のうち、美濃や飛騨などの広域の民政を担当した役職は何か。", "choices": ["郡代", "目付", "遠国奉行", "大番頭", "城代"], "answer": 0, "modelAnswer": "", "explanation": "郡代は幕府直轄領のうち特に広域の地域（美濃郡代・飛騨郡代など）の民政を担当した役人で、勘定奉行の支配下にあった。より小規模な幕領は代官が支配した。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6333", "field": "近代", "difficulty": 4, "type": "essay", "question": "明治政府が市制町村制・府県制郡制を制定した目的について、地方自治の観点から説明せよ。", "choices": [], "answer": "", "modelAnswer": "地方自治及び分権の原則を実施し、府県・郡・市町村を三階級の自治団体とすることで国家の基礎を強固にし、地方人民に地方自治の責任を負わせるとともに地方の公務に習熟させることを通じて、立憲制（憲法）を支える基盤を築くことを目的とした。", "explanation": "山県有朋らはプロイセン流の地方自治制度を参考にしながら、中央集権と地方自治を組み合わせた統治体制の構築を進めた。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6334", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "立憲改進党は、大隈重信を党首としてイギリス流の議院内閣制を主張し、地方の豪農商層を主な支持基盤として結成された。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "立憲改進党は1882年、大隈重信を中心に結成され、イギリス流の漸進的な議院内閣制を主張した。都市の実業家や地方の豪農商層に支持基盤を持ち、自由党とは異なる立場をとった。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6335", "field": "外交史", "difficulty": 3, "type": "short", "question": "1884年、日本の支援を受けた朝鮮の急進開化派によるクーデターが清国の介入で失敗に終わった事件を何と呼ぶか。", "choices": [], "answer": "甲申事変", "modelAnswer": "甲申事変", "explanation": "甲申事変は金玉均ら急進開化派が日本公使館の支援を得て起こしたクーデターだが、清国軍の介入により失敗した。この結果、朝鮮に対する清国の影響力がむしろ強まり、事後処理として日清両国は天津条約を結んだ。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6336", "field": "近代", "difficulty": 3, "type": "choice", "question": "1898年、自由党と進歩党の合同によって成立した憲政党を基礎とし、大隈重信を首相、板垣退助を内相とした日本初の政党内閣は何と呼ばれるか。", "choices": ["隈板内閣", "第2次伊藤内閣", "第1次山県内閣", "第1次松方内閣", "桂内閣"], "answer": 0, "modelAnswer": "", "explanation": "隈板内閣は大隈重信を総理、板垣退助を内務大臣とした、陸海軍大臣以外を政党員が占めた日本初の政党内閣であるが、共和演説事件などをめぐる内紛から憲政党が分裂し、短期間で崩壊した。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6337", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "1897年に結成された労働組合期成会は、高野房太郎や片山潜らによって組織され、その後1900年制定の治安警察法によって労働運動は大きく制約された。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "労働組合期成会は高野房太郎・片山潜らが労働組合の組織化を進めるために結成した団体である。1900年制定の治安警察法は労働者のストライキ権や団結権を制限し、労働組合期成会は衰退、1907年には社会民主党にも解散命令が出された。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6338", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "1911年に制定され、実施に5年を要した、少年・女性の就業時間制限などを定めた法律は何か。", "choices": ["工場法", "治安警察法", "労働組合法", "工場法施行令", "職工事情"], "answer": 0, "modelAnswer": "", "explanation": "工場法は1911年に制定されたが、資本家の反対もあって実施は1916年まで遅れた。少年の就業時間を10時間、女性を12時間とし、深夜業を禁止したが、適用対象は従業員15人以上の工場に限られ、内容は不十分なものであった。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6339", "field": "文化史", "difficulty": 3, "type": "short", "question": "1879年、全国画一的な学制を改め、町村を小学校設置単位とし地方への権限移譲を進めた法令は何か。", "choices": [], "answer": "教育令", "modelAnswer": "教育令", "explanation": "教育令は学制による画一的な政策への批判を受けて公布され、全国画一の学区制を廃止し、地方の実情に応じた教育制度への移行を図った。その後、森有礼文部大臣のもとで学校体系が1886年に整備された。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6340", "field": "文化史", "difficulty": 2, "type": "choice", "question": "1890年に発布され、忠君愛国を教育の基本理念として強調した勅語は何か。", "choices": ["教育勅語", "学制", "教育令", "学校令", "戊申詔書"], "answer": 0, "modelAnswer": "", "explanation": "教育勅語（教育に関する勅語）は1890年に発布され、忠君愛国を基本理念として学校教育に強い影響を与えた。1903年には国定教科書制度が導入され、教育内容への国家統制がさらに強まった。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6341", "field": "現代", "difficulty": 4, "type": "essay", "question": "1974年前後、日本経済が高度経済成長から安定成長へ転換する契機となった経済現象と、その内容を説明せよ。", "choices": [], "answer": "", "modelAnswer": "第1次オイルショックの影響により、物価の上昇と不況が同時に発生するスタグフレーションが生じ、高度経済成長は終焉を迎えた。田中角栄内閣期のこの現象を経て、日本経済は減量経営などを通じて安定成長へと移行した。", "explanation": "スタグフレーションは原油価格高騰によるコスト上昇と、それに伴う不況が同時進行する現象で、日本的経営とされた終身雇用・年功序列賃金などの高度成長期の仕組みも、この後見直しを迫られていくことになる。（商学部2014年で問われた論点）", "source": "2014", "faculty": "商学部"},
  {"id": "q6360", "field": "古代", "difficulty": 3, "type": "short", "question": "天武天皇の皇子で、皇位継承のライバルとみなされ、謀反の疑いをかけられて自害に追い込まれた人物は誰か。", "choices": [], "answer": "大津皇子", "modelAnswer": "大津皇子", "explanation": "大津皇子は文武・詩歌に優れた皇子であったが、天武天皇没後まもなく謀反の疑いで捕らえられ、自害させられた。持統天皇が自らの子である草壁皇子を皇位につけるための策謀とも言われる。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6361", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "文武天皇の死後、皇位は文武天皇の母である元明天皇に受け継がれ、ついで元明天皇の娘であり文武天皇の姉にあたる元正天皇が即位して、二代続けて女帝の治世となった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "文武天皇の急逝後、皇太子(首皇子)がまだ幼少だったため、文武の母元明天皇が中継ぎとして即位し、ついでその娘で文武の姉である元正天皇も即位した。二代続けての女帝である。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6362", "field": "古代", "difficulty": 2, "type": "short", "question": "和同開珎の流通を促進するため、蓄えた銭の額に応じて位階を昇進させるという奈良時代の法令を何というか。", "choices": [], "answer": "蓄銭叙位令", "modelAnswer": "蓄銭叙位令", "explanation": "708年、武蔵国から銅が献上されたことを機に和同開珎が鋳造されたが、貨幣流通の定着を図るため蓄銭叙位令が出された。しかし銭を貯め込む風潮を招き、かえって流通を妨げたため後に廃止された。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6363", "field": "古代", "difficulty": 3, "type": "short", "question": "藤原不比等と県犬養三千代との間に生まれ、聖武天皇の皇后となった人物は誰か。", "choices": [], "answer": "光明子(光明皇后)", "modelAnswer": "光明子(光明皇后)", "explanation": "光明子は藤原氏出身で初めて皇后となった人物であり、聖武天皇との間に基王をもうけたが夭逝し、皇女(のちの孝謙天皇)のみが成長した。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6364", "field": "古代", "difficulty": 3, "type": "choice", "question": "阿倍内親王(孝謙天皇)が譲位して即位した天皇と、その天皇を廃してみずから再び即位した後の天皇号の組み合わせとして正しいものはどれか。", "choices": ["淳仁天皇→称徳天皇", "聖武天皇→孝謙天皇", "文武天皇→元明天皇", "光仁天皇→桓武天皇"], "answer": 0, "modelAnswer": "", "explanation": "孝謙天皇はいったん淳仁天皇に位を譲ったが、対立の末に淳仁天皇を廃し、みずから重祚して称徳天皇となった。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6365", "field": "古代", "difficulty": 3, "type": "short", "question": "称徳天皇の死後、その寵愛を受けた僧の権勢が終わりを迎え、群臣に擁立されて即位した天智天皇の孫にあたる天皇は誰か。", "choices": [], "answer": "光仁天皇", "modelAnswer": "光仁天皇", "explanation": "称徳天皇が没すると道鏡は失脚し、群臣は天智天皇の孫にあたる白壁王を擁立した。これが光仁天皇であり、桓武天皇の父にあたる。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6366", "field": "古代", "difficulty": 2, "type": "truefalse", "question": "藤原不比等は大宝律令の編纂に参加し、養老律令の編纂にも中心的な役割を果たし、また平城京遷都にも尽力した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原不比等は藤原鎌足の子で、大宝律令・養老律令の編纂に関与し、娘の宮子・光明子を通じて皇室との結びつきを強めながら平城京遷都にも尽力した政治家である。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6367", "field": "古代", "difficulty": 3, "type": "short", "question": "舒明天皇の皇后であり、舒明天皇の死後に自ら即位して女帝となった人物は誰か。", "choices": [], "answer": "皇極天皇", "modelAnswer": "皇極天皇", "explanation": "舒明天皇の皇后であった宝皇女は、舒明天皇の死後に即位して皇極天皇となり、乙巳の変ののち重祚して斉明天皇となった。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6368", "field": "古代", "difficulty": 3, "type": "choice", "question": "聖武天皇の時代に行われた都の移転について、正しい順序はどれか。", "choices": ["恭仁京→難波宮→紫香楽宮", "難波宮→恭仁京→紫香楽宮", "紫香楽宮→難波宮→恭仁京", "難波宮→紫香楽宮→恭仁京"], "answer": 0, "modelAnswer": "", "explanation": "聖武天皇は740年の藤原広嗣の乱を機に平城京を離れ、恭仁京、ついで難波宮、さらに紫香楽宮へと遷都を重ね、最終的に平城京へ戻った。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6369", "field": "中世", "difficulty": 3, "type": "short", "question": "1297年、鎌倉幕府が御家人の窮乏を救うために出した、御家人の所領の質入れ・売却を禁じ、越訴を停止した法令を何というか。", "choices": [], "answer": "永仁の徳政令", "modelAnswer": "永仁の徳政令", "explanation": "永仁の徳政令は執権北条貞時の時代に出され、御家人が売却・質入れした所領を無償で取り戻させる一方、越訴(再審請求)を停止するなど、幕府財政と御家人統制の両面から出された法令である。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6370", "field": "中世", "difficulty": 4, "type": "truefalse", "question": "三浦泰村一族が滅ぼされた宝治合戦は、安達泰盛一族が滅ぼされた霜月騒動よりも後に起きた出来事である。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "三浦泰村一族が滅ぼされた宝治合戦は1247年、安達泰盛一族が滅ぼされた霜月騒動は1285年であり、宝治合戦の方が先に起きている。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6371", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉幕府において執権を補佐する役職として、北条泰時が執権に就任した際に叔父の北条時房が初めて就任した役職は何か。", "choices": [], "answer": "連署", "modelAnswer": "連署", "explanation": "連署は執権を補佐する役職で、北条泰時が執権に就任した際に叔父の北条時房が初代連署となったのが始まりとされる。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6372", "field": "中世", "difficulty": 2, "type": "short", "question": "1577年、織田信長が本拠地の城下町に対して出した、座・諸役・諸公事を免除し自由な商業活動を認めた法令を何というか。", "choices": [], "answer": "楽市令(楽市楽座令)", "modelAnswer": "楽市令(楽市楽座令)", "explanation": "織田信長は安土などの城下町で楽市令を発し、座の特権や各種課役を免除することで商人・職人を集め、城下の繁栄を図った。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6373", "field": "近世", "difficulty": 2, "type": "choice", "question": "第3代将軍徳川家光の在職中の出来事として誤っているものはどれか。", "choices": ["参勤交代の制度化", "支倉常長の帰国", "島原の乱", "田畑永代売買の禁止"], "answer": 1, "modelAnswer": "", "explanation": "支倉常長がスペイン・ローマへの使節から帰国したのは1620年で、これは第2代将軍徳川秀忠の時代である。参勤交代の制度化・島原の乱・田畑永代売買の禁止はいずれも徳川家光の在職中の出来事である。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6374", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "新井白石は、勘定奉行荻原重秀による貨幣改鋳政策を批判し、朝鮮からの国書における将軍の称号を「日本国王」に改めさせるなど、正徳の治と呼ばれる政治を行った。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "新井白石は第6代将軍徳川家宣・第7代将軍徳川家継に仕え、荻原重秀の貨幣政策を批判して正徳小判を鋳造させたほか、朝鮮通信使への待遇簡素化や将軍称号の「日本国王」への変更を進めた。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6375", "field": "外交史", "difficulty": 3, "type": "choice", "question": "江戸時代に日本へ来航した人物とその来航地の組み合わせとして正しいものはどれか。", "choices": ["シドッチ―屋久島", "レザノフ―長崎", "ラクスマン―根室", "ビッドル―下田"], "answer": 2, "modelAnswer": "", "explanation": "ラクスマンは1792年、漂流民大黒屋光太夫らを伴い根室に来航して通商を求めた。シドッチは屋久島に上陸し、レザノフは長崎に来航、ビッドルは浦賀に来航している。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6376", "field": "近代", "difficulty": 4, "type": "truefalse", "question": "血盟団事件は「一人一殺」を掲げて政財界要人を暗殺した右翼テロ事件であり、その直後に発生した五・一五事件では海軍青年将校らが首相官邸を襲撃して犬養毅首相を殺害し、これによって政党内閣の時代が終わりを告げた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "血盟団事件では日蓮宗僧侶井上日召に率いられた一団が井上準之助・団琢磨を暗殺し、続く五・一五事件では海軍青年将校らが犬養毅首相を射殺した。これにより政党内閣は途絶え、軍部の政治的発言力が強まった。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6377", "field": "外交史", "difficulty": 2, "type": "short", "question": "1854年の日米和親条約で、日本がアメリカに対して一方的に認めた、通商上の待遇を他国より不利にしないという条項を何というか。漢字で記せ。", "choices": [], "answer": "片務的最恵国待遇", "modelAnswer": "片務的最恵国待遇", "explanation": "日米和親条約は下田・箱館の開港のほか、アメリカに対して片務的最恵国待遇を認めるなど、日本に不利な内容を含んでいた。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6378", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "1872年に開設された官営富岡製糸場では、フランス人技師の指導のもとで熟練工の養成が図られ、生糸の輸出拡大に貢献した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "富岡製糸場はフランスの製糸技術を導入した官営模範工場で、フランス人技師の指導のもとで工女の技術養成が行われ、器械製糸の普及に貢献した。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6379", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "日清戦争前後の日本の産業革命に関する記述として誤っているものはどれか。", "choices": ["綿糸の生産量が輸入量を上回った。", "紡績業を中心に産業革命が進展した。", "大阪紡績会社は輸入紡績機の導入で成果をあげた。", "綿糸の輸出量が国内生産量そのものを上回るようになった。"], "answer": 3, "modelAnswer": "", "explanation": "1890年に綿糸の生産量が輸入量を上回り、1897年には綿糸の輸出量が輸入量を超えたが、輸出量が国内生産量そのものを上回ることはあり得ない。日本の産業革命は紡績業を中心に進展した。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6380", "field": "現代", "difficulty": 3, "type": "short", "question": "終戦直後、GHQ最高司令官マッカーサーが幣原喜重郎首相に対して口頭で示した、女性参政権の付与や労働組合結成の奨励などを含む一連の改革指示を何と呼ぶか。", "choices": [], "answer": "五大改革指示", "modelAnswer": "五大改革指示", "explanation": "マッカーサーは女性参政権の付与、労働組合の結成奨励、教育制度の自由主義的改革、秘密警察などの廃止、経済機構の民主化からなる五大改革を幣原首相に指示し、戦後改革の出発点となった。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6381", "field": "近代", "difficulty": 4, "type": "truefalse", "question": "ロンドン海軍軍縮会議で、日本の対英米補助艦保有量はほぼ7割に決定されたが、大型巡洋艦については対英米7割は認められず、これを機に統帥権干犯問題が政治問題化した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "ロンドン海軍軍縮条約では補助艦全体の対英米比率が約7割とされたが、大型巡洋艦の7割は認められなかった。浜口内閣がこれを受け入れたことに対し、野党や海軍軍令部などから統帥権干犯であるとの批判が起こった。（商学部2015年で問われた論点）", "source": "2015", "faculty": "商学部"},
  {"id": "q6400", "field": "古代", "difficulty": 3, "type": "choice", "question": "『古事記』編纂の基礎となったとされる、大王の皇位継承を中心とした伝承・記録をまとめたものと、古代の神話や伝承をまとめたものの組み合わせとして正しいものはどれか。", "choices": ["帝紀と旧辞", "国記と天皇記", "風土記と万葉集", "日本書紀と続日本紀"], "answer": 0, "modelAnswer": "", "explanation": "『古事記』は、大王の皇位継承を中心とした伝承・記録をまとめた「帝紀」と、古代の神話・伝承をまとめた「旧辞」をもとに、稗田阿礼の誦習を太安万侶が筆録して編纂されたと伝えられる。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6401", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "藤原京は、中国の書物である『周礼』を範として都城を設計したと推測されており、大和三山に囲まれた立地にあった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原京は中国周代の制度を記した『周礼』の考工記を参考に設計されたと考えられており、大和三山(畝傍山・耳成山・香久山)に囲まれた地に営まれた日本初の本格的な都城である。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6402", "field": "文化史", "difficulty": 3, "type": "choice", "question": "『万葉集』についての説明として誤っているものはどれか。", "choices": ["全20巻からなる。", "万葉仮名が用いられている。", "巻14には東歌が収められている。", "大伴旅人が単独で編纂した。"], "answer": 3, "modelAnswer": "", "explanation": "『万葉集』の編纂には大伴家持が深く関わったとされ、大伴旅人が単独で編纂したとする説は誤り。全20巻からなり、万葉仮名で表記され、東歌や防人歌も収められている。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6403", "field": "文化史", "difficulty": 2, "type": "short", "question": "平安時代中期、地獄と極楽の様相を描いて浄土信仰を盛んにした『往生要集』を著した僧は誰か。", "choices": [], "answer": "源信(恵心僧都)", "modelAnswer": "源信(恵心僧都)", "explanation": "源信は比叡山の僧で、『往生要集』を著して念仏による極楽往生の教えを説き、貴族社会を中心に浄土信仰を広める大きな役割を果たした。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6404", "field": "中世", "difficulty": 3, "type": "short", "question": "1336年、足利尊氏が京都を制圧したのち、今後の政治方針として示した基本方針を何というか。", "choices": [], "answer": "建武式目", "modelAnswer": "建武式目", "explanation": "建武式目は足利尊氏が京都を掌握し持明院統の天皇を擁立した際に示した施政方針で、幕府を鎌倉に置くか京都に置くかを論じ、倹約や人材登用の必要性などを掲げている。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6405", "field": "中世", "difficulty": 3, "type": "choice", "question": "後醍醐天皇による建武の新政に関する記述として誤っているものはどれか。", "choices": ["武士社会の慣習を軽視し武士の不満を招いた。", "天皇への権限集中を目指した。", "記録荘園券契所を設けた。", "足利尊氏を征夷大将軍に任じ幕府開設を全面的に支援した。"], "answer": 3, "modelAnswer": "", "explanation": "建武の新政は武家社会の慣習を軽視したため武士の不満を招き、足利尊氏はやがてこれに反旗を翻した。天皇は征夷大将軍を尊氏に与えておらず、新政は武士の支持を得られず短期間で崩壊した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6406", "field": "中世", "difficulty": 3, "type": "short", "question": "1350年から51年にかけて、足利尊氏と弟の足利直義との対立を軸に展開された室町幕府内部の内乱を何というか。", "choices": [], "answer": "観応の擾乱", "modelAnswer": "観応の擾乱", "explanation": "観応の擾乱は、尊氏の執事高師直と対立した足利直義が尊氏と争った内乱で、南朝方も巻き込みながら展開し、以後の南北朝内乱を長期化させる要因となった。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6407", "field": "中世", "difficulty": 3, "type": "short", "question": "派手な服装や振る舞いを好み、「ばさら大名」として知られた近江の武士は誰か。", "choices": [], "answer": "佐々木導誉(京極高氏)", "modelAnswer": "佐々木導誉(京極高氏)", "explanation": "佐々木導誉は近江の守護大名で、華美な服装や豪奢な振る舞いを好んだことから「ばさら大名」の代表として知られ、室町幕府草創期に活躍した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6408", "field": "近世", "difficulty": 3, "type": "short", "question": "徳川家康の死後、その霊を祀るために日光に建立された社の、朝廷から与えられた神号は何か。", "choices": [], "answer": "東照大権現", "modelAnswer": "東照大権現", "explanation": "家康の死後、その神号をめぐり吉田神道と山王一実神道の間で論争があったが、天海の主張する山王一実神道に基づき東照大権現の神号が定められ、日光東照宮に祀られた。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6409", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸幕府が大名に課した負担・義務に該当しないものはどれか。", "choices": ["参勤交代", "お手伝い普請", "朝鮮通信使の通行への人馬動員", "キリシタンの棄教強制"], "answer": 3, "modelAnswer": "", "explanation": "参勤交代・お手伝い普請・朝鮮通信使通行への人馬動員はいずれも幕府が大名に課した軍役・負担であるが、キリシタンの棄教強制は宗門改めなど宗教統制策であり、大名への軍役負担とは性質が異なる。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6410", "field": "近世", "difficulty": 4, "type": "truefalse", "question": "修験道の宗教者は山伏または修験者と呼ばれ、その統制は江戸時代を通じて吉田家が担った。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "修験道の宗教者は修験者または山伏と呼ばれ、天台系の本山派(聖護院を本山)と真言系の当山派(醍醐寺三宝院を本山)という組織のもとにあった。陰陽道を統制したのが土御門家であるのに対し、修験道の統制を吉田家が担ったとするのは誤りである。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6411", "field": "近代", "difficulty": 2, "type": "short", "question": "1882年、大隈重信が政治・法律の教育を中心として開校し、のちに早稲田大学となった学校を何というか。", "choices": [], "answer": "東京専門学校", "modelAnswer": "東京専門学校", "explanation": "東京専門学校は立憲改進党の党首であった大隈重信が開校し、政治・法律の教育を中心に「学問の独立」を掲げて自由主義的な教育を行った。後に学校令により正式に早稲田大学として認可された。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6412", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "教育勅語は第一次山県有朋内閣のときに発布され、その奉読式で拝礼をしなかったとして内村鑑三が教職を追われる事件が起きた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "教育勅語は1890年、第一次山県有朋内閣のもとで発布された。第一高等中学校での奉読式に際し拝礼を拒んだ内村鑑三が教職を追われる不敬事件が起きている。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6413", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "足尾銅山鉱毒事件に関する記述として誤っているものはどれか。", "choices": ["古河市兵衛が経営する銅山から鉱毒が流出した。", "田中正造は議会や天皇への直訴を通じて操業停止を訴えた。", "政府は鉱毒予防を命じ、一時操業を停止させた。", "政府は谷中村を存続させ鉱毒被害民を保護した。"], "answer": 3, "modelAnswer": "", "explanation": "足尾鉱毒事件では古河市兵衛経営の銅山から鉱毒が渡良瀬川流域に流出し、田中正造が議会や天皇への直訴を通じて訴えた。政府は一時操業停止を命じたものの、最終的には遊水池化のため谷中村を廃村とした。「谷中村を存続させ保護した」というのは誤り。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6414", "field": "社会経済", "difficulty": 2, "type": "short", "question": "松方正義が主導し、緊縮財政による紙幣整理を通じて銀本位制の確立に至った財政政策を何というか。", "choices": [], "answer": "松方財政", "modelAnswer": "松方財政", "explanation": "松方正義は増税と歳出緊縮によるデフレ政策を進め、不換紙幣の整理と日本銀行を中心とした銀兌換制度の確立を実現し、通貨制度の安定を図った。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6415", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "1872年制定の国立銀行条例では兌換義務が厳しかったため設立された銀行数はわずか4行にとどまったが、1876年の改正で兌換義務が緩和されると設立が急増し、約150行にのぼった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "1872年の国立銀行条例は正貨兌換の義務が厳しく設立条件が厳格だったため設立は4行にとどまったが、1876年の改正で兌換義務が緩和されると不換紙幣の発行が可能になり、国立銀行の設立が急増して約150行に達した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6416", "field": "社会経済", "difficulty": 5, "type": "essay", "question": "1927年の昭和金融恐慌が全国的な信用不安を引き起こした経緯と、その後1930年に断行された金解禁の目的について、80字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "若槻内閣の片岡蔵相の失言を機に取付け騒ぎが広がり、鈴木商店関連の台湾銀行など大銀行が休業に追い込まれ信用不安が全国化した。その後浜口内閣は円高誘導により輸出品価格を割高にし、生産性の低い企業の整理を促す目的で金解禁を断行した。", "explanation": "1927年、若槻礼次郎内閣の片岡直温蔵相の失言から取付け騒ぎが起こり、鈴木商店の経営破綻とそれに伴う台湾銀行の危機などが重なって金融恐慌が全国化した。浜口雄幸内閣の井上準之助蔵相は、円高への誘導を通じて輸出品価格を割高に導き、国際競争力の弱い企業の整理・淘汰を促すことを意図して金解禁を断行した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6417", "field": "現代", "difficulty": 2, "type": "short", "question": "1985年9月、先進5か国が協調してドル高是正のための為替介入で合意し、急速な円高をもたらした合意を何というか。", "choices": [], "answer": "プラザ合意", "modelAnswer": "プラザ合意", "explanation": "プラザ合意はニューヨークのプラザホテルで開かれた先進5か国(日米英仏独)蔵相・中央銀行総裁会議での合意で、これにより急速な円高が進行し、輸出型産業が打撃を受けた。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6418", "field": "現代", "difficulty": 3, "type": "truefalse", "question": "プラザ合意後の円高不況に対応するため、政府・日本銀行は内需主導型の経済を促すべく超低金利政策や公共投資の拡大を行ったが、これが金融機関による投機的な融資を助長し、バブル経済の発生につながった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "円高不況対策として低金利政策・公共投資拡大が行われた結果、余剰資金が土地・株式への投機的な投資に向かい、地価・株価が急騰するバブル経済が生じた。その後の金融引き締めによりバブルは崩壊し、不良債権問題が深刻化した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6419", "field": "現代", "difficulty": 3, "type": "short", "question": "バブル崩壊後、規制やコスト高を嫌う日本企業がアジアなどへ工場移転を進めた結果、国内産業の一部が衰退する現象を何というか。", "choices": [], "answer": "産業の空洞化", "modelAnswer": "産業の空洞化", "explanation": "バブル崩壊後、不良債権問題や実体経済の不況を受け、企業は事業整理や人員削減とあわせて海外、特にアジア諸国への生産拠点移転を進め、これにより国内産業の一部が衰退する産業の空洞化が進行した。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6420", "field": "古代", "difficulty": 3, "type": "short", "question": "平安時代中期、地方政治の実情や国家財政の窮乏を訴え、「意見封事十二箇条」を醍醐天皇に奉った学者・政治家は誰か。", "choices": [], "answer": "三善清行", "modelAnswer": "三善清行", "explanation": "三善清行は914年、律令制の実情に即した地方政治の改革などを説いた「意見封事十二箇条」を醍醐天皇に提出したことで知られる。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6421", "field": "文化史", "difficulty": 3, "type": "short", "question": "藤原道長が著し、自筆原本も現存して近年ユネスコ「世界の記憶」に登録された日記は何か。", "choices": [], "answer": "御堂関白記", "modelAnswer": "御堂関白記", "explanation": "『御堂関白記』は藤原道長が長期間書き継いだ日記で、平安貴族の政務や生活を知る第一級史料であり、自筆本が現存する希少性から2013年にユネスコ「世界の記憶」に登録された。（商学部2016年で問われた論点）", "source": "2016", "faculty": "商学部"},
  {"id": "q6440", "field": "古代", "difficulty": 3, "type": "choice", "question": "桓武天皇が行った政治改革として正しいものはどれか。", "choices": ["雑徭の期間を年間40日に減らした。", "班田の期間を6年に改めた。", "公出挙の利率を2割に引き上げた。", "隼人を新たに征討した。"], "answer": 0, "modelAnswer": "", "explanation": "桓武天皇は雑徭の期間を年間60日から40日に減らし、班田の期間は6年から12年に改め、公出挙の利率も5割から3割へ引き下げるなど、民衆の負担軽減を図る改革を進めた。隼人征討はすでに奈良時代前半に行われていた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6441", "field": "古代", "difficulty": 3, "type": "short", "question": "桓武天皇の弟で、藤原種継暗殺事件に関与した疑いをかけられ、皇太子を廃されたのち配流される途中で死去した人物は誰か。", "choices": [], "answer": "早良親王", "modelAnswer": "早良親王", "explanation": "長岡京造営長官藤原種継が暗殺された事件に関与したとされた早良親王は、皇太子の地位を廃され淡路国へ配流される途中で絶食し死去した。その後、桓武天皇の身辺に不幸が続いたため早良親王の怨霊を鎮める措置がとられた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6442", "field": "古代", "difficulty": 3, "type": "short", "question": "嵯峨天皇と平城太上皇とが対立した「二所朝廷」の政変に際し、天皇の機密文書を扱わせるために嵯峨天皇が新設した令外官は何か。", "choices": [], "answer": "蔵人所(蔵人頭)", "modelAnswer": "蔵人所(蔵人頭)", "explanation": "嵯峨天皇は平城太上皇との対立(平城太上皇の変、薬子の変)に際し、機密保持のため蔵人所を設置し、藤原冬嗣らを蔵人頭に任じてこの政争に勝利した。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6443", "field": "古代", "difficulty": 4, "type": "essay", "question": "承和の変と応天門の変が、藤原北家の政治的地位確立にどのような役割を果たしたか、60字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "承和の変で伴健岑・橘逸勢ら、応天門の変で伴善男ら他氏族の有力者を退けることで、藤原北家は他氏排斥を進め、摂政・関白の地位を独占する基盤を築いた。", "explanation": "承和の変(842年)では伴健岑・橘逸勢が配流され、応天門の変(866年)では大納言伴善男が失脚するなど、藤原北家は他氏排斥を通じてライバルを退け、藤原良房・基経の代に摂政・関白の地位を確立していった。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6444", "field": "中世", "difficulty": 2, "type": "short", "question": "保元・平治の乱を経て勢力を伸ばし、武士として初めて太政大臣に就任した人物は誰か。", "choices": [], "answer": "平清盛", "modelAnswer": "平清盛", "explanation": "平清盛は保元の乱・平治の乱を勝ち抜いて勢力を拡大し、1167年に武士として初めて太政大臣に就任した。娘の徳子を高倉天皇に入内させるなど、朝廷とも姻戚関係を結び権勢を築いた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6445", "field": "中世", "difficulty": 3, "type": "choice", "question": "日宋貿易に関する記述として正しいものはどれか。", "choices": ["日本からの輸出品には金・硫黄・漆器などがあった。", "宋が南宋になると貿易は途絶えた。", "貿易の窓口として長崎が開かれた。", "日本からの輸出品の中心は生糸であった。"], "answer": 0, "modelAnswer": "", "explanation": "日宋貿易では金・硫黄・漆器・刀剣などが日本から輸出され、宋銭・陶磁器・書籍などが輸入された。平清盛は瀬戸内海航路を整備し大輪田泊を修築するなど貿易振興に努め、南宋期にも貿易は継続した。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6446", "field": "中世", "difficulty": 2, "type": "short", "question": "1274年、モンゴル・高麗軍が北九州に来襲した出来事を何というか。", "choices": [], "answer": "文永の役", "modelAnswer": "文永の役", "explanation": "文永の役では元・高麗の連合軍が対馬・壱岐を経て博多湾に来襲し、幕府は御家人だけでなく本所一円地の住人にも動員をかけて防戦にあたらせた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6447", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "戦国時代の堺は、会合衆と呼ばれる有力商人の合議によって自治的な町政運営が行われていたが、織田信長によって直轄領とされた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "堺は会合衆による自治都市として栄えたが、織田信長はその経済力に着目して直轄領とし、自治権を制限した。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6448", "field": "近世", "difficulty": 3, "type": "short", "question": "オランダ商館の医師ケンペルの著作を、志筑忠雄が翻訳・抄訳する際に用いたことで広まったとされる、江戸幕府の対外関係のあり方を表す語は何か。", "choices": [], "answer": "鎖国", "modelAnswer": "鎖国", "explanation": "「鎖国」の語は、ケンペルの著作を志筑忠雄が翻訳した際に用いたことで広まったとされ、それ以前の日本人はこの対外関係の仕組みをこのように認識していなかった。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6449", "field": "外交史", "difficulty": 3, "type": "choice", "question": "江戸時代の朝鮮通信使に関する記述として正しいものはどれか。", "choices": ["当初は日本からの捕虜返還を求める使節であった。", "将軍代替わりごとに派遣が義務づけられ、幕末まで継続した。", "将軍の権威を示すため朝鮮から一方的に派遣させた朝貢使節であった。", "来日の目的は一貫して軍事情報の収集のみであった。"], "answer": 0, "modelAnswer": "", "explanation": "朝鮮通信使は当初、豊臣秀吉の朝鮮侵略の際に日本へ連行された朝鮮人捕虜の返還を求める使節(回答兼刷還使)として始まり、後には将軍就任を祝う目的の使節「通信使」として位置づけられた。財政難を理由に対馬での簡略な応接に変更され、1811年を最後に派遣は停止された。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6450", "field": "外交史", "difficulty": 3, "type": "short", "question": "1811年、国後島で測量中のロシア軍人が幕府に捕らえられた事件をきっかけに悪化した日露関係が、高田屋嘉兵衛の尽力によって緩和された事件を何というか。", "choices": [], "answer": "ゴローニン事件", "modelAnswer": "ゴローニン事件", "explanation": "ゴローニン事件では、ロシア軍艦艦長ゴローニンが国後島で捕らえられたが、その後、日本人商人高田屋嘉兵衛の仲介などにより両国関係の緊張は緩和された。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6451", "field": "近世", "difficulty": 4, "type": "choice", "question": "ペリー来航を契機に実施された安政の改革に関する記述として誤っているものはどれか。", "choices": ["阿部正弘が中心となって行われた。", "徳川斉昭が幕政に参加した。", "江戸湾に台場が築かれた。", "五品江戸廻送令が発令された。"], "answer": 3, "modelAnswer": "", "explanation": "安政の改革は老中阿部正弘が中心となり、徳川斉昭の幕政参加、江戸湾への台場築造、大船建造の禁の解除などが行われた。五品江戸廻送令は1860年、貿易開始後の物価対策として出されたもので、安政の改革とは時期・目的が異なる。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6452", "field": "近代", "difficulty": 3, "type": "short", "question": "1905年、ポーツマス条約の内容への不満から東京日比谷公園での講和反対国民大会を機に発生した暴動事件を何というか。", "choices": [], "answer": "日比谷焼打事件", "modelAnswer": "日比谷焼打事件", "explanation": "日比谷焼打事件は、ポーツマス条約で賠償金が得られなかったことへの不満から起きた暴動で、警察署・内務大臣官邸・政府系新聞社などが襲撃され、戒厳令が敷かれる事態となった。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6453", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "第1次伊藤博文内閣では、皇室事務や華族の管理を担当する宮内省が内閣の外に置かれ、伊藤自身が宮内大臣を兼任した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "第1次伊藤博文内閣は皇室事務や華族管理を担う宮内省を内閣に属さない機関として閣外に置き、伊藤博文が宮内大臣を兼任した。同内閣はほかに文官任用令の制定、議院法・衆議院議員選挙法・貴族院令の公布なども行っている。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6454", "field": "外交史", "difficulty": 2, "type": "short", "question": "日清戦争後の下関条約で日本が獲得した遼東半島について、ロシア・フランス・ドイツの3国が清への返還を求めた出来事を何というか。", "choices": [], "answer": "三国干渉", "modelAnswer": "三国干渉", "explanation": "三国干渉により日本は遼東半島を清に返還したが、その後ロシアが旅順・大連地域を清から租借し、日露戦争後にはその租借権を日本が譲り受けた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6455", "field": "近代", "difficulty": 4, "type": "choice", "question": "日露戦争後の社会主義・労働運動に関する記述として正しいものはどれか。", "choices": ["友愛会が設立された。", "平民社が解散した。", "社会主義協会に結社禁止命令が出された。", "治安警察法が制定された。"], "answer": 0, "modelAnswer": "", "explanation": "友愛会は1912年、鈴木文治によって設立された労働団体で、日露戦争後の出来事にあたる。平民社の解散、社会主義協会への結社禁止命令、治安警察法の制定はいずれも日露戦争(1904-05年)より前の出来事である。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6456", "field": "社会経済", "difficulty": 4, "type": "choice", "question": "政商とその払い下げを受けた鉱山の組み合わせとして正しいものはどれか。", "choices": ["三井―高島炭鉱", "三菱―別子銅山", "古河―阿仁銅山", "住友―生野銀山"], "answer": 2, "modelAnswer": "", "explanation": "高島炭鉱は三菱、生野銀山と佐渡金山も三菱が払い下げを受けて経営し、別子銅山は住友がもともと江戸時代から経営していた自山で払い下げ物件ではない。阿仁銅山は古河市兵衛が払い下げを受けて経営を発展させた鉱山である。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6457", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "日露戦争後、池貝鉄工所は世界水準の精度をもつ旋盤を完成させるなど、日本の工作機械技術は着実に向上した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "池貝鉄工所は日露戦争後、アメリカ製旋盤に匹敵する精度の旋盤を国産化し、日本の工作機械工業の発展を示す象徴的な事例となった。同時期には日本製鋼所など民間の鉄鋼メーカーも設立された。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6458", "field": "社会経済", "difficulty": 3, "type": "short", "question": "1931年、大蔵大臣として金輸出を再禁止し、円安を通じてアジア市場への輸出拡大を図った人物は誰か。", "choices": [], "answer": "高橋是清", "modelAnswer": "高橋是清", "explanation": "高橋是清は犬養毅内閣の大蔵大臣として金輸出再禁止を断行し、これにより円相場が下落(円安)して、アジア市場への綿織物などの輸出が拡大した。あわせて赤字国債発行による財政支出拡大で恐慌からの脱出を図った。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6459", "field": "現代", "difficulty": 3, "type": "choice", "question": "ドッジ・ラインに関する記述として正しいものはどれか。", "choices": ["インフレ抑制のため均衡予算を編成させた。", "1ドル=308円の単一為替レートを設定した。", "シャウプ勧告に先立って実施された社会保障改革である。", "朝鮮戦争後に実施された内需拡大策である。"], "answer": 0, "modelAnswer": "", "explanation": "ドッジ・ラインは、インフレ収束のため赤字を許さない均衡予算の編成を求める緊縮財政政策で、1ドル=360円の単一為替レートの設定も行われた。これにより深刻な不況(安定恐慌)が生じ、下山事件・松川事件などの影響もあって労働運動は打撃を受けた。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6460", "field": "現代", "difficulty": 3, "type": "short", "question": "高度経済成長期に確立した、終身雇用・年功賃金とならぶ、企業別労働組合を軸とする労使関係の慣行を何というか。", "choices": [], "answer": "労資協調", "modelAnswer": "労資協調", "explanation": "高度経済成長期には、終身雇用・年功賃金・労資協調を特徴とする日本的経営が確立し、企業別労働組合を通じた安定的な労使関係が定着した。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6461", "field": "現代", "difficulty": 3, "type": "choice", "question": "高度経済成長期における好況の名称を、始まった時期の早い順に並べたものはどれか。", "choices": ["神武景気―岩戸景気―オリンピック景気―いざなぎ景気―列島改造ブーム", "岩戸景気―神武景気―オリンピック景気―いざなぎ景気―列島改造ブーム", "神武景気―岩戸景気―いざなぎ景気―オリンピック景気―列島改造ブーム", "岩戸景気―いざなぎ景気―神武景気―オリンピック景気―列島改造ブーム"], "answer": 0, "modelAnswer": "", "explanation": "高度経済成長期の好況は、神武景気(1954年末~)、岩戸景気(1958年~)、オリンピック景気(1962年~)、いざなぎ景気(1965年~)、列島改造ブーム(1972年~)の順で展開した。（商学部2017年で問われた論点）", "source": "2017", "faculty": "商学部"},
  {"id": "q6480", "field": "古代", "difficulty": 2, "type": "choice", "question": "江戸時代に福岡県志賀島で発見され、後漢の光武帝が倭の奴国王に授けたと考えられている金印に刻まれた文字として正しいものを選べ。", "choices": ["親魏倭王", "漢委奴国王", "日本国王", "大倭王"], "answer": 1, "modelAnswer": "", "explanation": "『後漢書』東夷伝には、紀元57年に倭の奴国王の使者が洛陽に派遣され、光武帝から印綬を授けられたことが記されている。この印は江戸時代に志賀島から発見された金印と推測され、印文には「漢委奴国王」と刻まれている。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6481", "field": "古代", "difficulty": 2, "type": "choice", "question": "3世紀に邪馬台国の女王卑弥呼が魏に使者を送った際、魏の皇帝から与えられたとされる称号はどれか。", "choices": ["親魏倭王", "漢委奴国王", "安東大将軍倭王", "日本国王"], "answer": 0, "modelAnswer": "", "explanation": "後漢が滅び魏・呉・蜀が並び立つ三国時代、邪馬台国の女王卑弥呼は魏の皇帝に使者を送り、「親魏倭王」の称号と金印紫綬を授けられた。卑弥呼の死後は男王が立って国内が乱れ、壱与（台与）が女王となっておさまったとされる。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6482", "field": "外交史", "difficulty": 3, "type": "short", "question": "4世紀末以降、倭が朝鮮半島に進出し百済・新羅を臣従させたが高句麗の好太王（広開土王）に撃退されたという内容が刻まれた、中国吉林省集安市にある石碑の名称を答えよ。", "choices": [], "answer": "好太王碑（広開土王碑）", "modelAnswer": "好太王碑（広開土王碑）", "explanation": "4世紀末、倭国が朝鮮半島に渡って百済や新羅を従属させたため高句麗の好太王が倭を打ち破ったという内容が刻まれている。明治期に日本陸軍の軍人が文字を改ざんしたとの説もあったが、近年の精緻な拓本研究の結果この説はほぼ否定されている。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6483", "field": "外交史", "difficulty": 3, "type": "choice", "question": "5世紀の倭の五王が中国の南朝に使者を送り官職・称号を求めたことを伝える中国の歴史書はどれか。", "choices": ["漢書地理志", "後漢書東夷伝", "宋書倭国伝", "隋書倭国伝"], "answer": 2, "modelAnswer": "", "explanation": "5世紀になると倭の五王（讃・珍・済・興・武）が中国に使者を遣わし朝貢したことが『宋書』倭国伝にみえる。最後の武は安東大将軍倭王に任命されたとされ、雄略天皇に比定する説が有力である。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6484", "field": "古代", "difficulty": 4, "type": "short", "question": "埼玉県稲荷山古墳出土の鉄剣銘に刻まれている、雄略天皇に比定される大王の名を、金石文にみえる表記で答えよ。", "choices": [], "answer": "ワカタケル大王（獲加多支鹵大王）", "modelAnswer": "ワカタケル大王（獲加多支鹵大王）", "explanation": "埼玉県行田市の稲荷山古墳から出土した鉄剣銘と、熊本県江田船山古墳から出土した鉄刀銘には、ともに「ワカタケル大王」と読める文字が刻まれており、雄略天皇に比定される。関東から九州にまで大和政権の勢力が及んでいたことを示す資料とされる。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6485", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "6世紀前半、筑紫国造磐井が新羅と結んで大和政権に反乱を起こしたとされる磐井の乱は、大伴金村の指揮によって鎮圧された。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "誤り。磐井の乱を鎮圧したのは物部麁鹿火である。磐井の乱や後の武蔵国造の乱を経て、ヤマト王権の勢力はさらに強大化し、日本列島各地への支配を広げていった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6486", "field": "中世", "difficulty": 2, "type": "short", "question": "1086年、天皇の位を幼少の子（堀河天皇）に譲り、自らは上皇として政治の実権を握るという新しい政治形態を創始した人物は誰か。", "choices": [], "answer": "白河天皇（白河上皇）", "modelAnswer": "白河天皇（白河上皇）", "explanation": "1086年、白河天皇が当時8歳であった善仁親王（堀河天皇）に譲位したことに始まる院政は、その後の歴史に大きな位置を占める政治形態となった。院政の目的の一つには、摂関家から皇位継承の主導権を取り戻すことがあったと考えられている。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6487", "field": "中世", "difficulty": 3, "type": "choice", "question": "院政期における国司制度について述べた文のうち、誤っているものはどれか。", "choices": ["現地に赴任した国司の最上席者は受領と呼ばれた", "在庁官人には地元の開発領主層などが登用された", "任国に赴かず在京する遙任国司が次第に増加した", "国司が在国しない国衙には留守所は置かれなかった"], "answer": 3, "modelAnswer": "", "explanation": "国司が任国に在国しない場合、国衙には留守所が置かれ、目代や在庁官人が実務を担った。院政期は摂関政治のもとで冷遇されていた国司層を院が近臣として組織し、権力基盤を固めていった時期である。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6488", "field": "文化史", "difficulty": 4, "type": "short", "question": "院政期、白河上皇の専制的な政治のようすを記録した貴族藤原宗忠の日記の名称を答えよ。", "choices": [], "answer": "中右記", "modelAnswer": "中右記", "explanation": "藤原宗忠の日記『中右記』は白河上皇の専制政治について詳しく記した史料として著名である。同時代の日記史料には他に『御堂関白記』『小右記』などもあり、それぞれ執筆者・時代が異なる点に注意が必要である。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6489", "field": "中世", "difficulty": 3, "type": "short", "question": "院政を担った上皇の身辺警護のために組織された武力組織で、平正盛らが取り立てられたことをきっかけに平氏台頭の足がかりとなった、院御所に置かれた武士集団を何というか。", "choices": [], "answer": "北面の武士", "modelAnswer": "北面の武士", "explanation": "院政のもう一つの大きな特徴は、台頭し始めた武士を積極的に登用したことで、中でも平氏は平正盛が白河上皇によって創設された北面の武士の一員に取り立てられたことから勢力を伸ばし、その子忠盛、孫の清盛は鳥羽上皇・後白河上皇の院政を強力に支えた。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6490", "field": "中世", "difficulty": 3, "type": "choice", "question": "1221年に後鳥羽上皇が幕府打倒を企てて挙兵し、幕府方の圧勝に終わった内乱に関する説明として誤っているものはどれか。", "choices": ["乱後、京都に六波羅探題が設置され朝廷の監視にあたった", "後鳥羽・土御門・順徳の三上皇が配流された", "乱の結果、幕府の支配権は西国にも広く及ぶようになった", "上皇方についた貴族・武士の所領は没収されず安堵された"], "answer": 3, "modelAnswer": "", "explanation": "承久の乱では、上皇方貴族の所領は没収され、その地に東国御家人が地頭として補任された。乱の戦後処理により幕府の支配は一気に西国に広がり、六波羅探題が設置されて朝廷の監視や西国統轄にあたった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6491", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "1232年に北条泰時のもとで制定された御成敗式目は、公家法や本所法の効力をすべて否定するものであった。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "誤り。御成敗式目は頼朝以来の先例や道理を成文化し、幕府に評定衆を置いて合議政治を進めるための武家社会向けの法であり、公家法・本所法の効力を否定するものではなく、これらと並存した。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6492", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代後期、後嵯峨上皇の二人の子（後深草上皇と亀山天皇）の子孫がそれぞれ皇位を争うようになった状態を、漢字4字で何というか。", "choices": [], "answer": "両統迭立", "modelAnswer": "両統迭立", "explanation": "後嵯峨上皇が自らの後継者を定めずに亡くなったことから、その後は皇統が持明院統と大覚寺統に分裂し、皇位継承が幕府の助言を受けつつようやくなされる両統迭立の状態となった。これにより院政の歴史的役割は実質を失っていった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6493", "field": "中世", "difficulty": 4, "type": "choice", "question": "後醍醐天皇が幕府滅亡後に始めた親政にともない設置・再興された機関として当てはまらないものはどれか。", "choices": ["記録所", "雑訴決断所", "陸奥将軍府", "鎌倉府"], "answer": 3, "modelAnswer": "", "explanation": "鎌倉府は室町幕府が関東統治のために設置した機関であり、建武の新政期の機関ではない。後醍醐天皇の親政では記録所・雑訴決断所・陸奥将軍府・武者所などが設置・再興された。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6494", "field": "近世", "difficulty": 2, "type": "short", "question": "5代将軍徳川綱吉が発した、生類の殺生を禁じ捨て子の養育なども含んだ一連の法令を総称して何というか。", "choices": [], "answer": "生類憐みの令", "modelAnswer": "生類憐みの令", "explanation": "徳川綱吉の時代に発せられた生類憐みの令は単なる動物保護政策にとどまらず、人々に大きな影響を及ぼすものであった。前将軍死去直前の遺言を巡って、この政策の継続・停止が新井白石らの間で議論となった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6495", "field": "近世", "difficulty": 3, "type": "choice", "question": "新井白石が正徳の治のもとで発した、長崎における貿易額を制限する法令はどれか。", "choices": ["異国船打払令", "海舶互市新例", "薪水給与令", "寛政異学の禁"], "answer": 1, "modelAnswer": "", "explanation": "1715年に発せられた海舶互市新例は、長崎における貿易を制限することを企図した法令である。新井白石は将軍の対外的呼称を「日本国大君」から「日本国王」に改めることも提言するなど、前代の政治を見直し幕府政治の原則を再確認しようとした。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6496", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "1873年に発布された徴兵令では、戸主やその嗣子、官吏、学生などに兵役免除の規定が設けられていた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "正しい。徴兵令には代人料270円を納める者や戸主・官吏・学生などに対する兵役免除規定が設けられていたが、前年の徴兵告諭にあった「血税」という文言が民間に誤解を与え、血税一揆が起こる一因ともなった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6497", "field": "近代", "difficulty": 3, "type": "short", "question": "1888年の市制・町村制公布に続き、1890年に公布され、府県と郡に自治体的性格を持たせつつ知事の統制を強めた二つの制度をあわせて漢字4字で答えよ。", "choices": [], "answer": "府県制郡制", "modelAnswer": "府県制郡制", "explanation": "府県制によって府県知事は官選のまま、府県会が地方税の使途などを議決する仕組みが整えられ、郡制では郡長・郡参事会が行政機関として位置づけられた。市制では府県知事が任命する市長と、市会が選任する参事会員によって行政が担われた。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6498", "field": "近代", "difficulty": 2, "type": "choice", "question": "1925年に加藤高明内閣のもとで成立した普通選挙法の内容として正しいものはどれか。", "choices": ["満20歳以上の男女に選挙権を与えた", "満25歳以上のすべての男性に選挙権を与えた", "満30歳以上の男性で直接国税3円以上を納める者に選挙権を与えた", "華族を除く満25歳以上の男性で直接国税10円以上を納める者に選挙権を与えた"], "answer": 1, "modelAnswer": "", "explanation": "1925年の普通選挙法は満25歳以上のすべての男性に選挙権を与えたが、女性には参政権を認めなかった。加藤高明首相は普通選挙法案提案理由の中で、選挙の公正を完うすることが憲政の基礎を鞏固にすると述べた。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6499", "field": "近代", "difficulty": 3, "type": "short", "question": "1924年の総選挙後、憲政会・立憲政友会・革新倶楽部の三党が協力して組織した内閣を、その与党名にちなんで何と呼ぶか。", "choices": [], "answer": "護憲三派内閣", "modelAnswer": "護憲三派内閣", "explanation": "清浦奎吾内閣が超然内閣として組織されたことに反発し、憲政会・立憲政友会・革新倶楽部の護憲三派が共同宣言を出して総選挙にのぞみ、勝利して護憲三派内閣（加藤高明内閣）を成立させた。政友本党はこれに対抗する立場をとった。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6500", "field": "社会経済", "difficulty": 4, "type": "essay", "question": "松方正義が大蔵卿として進めた財政・通貨政策が、その後の日本の金融制度にどのような影響を与えたか、日本銀行の設立と銀本位制の確立に触れながら100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "松方正義は緊縮財政によって不換紙幣の整理をはかるとともに、中央銀行として日本銀行を設立し、1880年代半ばに日銀券を中心とする銀本位制を確立した。これにより貨幣価値が安定し、その後の企業勃興・産業革命期を支える金融基盤が整えられた。", "explanation": "大隈重信大蔵卿の下でのインフレを収束させるため、後任の松方正義は緊縮財政を進め、日本銀行を設立して銀本位制を確立した。その後主要先進国が金本位制に移行する中で銀安（金高）傾向が続き、日本は1897年に金本位制を正式に採用するに至った。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6501", "field": "現代", "difficulty": 3, "type": "choice", "question": "1946年、悪性インフレーションに対処するため幣原喜重郎内閣が発した、預金を封鎖し新円切替を行った政策はどれか。", "choices": ["金融緊急措置令", "農地調整法", "国家総動員法", "経済安定九原則"], "answer": 0, "modelAnswer": "", "explanation": "復員兵や引き揚げ者の増加、軍需工場の閉鎖などにより失業者が急増し悪性インフレーションが起こったため、幣原喜重郎内閣は預金を封鎖し旧円の流通禁止と新円の引き出し制限をかける金融緊急措置令を発令した。効果は一時的で、第一次吉田茂内閣は傾斜生産方式を採用し復興金融金庫を創設して基幹産業を支援した。（商学部2018年で問われた論点）", "source": "2018", "faculty": "商学部"},
  {"id": "q6520", "field": "古代", "difficulty": 2, "type": "choice", "question": "866年、大納言伴善男が放火の疑いをかけられて配流された事件を何というか。", "choices": ["昌泰の変", "安和の変", "応天門の変", "承和の変"], "answer": 2, "modelAnswer": "", "explanation": "応天門の変では伴善男が放火させたとされ、この事件をきっかけに藤原良房の勢力が一段と強まった。応天門は平安京大内裏の南面にある門である。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6521", "field": "古代", "difficulty": 2, "type": "short", "question": "応天門の変後、臣下として初めて摂政に就任した人物は誰か。", "choices": [], "answer": "藤原良房", "modelAnswer": "藤原良房", "explanation": "清和天皇が幼くして即位した結果、藤原良房は外祖父として臣下ではじめて摂政となった。以後、藤原氏と天皇家との婚姻関係が広がり、藤原氏の摂関政治への道が開かれていく。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6522", "field": "古代", "difficulty": 4, "type": "short", "question": "宇多天皇が藤原基経を関白に任じる詔書の文言をめぐって基経が抗議し政務を停止した事件を何というか。", "choices": [], "answer": "阿衡の紛議（阿衡事件）", "modelAnswer": "阿衡の紛議（阿衡事件）", "explanation": "藤原良房の地位を継いだ藤原基経は、素行の悪かった陽成天皇を退位させ、仁明天皇の子であった光孝天皇を即位させた。宇多天皇の代には、基経を関白に任じる詔書の文言をめぐり阿衡の紛議が起こった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6523", "field": "外交史", "difficulty": 2, "type": "short", "question": "菅原道真が894年に建議し、これ以降実施されなくなった、中国への公式使節派遣を何というか。", "choices": [], "answer": "遣唐使（の停止・中止）", "modelAnswer": "遣唐使（の停止・中止）", "explanation": "宇多天皇は文人として名高い菅原道真を登用し、非藤原氏の親政を目指した。道真は遣唐使の中止（停止）を建議したことで知られ、以後遣唐使は派遣されなくなった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6524", "field": "古代", "difficulty": 2, "type": "short", "question": "醍醐天皇の時代、藤原時平の策謀により菅原道真が大宰府に左遷された事件を何というか。", "choices": [], "answer": "昌泰の変", "modelAnswer": "昌泰の変", "explanation": "醍醐天皇が即位すると、藤原時平の策謀により菅原道真は昌泰の変で大宰府に左遷され、都に戻ることなく現地で亡くなった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6525", "field": "文化史", "difficulty": 3, "type": "short", "question": "醍醐天皇の治世（延喜の治）に編纂された、律令の施行細則を集大成した法典は何か。", "choices": [], "answer": "延喜式", "modelAnswer": "延喜式", "explanation": "延喜の治のもとでは『古今和歌集』や『延喜格』の編纂など文化・法制両面での事業が進められ、律令の施行細則を集大成した延喜式もこの時代に編纂された。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6526", "field": "古代", "difficulty": 2, "type": "short", "question": "醍醐天皇の子で、みずから親政を行い数々の施策を実施したことから「天暦の治」と称される天皇は誰か。", "choices": [], "answer": "村上天皇", "modelAnswer": "村上天皇", "explanation": "醍醐天皇の次の天皇は朱雀であり、この天皇の時には大きな反乱（承平・天慶の乱）が日本の東西で起きたが、王権はなんとか鎮圧に成功した。次代の村上天皇は数々の施策を実施し親政を行ったことから天暦の治と呼ばれる。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6527", "field": "古代", "difficulty": 3, "type": "short", "question": "969年、村上天皇の死後まもなく、源高明が左遷される事件が起きた。これを何というか。", "choices": [], "answer": "安和の変", "modelAnswer": "安和の変", "explanation": "村上天皇の死後、源高明を左遷に追い込んだ安和の変が起きた。この事件を機に他氏排斥がほぼ完了し、藤原氏の覇権が確立することとなった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6528", "field": "古代", "difficulty": 2, "type": "choice", "question": "10世紀前半、関東で平将門が、瀬戸内で藤原純友がそれぞれ起こした反乱を総称して何というか。", "choices": ["保元の乱", "平治の乱", "承平・天慶の乱", "治承・寿永の乱"], "answer": 2, "modelAnswer": "", "explanation": "平将門は関東で、藤原純友は瀬戸内海を中心に海賊行為を働き反乱を起こした。両者の乱をあわせて承平・天慶の乱という。将門を討ち取ったのは平貞盛・藤原秀郷らである。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6529", "field": "中世", "difficulty": 4, "type": "short", "question": "1183年、後白河法皇が源頼朝に東海・東山道の支配権を認めたことを何というか、その宣旨の名称を答えよ。", "choices": [], "answer": "寿永二年十月宣旨", "modelAnswer": "寿永二年十月宣旨", "explanation": "鎌倉幕府が成立し政権の安定をみるまでには長い時間を要した。1183年、後白河法皇は源頼朝に東国の行政権を認め、朝廷の権限の一部が頼朝に委ねられることになった。これを寿永二年十月宣旨という。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6530", "field": "中世", "difficulty": 3, "type": "choice", "question": "1185年、源頼朝が守護・地頭を設置する権限を朝廷から認められる契機となったできごとは何か。", "choices": ["文治の勅許", "建久の新制", "寿永の宣旨", "承久の宣旨"], "answer": 0, "modelAnswer": "", "explanation": "平氏滅亡後、頼朝は文治の勅許によって守護・地頭を設置する権限を朝廷から認められた。守護は当初惣追捕使・国地頭などとも呼ばれ、鎌倉時代には京都大番役の催促を職務の一つとした。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6531", "field": "中世", "difficulty": 2, "type": "short", "question": "源頼朝が1189年、みずから軍を率いて奥州藤原氏を滅ぼした戦いを何というか。", "choices": [], "answer": "奥州合戦", "modelAnswer": "奥州合戦", "explanation": "頼朝は奥州藤原氏を討って政権の強化を図り、さらに征夷大将軍に任じられた。ただし頼朝の在世時には政権の安定化には至らず、死後も相次いで抗争が起きた。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6532", "field": "中世", "difficulty": 3, "type": "short", "question": "13世紀半ば以降、鎌倉幕府において北条氏嫡流の当主が権勢をふるうようになった体制を何というか。", "choices": [], "answer": "得宗専制（政治）", "modelAnswer": "得宗専制（政治）", "explanation": "13世紀半ば以降、北条氏の権力が拡大すると御家人たちの不満が高まり、幕府は衰退に向かった。宝治合戦で三浦泰村らが滅び、得宗が権勢を強めていったことがその背景にある。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6533", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "田沼意次は民間の経済活動を活性化させるための施策を講じる一方、株仲間の結成を抑制する政策をとった。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "誤り。田沼意次は株仲間の結成を積極的に公認・奨励し、運上・冥加など営業税を徴収することで幕府財政の増収を図った。あわせて干拓工事などによる新田開発もおこなわれた。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6534", "field": "近世", "difficulty": 3, "type": "choice", "question": "松平定信が寛政の改革で行った農村復興策として当てはまらないものはどれか。", "choices": ["囲米の実施", "旧里帰農令の発令", "人足寄場の設置", "上知令の発令"], "answer": 3, "modelAnswer": "", "explanation": "上知令は天保の改革で水野忠邦が発した政策であり、寛政の改革のものではない。松平定信は飢饉に備え諸藩へ米の備蓄を命じ（囲米）、江戸に流入した貧困層には故郷へ戻ることを奨励し（旧里帰農令）、江戸に人足寄場を設けて無宿人を収容し職業技術を授けた。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6535", "field": "文化史", "difficulty": 2, "type": "short", "question": "アメリカに渡り帰国後、1875年に京都でキリスト教主義に基づく私立学校を創立した人物は誰か。", "choices": [], "answer": "新島襄", "modelAnswer": "新島襄", "explanation": "新島襄は私立大学設立を計画し、1875年頃京都で洋学塾を創立、後にこれを発展させて同志社を築いた。この計画には大隈重信や井上馨らも協力・尽力したとされる。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6536", "field": "近代", "difficulty": 2, "type": "choice", "question": "1881年に板垣退助を党首として結成された、フランス流の急進的自由主義を掲げた政党はどれか。", "choices": ["立憲改進党", "自由党", "立憲帝政党", "国民協会"], "answer": 1, "modelAnswer": "", "explanation": "自由党は1881年、板垣退助を党首としてフランス流の急進的自由主義を理想に結成され、国会開設後は「民党」と呼ばれる側に属した。翌年結成された立憲改進党はイギリス流の政党政治を理想とした。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6537", "field": "近代", "difficulty": 3, "type": "short", "question": "明治政府が1873年から実施した地租改正にともない、地価の3％を金納させる代わりに土地所有者に交付した証書を何というか。", "choices": [], "answer": "地券", "modelAnswer": "地券", "explanation": "地租改正では地価を定めて地券を交付し、土地所有権を確認するとともに地価の3％を地租として金納させる制度に改めた。これは年貢負担者であった自作農・小作農に地券を交付し土地所有権を認めるものであった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6538", "field": "近代", "difficulty": 2, "type": "choice", "question": "1923年の関東大震災に際して、経済混乱を緩和するために発せられた、手形の決済を一定期間猶予する措置を何というか。", "choices": ["徳政令", "モラトリアム", "金解禁", "為替管理"], "answer": 1, "modelAnswer": "", "explanation": "関東大震災では建物や商品などの被害総額がGNPの3分の1を超え、震災に伴う経済的混乱の中で被災地企業も窮地に陥った。この危機を救うためモラトリアム（支払猶予令）が発令されたが、これが後の金融恐慌を引き起こす要因の一つともなった。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6539", "field": "社会経済", "difficulty": 3, "type": "short", "question": "1927年、議会で片岡直温大蔵大臣が特定銀行の経営破綻について失言したことが引き金となって銀行への取り付け騒ぎが広がった事件を何というか。", "choices": [], "answer": "昭和金融恐慌（金融恐慌）", "modelAnswer": "昭和金融恐慌（金融恐慌）", "explanation": "関東大震災の震災手形処理をめぐる過程で経営が悪化していた銀行が、片岡直温大蔵大臣の失言をきっかけとする取り付け騒ぎで休業に追い込まれた。若槻内閣は台湾銀行を救済しようとしたが枢密院の同意が得られず失敗し、内閣は総辞職した。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6540", "field": "現代", "difficulty": 3, "type": "choice", "question": "GHQの指令により財閥解体が進められる中、1946年に発足し、財閥の株式譲渡を管理した機関はどれか。", "choices": ["持株会社整理委員会", "経済安定本部", "公正取引委員会", "復興金融金庫"], "answer": 0, "modelAnswer": "", "explanation": "GHQは財閥を非民主的で軍国主義の温床になっていた組織と認識し、財閥本社の解体とともに財閥本社や財閥家族が保有する株式を持株会社整理委員会に強制的に譲渡させた。1947年には独占禁止法や過度経済力集中排除法も公布された。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6541", "field": "現代", "difficulty": 4, "type": "essay", "question": "GHQの勧告に基づいて行われた第二次農地改革が、日本の農村構造にもたらした変化について、不在地主・在村地主の扱いの違いに触れながら100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "第二次農地改革では、不在地主の全貸付地と在村地主の貸付地のうち保有限度を超える部分を国が強制的に買い上げ、小作人に安く売り渡した。これにより寄生地主制が解体され多数の自作農が創出され、1949年には小作地率が大幅に低下して戦後農業の基盤となった。", "explanation": "第一次農地改革案が地主制解体に不徹底であったためGHQがこれを拒否し、改正農地調整法と自作農創設特別措置法が1946年に公布された（第二次農地改革）。不在地主の全貸付地、在村地主の貸付地で保有限度を超える部分が買収対象とされた点が重要な論点である。（商学部2019年で問われた論点）", "source": "2019", "faculty": "商学部"},
  {"id": "q6560", "field": "古代", "difficulty": 2, "type": "short", "question": "古代、中央と地方の国府を結ぶ官道で、約16kmごとに駅が置かれ駅馬が配備されていたものを何というか。", "choices": [], "answer": "駅路", "modelAnswer": "駅路", "explanation": "古代には駅路や伝路とよばれる官道が整備された。駅路は中央と地方の国府を結ぶ道で、30里（約16km）ごとに駅がおかれ駅には駅馬がおかれた。伝路は地方豪族の拠点となる場所をつないでいた道から発展し、郡家には伝馬がおかれた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6561", "field": "外交史", "difficulty": 4, "type": "choice", "question": "七道のうち、蝦夷征討の拠点とされたことから中路とされた道の組み合わせとして正しいものはどれか。", "choices": ["東山道と東海道", "東海道と山陽道", "北陸道と山陰道", "西海道と南海道"], "answer": 0, "modelAnswer": "", "explanation": "七道の多くは小路とされたが、東山道と東海道は中路とされた。これは蝦夷征討事業のためと考えられており、東国は蝦夷征討のための拠点とされたことから東山道と東海道は重視された。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6562", "field": "古代", "difficulty": 2, "type": "short", "question": "8世紀初め、蝦夷経営の拠点として現在の宮城県に築かれ、後に鎮守府や陸奥国府が置かれた城柵の名を答えよ。", "choices": [], "answer": "多賀城", "modelAnswer": "多賀城", "explanation": "蝦夷征討事業に関連して設置された城柵には秋田城・磐舟柵・胆沢城・出羽柵などがあるが、その中でも多賀城は陸奥国府・鎮守府が置かれた東北支配の中心的拠点であった。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6563", "field": "古代", "difficulty": 3, "type": "short", "question": "称徳天皇に寵愛された僧道鏡の皇位継承への野心を阻止し、その結果自身は大隅に配流された貴族は誰か。", "choices": [], "answer": "和気清麻呂", "modelAnswer": "和気清麻呂", "explanation": "道鏡は称徳天皇に重用され皇位をうかがう動きをみせたが、和気清麻呂が宇佐八幡神託を確認しこれを阻止した。清麻呂はその結果、大隅国へ流された。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6564", "field": "中世", "difficulty": 3, "type": "short", "question": "1454年、鎌倉公方足利成氏が関東管領上杉憲忠を謀殺したことをきっかけに始まり、関東を二分する大乱となったできごとを何というか。", "choices": [], "answer": "享徳の乱", "modelAnswer": "享徳の乱", "explanation": "鎌倉公方の地位についていた上杉憲忠の謀殺がきっかけで起きた大乱は、現在では享徳の乱といわれる。この大乱後、鎌倉公方に対抗して古河公方が立てられ、堀越公方はのちに伊勢宗瑞（北条早雲）に滅ぼされた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6565", "field": "中世", "difficulty": 4, "type": "choice", "question": "応仁の乱の要因や経過について述べた文として、正しいものはどれか。", "choices": ["日野富子は実子義尚を将軍にしようとした", "足利義視は当初から一貫して西軍に属した", "加賀一向一揆が細川勝元を滅ぼした", "応仁の乱は一色氏の家督争いに始まった"], "answer": 0, "modelAnswer": "", "explanation": "日野富子が養子の足利義視ではなく実子義尚を将軍にしようとしたことが、応仁の乱の要因の一つとなった。足利義視は当初東軍にあったが翌年西軍に移り、加賀一向一揆は細川勝元の命令ではなく富樫政親を滅ぼした事件であり、乱のきっかけは畠山・斯波氏の家督争いであった。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6566", "field": "文化史", "difficulty": 3, "type": "choice", "question": "室町~安土桃山時代にかけての西日本における地方文化について、正しいものはどれか。", "choices": ["大内氏のもとで出版が盛んになり大内版といわれた", "薩摩では陽明学が講じられ薩南学派といわれた", "南村梅軒が桂庵玄樹に朱子学を学んだ", "宣教師が木製活字による活字印刷術をもたらした"], "answer": 0, "modelAnswer": "", "explanation": "大内氏のもとでは出版が盛んで大内版といわれた。薩南学派は桂庵玄樹が肥後などで講じた朱子学の系統であり陽明学ではなく、南村梅軒は薩南学派とは別に海南学派を興したとされる。また宣教師がもたらしたのは金属製活字による活字印刷術である。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6567", "field": "文化史", "difficulty": 3, "type": "short", "question": "東常縁から古今伝授を受けその正統な伝承者（古今伝授の祖）とされた連歌師で、肖柏・宗長とともに『水無瀬三吟百韻』を詠んだ人物は誰か。", "choices": [], "answer": "宗祇", "modelAnswer": "宗祇", "explanation": "宗祇は連歌の規則書『応安新式』を制定した二条良基以降の連歌の発展を担い、東常縁に古今伝授をほどこされてその祖とされた。心敬より1年早く関東に下向し、心敬との交流もあったとされる。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6568", "field": "近世", "difficulty": 4, "type": "short", "question": "江戸時代後期、将軍の統治権はもともと天皇から預けられたものであるとする考え方が有力となり、これが幕末の大政奉還の論理的根拠ともなった。この考え方を何というか。", "choices": [], "answer": "大政委任論", "modelAnswer": "大政委任論", "explanation": "江戸幕府がなぜ日本の土地と人民を支配する権限を持っているのかという問いに対し、幕府支配の正当性を保証するのは天であるとの考えが当初あったが、それがやがて将軍は天皇から政務を預かっているとの大政委任論が有力になっていった。これを支える論理であり、徳川慶喜による大政奉還を支えた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6569", "field": "近世", "difficulty": 2, "type": "choice", "question": "1615年に江戸幕府が制定した、天皇や公家の行動を規定した法度はどれか。", "choices": ["武家諸法度", "禁中並公家諸法度", "公家諸法度", "寺院諸法度"], "answer": 1, "modelAnswer": "", "explanation": "禁中並公家諸法度は幕府が制定した、天皇や公家の行動を規定する法令である。これに関連して起きた紫衣事件では、幕府の法令が天皇の意向に優先することが示された。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6570", "field": "文化史", "difficulty": 4, "type": "short", "question": "徳川綱豊（のちの6代将軍家宣）が儒者新井白石に命じて編纂させた、諸大名の系譜を記した書物を何というか。", "choices": [], "answer": "藩翰譜", "modelAnswer": "藩翰譜", "explanation": "藩翰譜は諸大名の系譜を記した書物で、18世紀初期に将軍に仕えた新井白石が編纂した。慶長五年より書き始めたとされ、諸大名の由緒や系譜を体系的にまとめている。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6571", "field": "近世", "difficulty": 2, "type": "short", "question": "1867年、15代将軍徳川慶喜が政権を朝廷に返上したできごとを何というか。", "choices": [], "answer": "大政奉還", "modelAnswer": "大政奉還", "explanation": "徳川慶喜による大政奉還は、幕府政治の矛盾が広がる中で強調されていった大政委任論を支える論理の延長線上に実行されたものであった。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6572", "field": "近代", "difficulty": 3, "type": "short", "question": "1875年、大久保利通が中心となって設置され、府県会開設の下地を作った、地方官を集めて開いた会議を何というか。", "choices": [], "answer": "地方官会議", "modelAnswer": "地方官会議", "explanation": "1875年に地方官会議が設けられ、翌年には府県会が開かれた。この会議は漸次基盤を創設し、順を追って着実に進める道によるものとされた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6573", "field": "近代", "difficulty": 3, "type": "choice", "question": "1881年、開拓使官有物払下げをめぐる世論の批判をきっかけに、国会開設の勅諭が出されるとともに、ある政治家が政府から追放される事件が起きた。この事件を何というか。", "choices": ["明治六年の政変", "明治十四年の政変", "秩禄処分", "西南戦争"], "answer": 1, "modelAnswer": "", "explanation": "開拓使官有物の払下げが世論の批判にさらされ、大隈重信ら慶応義塾出身の官僚が政府から追放されるとともに国会開設の勅諭が出された。この一連のできごとを明治十四年の政変という。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6574", "field": "近代", "difficulty": 2, "type": "short", "question": "明治十四年の政変に際して、10年後の1890年に国会を開設することを約束した詔を何というか。", "choices": [], "answer": "国会開設の勅諭", "modelAnswer": "国会開設の勅諭", "explanation": "明治十四年の政変後、政府は明治二十三年（1890年）を期し議員を召し国会を開き、初志を達成しようとする国会開設の勅諭を出した。これにより自由民権運動は政党結成へと向かっていく。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6575", "field": "近代", "difficulty": 3, "type": "short", "question": "1889年、大日本帝国憲法発布の翌日に行われた黒田清隆首相の演説で示された、政府は政党の意向に左右されずに政策を進めるべきだとする立場を何というか。", "choices": [], "answer": "超然主義", "modelAnswer": "超然主義", "explanation": "施政上の意見は人々それぞれ異なり、その合同する者が相投じて団結するいわゆる政党なるものが社会に存立するのも情勢の免れざる所であるが、政府は常に一定の方向をとり超然として政党の外に立つべきだとする超然主義が、黒田清隆首相の演説で示された。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6576", "field": "外交史", "difficulty": 2, "type": "choice", "question": "1858年に締結された日米修好通商条約の内容として正しいものはどれか。", "choices": ["日本に滞在するアメリカ人への領事裁判権を認めた", "日本が関税率を自主的に決定できる権利を認めた", "相互に最も良い待遇を与えあう最恵国待遇を双務的に定めた", "外国人の国内旅行を自由に認めた"], "answer": 0, "modelAnswer": "", "explanation": "日米和親条約に続き、幕府が欧米列強と結んだ日米修好通商条約は、日本に滞在するアメリカ人への領事裁判権を認めさせるものであり、関税については日本側が自主的に税率を決定できない不平等な内容であった。欧米列強は日本を対等な国家とは認めず、半植民地化しうる対象とみなしていた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6577", "field": "社会経済", "difficulty": 2, "type": "short", "question": "明治政府が工業化を促進するため、工部省・内務省・農商務省などを通じて進めた一連の政策を総称して何というか。", "choices": [], "answer": "殖産興業（政策）", "modelAnswer": "殖産興業（政策）", "explanation": "明治政府の殖産興業政策は工業化の課題に対応したものであり、様々な工業化促進政策が実施された。1880年代後半に市場を混乱させていた通貨制度が安定すると、紡績業などを中心に近代的な機械制工場が発達し始め、日本は産業革命期を迎えた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6578", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "1930年代初頭の日本経済において、重工業や化学工業部門はすでに十分発達しており、投資財を国内で自給することに問題はなかった。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "誤り。1900年代に本格的な工業化が進むと鉄鋼などの資材や機械への需要が強まったが、これらの投資財を供給する国内重工業部門の発達には限界があり、投資財需要の増加は輸入拡大による貿易収支の悪化につながった。重工業・化学工業部門の未成熟という産業構造上の弱点は1930年代初頭にも残存していた。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6579", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "1930年、浜口雄幸内閣が井上準之助蔵相のもとで実施した金解禁政策の内容として正しい組み合わせはどれか。", "choices": ["旧平価で解禁し、財政緊縮により物価引き下げを図った", "新平価で解禁し、財政拡大により物価引き上げを図った", "旧平価で解禁し、金融緩和により物価引き上げを図った", "新平価で解禁し、財政緊縮により物価引き下げを図った"], "answer": 0, "modelAnswer": "", "explanation": "浜口雄幸内閣は井上準之助を蔵相に起用し、1930年初頭に金解禁を断行した。この解禁準備の過程で円の為替相場を旧平価水準の円高に誘導するため、財政緊縮により物価の引き下げを実現して経常収支の改善をはかる政策が採用された。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6580", "field": "社会経済", "difficulty": 4, "type": "essay", "question": "高橋是清が犬養毅内閣・斎藤実内閣などで蔵相をつとめた際にとった財政政策の特徴を、金輸出再禁止・積極財政・国債発行の観点から100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "高橋是清は金輸出を再禁止して管理通貨制度に移行し、赤字国債の発行を財源に軍事費や公共土木事業費を中心とした積極財政を展開して日本をいち早く恐慌から脱出させた。しかし国債累積の主因である軍事費の膨張が財政や物価に及ぼす影響を懸念し、次第に公債発行の抑制にも努めた。", "explanation": "浜口内閣を引き継いだ若槻礼次郎内閣が閣内不統一で総辞職すると犬養毅政友会内閣が発足し、高橋是清が蔵相に就任した。日本経済をいち早く恐慌から脱出させる一方、公債を財源とする政府支出の増大や低金利政策がインフレを招くことを恐れ、軍事費の抑制につとめるようになった。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6581", "field": "現代", "difficulty": 3, "type": "short", "question": "1946年に「超国家主義の論理と心理」という論文を発表し、天皇制における政治権力と精神的権威の一元的集中という問題点を指摘した政治学者は誰か。", "choices": [], "answer": "丸山眞男", "modelAnswer": "丸山眞男", "explanation": "占領下の民主化政策のもとで思想や言論に対する国家の抑圧が除去され、丸山眞男の政治学、大塚久雄の経済史学、川島武宜の法社会学などが論壇にあらわれ、知識人・学生に大きな影響を及ぼした。丸山は1946年5月に「超国家主義の論理と心理」という論文を発表し、天皇制の問題点を、政治権力と精神的権威を一元的に集中していた点に見いだした。（商学部2020年で問われた論点）", "source": "2020", "faculty": "商学部"},
  {"id": "q6600", "field": "古代", "difficulty": 2, "type": "short", "question": "527年、新羅と結んで筑紫で反乱を起こした国造磐井を、翌年鎮圧した大和政権側の将軍は誰か。", "choices": [], "answer": "物部麁鹿火", "modelAnswer": "物部麁鹿火", "explanation": "継体天皇21年(527年)、筑紫国造磐井は新羅と通じて反乱を起こしたが、翌年、大将軍物部麁鹿火が磐井を斬り、乱を鎮圧した。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6601", "field": "古代", "difficulty": 2, "type": "choice", "question": "筑紫国造磐井の墓と伝えられ、多数の石人・石馬が出土した古墳として正しいものはどれか。", "choices": ["龍角寺岩屋古墳", "岩戸山古墳", "竹原古墳", "箸墓古墳", "作山古墳"], "answer": 1, "modelAnswer": "", "explanation": "岩戸山古墳(福岡県八女市)は筑紫国造磐井の墓と伝えられる前方後円墳で、多数の石人・石馬が出土したことで知られる。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6602", "field": "古代", "difficulty": 2, "type": "short", "question": "糟屋屯倉のように、大和政権が地方に設置した直轄地を何と呼ぶか、漢字2字で答えよ。", "choices": [], "answer": "屯倉", "modelAnswer": "屯倉", "explanation": "屯倉は大和政権の直轄地で、磐井の子筑紫君葛子が父の罪を許してもらうため糟屋屯倉を献上したことが知られる。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6603", "field": "古代", "difficulty": 3, "type": "choice", "question": "672年の壬申の乱に関して述べた文として正しいものはどれか。", "choices": ["大友皇子は美濃・尾張の兵を集め、不破道を塞いで大海人皇子軍に対抗した", "大海人皇子軍は瀬田橋の戦いで敗れ、吉野に逃れた", "大海人皇子は吉野から美濃国に入り、東国の兵を動員して近江朝廷軍と戦った", "乱の結果、大友皇子が即位して天武天皇となった", "乱の背景には蘇我氏と物部氏の対立があった"], "answer": 2, "modelAnswer": "", "explanation": "大海人皇子は吉野を脱出して美濃国に入り、安八磨郡などの兵を動員して近江朝廷軍と戦い勝利した。最終決戦の瀬田橋の戦いでは近江朝廷側の大友皇子軍が敗れ、大友皇子は自害した。乱後、大海人皇子が即位して天武天皇となった。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6604", "field": "古代", "difficulty": 3, "type": "choice", "question": "764年に起きた藤原仲麻呂(恵美押勝)の乱に関して述べた文として誤っているものはどれか。", "choices": ["仲麻呂は孝謙太上天皇と対立して挙兵した", "仲麻呂は道鏡の重用に反発した", "仲麻呂は乱の際に淳仁天皇を擁立しようとした", "仲麻呂は近江に逃れる途中で討たれた", "乱の後、孝謙太上天皇は重祚して桓武天皇となった"], "answer": 4, "modelAnswer": "", "explanation": "乱後に孝謙太上天皇が重祚したのは称徳天皇であり、桓武天皇ではない。桓武天皇は後の光仁天皇の子であり別人である。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6605", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "橘奈良麻呂の変は、藤原仲麻呂の台頭に反発した橘奈良麻呂が仲麻呂打倒を計画し、発覚して弾圧された事件である。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "757年、橘諸兄の子橘奈良麻呂は光明皇太后を後ろ盾に権勢をふるう藤原仲麻呂の排除を企てたが、計画は事前に発覚し厳しく弾圧された。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6606", "field": "古代", "difficulty": 2, "type": "choice", "question": "743年に発布され、開墾地の永年私有を認めた法令として正しいものはどれか。", "choices": ["三世一身法", "墾田永年私財法", "班田収授法", "荘園整理令", "加墾禁止令"], "answer": 1, "modelAnswer": "", "explanation": "墾田永年私財法は聖武天皇の治世下、743年に発布され、一定の制限のもとで開墾地の永久私有を認めた法令で、初期荘園形成の契機となった。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6607", "field": "古代", "difficulty": 2, "type": "choice", "question": "編年体で書かれた日本最初の勅撰史書であり、神代から持統天皇までを記す歴史書はどれか。", "choices": ["古事記", "日本書紀", "続日本紀", "日本後紀", "続日本後紀"], "answer": 1, "modelAnswer": "", "explanation": "『日本書紀』は720年に舎人親王らによって完成した日本最初の勅撰正史(六国史の第一)で、編年体で神代から持統天皇までを記す。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6608", "field": "中世", "difficulty": 3, "type": "choice", "question": "建武の新政について述べた文として誤っているものはどれか。", "choices": ["後醍醐天皇は摂政・関白を置かず、天皇親政を目指した", "中央には記録所や雑訴決断所が置かれた", "諸国司と守護をともに設置し、両者を併存させた", "大内裏の造営計画は財政難から実現が困難だった", "幕府を新たに開いて武家政治を継続した"], "answer": 4, "modelAnswer": "", "explanation": "建武の新政は幕府を否定し天皇親政を志向したものであり、幕府を新たに開いて武家政治を継続したという記述は誤り。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6609", "field": "中世", "difficulty": 3, "type": "choice", "question": "観応の擾乱に関して述べた文として正しいものはどれか。", "choices": ["足利尊氏の弟直義と、尊氏の執事高師直との対立を契機として抗争が起きた", "対立の中で足利直義は北朝に投降した", "足利尊氏は終始南朝と敵対し和睦しなかった", "抗争は直義の死によって完全に終息し、以後南北朝の争いは収まった", "観応の擾乱は鎌倉幕府滅亡の直接の原因となった"], "answer": 0, "modelAnswer": "", "explanation": "観応の擾乱は足利直義と高師直の対立に端を発し、尊氏・直義兄弟も対立して抗争は南朝を巻き込みながら展開した。直義の死後も抗争の余波は続き、南北朝内乱は長期化した。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6610", "field": "中世", "difficulty": 2, "type": "short", "question": "鎌倉幕府後期、北条氏の家督(得宗)の家臣である御内人の筆頭として権勢をふるった役職を何というか。", "choices": [], "answer": "内管領", "modelAnswer": "内管領", "explanation": "内管領は得宗の家臣である御内人の筆頭で、北条高時のもとでは長崎高資が内管領として権勢をふるった。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6611", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "1333年、新田義貞は鎌倉に攻め込み、追い詰められた北条高時・北条時行父子はともに自害した。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "鎌倉攻めで北条高時は一族とともに東勝寺で自害したが、子の北条時行は難を逃れて生き延び、1335年に中先代の乱を起こした。父子がともに自害したとする記述は誤り。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6612", "field": "中世", "difficulty": 3, "type": "choice", "question": "鎌倉時代後期に活発化した「悪党」について述べた文として誤っているものはどれか。", "choices": ["荘園領主や幕府の支配に反抗する武士や地侍などを指すことが多い", "御家人や荘園領主の中には悪党をかくまい召し抱える者もいた", "幕府は悪党を必ず厳しく処罰し、御家人が悪党を保護することは一切なかった", "楠木正成は悪党的な出自を持つ武士であったといわれる", "幕府は御家人に悪党の鎮圧を命じることがあった"], "answer": 2, "modelAnswer": "", "explanation": "実際には守護や荘園領主・御家人の中に悪党をかくまったり召し抱えたりする者もおり、幕府の統制は必ずしも徹底されなかった。したがって「一切なかった」とする記述は誤り。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6613", "field": "近世", "difficulty": 2, "type": "choice", "question": "江戸時代の出版文化について述べた文として誤っているものはどれか。", "choices": ["当初、書物を刊行する本屋は京都に限られていた", "17世紀中期以降、江戸・大坂でも本屋による出版が始まった", "18世紀末には三都以外の地方都市にも本屋が登場した", "軍記物語など古代・中世に成立した文学作品も刊行された", "出版は儒学書に限定され、娯楽的な読み物が刊行されることはなかった"], "answer": 4, "modelAnswer": "", "explanation": "江戸時代には浮世草子や読本など娯楽的な読み物も数多く刊行されており、出版が儒学書に限定されたとする記述は誤り。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6614", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸幕府の遠国奉行が置かれた都市として、置かれなかったものはどれか。", "choices": ["長崎", "山田", "日光", "新潟", "下田"], "answer": 3, "modelAnswer": "", "explanation": "遠国奉行は長崎・山田(伊勢)・日光・下田・佐渡・浦賀などの幕府直轄地に置かれたが、新潟には置かれなかった。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6615", "field": "近世", "difficulty": 4, "type": "essay", "question": "18世紀の百姓一揆物語(たとえば1739年の鳥取藩の一揆を描いた作品)に共通してみられる、領主と領民の関係を説明する政治思想を、漢字2字のキーワードを用いて30字以内で説明せよ。句読点も1字として数えよ。", "choices": [], "answer": "", "modelAnswer": "仁政を施す領主と年貢を納める領民の信頼関係。", "explanation": "百姓一揆物語は、仁政を施す領主とそれに応える年貢を納める領民という信頼関係が、間に立つ村役人や藩役人によって損なわれたために一揆が起きた、と説くのが典型的な筋書きである。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6616", "field": "近世", "difficulty": 2, "type": "choice", "question": "徳川吉宗が行った享保の改革の政策として誤っているものはどれか。", "choices": ["足高の制", "上げ米", "目安箱の設置", "生類憐みの令の発令", "公事方御定書の編纂"], "answer": 3, "modelAnswer": "", "explanation": "生類憐みの令は5代将軍徳川綱吉が発した法令であり、8代将軍徳川吉宗による享保の改革の政策ではない。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6617", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "江戸幕府は寛永期以降、石高に応じた軍役の基準(軍役令)を定め、大名はそれに応じた兵馬・装備を常備する義務を負った。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "江戸幕府は寛永期の軍役令などにより石高に応じた兵馬・装備の基準を定め、大名はそれに従って常時臨戦態勢を維持する義務を負っていた。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6618", "field": "近世", "difficulty": 2, "type": "short", "question": "1867年、東海・畿内地方を中心に、伊勢神宮の御札が降ってきたという噂とともに民衆が乱舞した現象を何と呼ぶか。", "choices": [], "answer": "ええじゃないか", "modelAnswer": "ええじゃないか", "explanation": "「ええじゃないか」は幕末期、伊勢神宮などの御札が降下したという風説をきっかけに民衆が熱狂的に乱舞した現象で、幕府と長州藩の対立が深まる政情不安のなかで発生した。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6619", "field": "近代", "difficulty": 3, "type": "choice", "question": "大隈重信が外相在任中に進めた条約改正交渉について述べた文として正しいものはどれか。", "choices": ["外国人判事の任用を認める改正案が発覚し世論の反発を受け、爆弾を投げつけられて交渉は中断した", "イギリスの同意を得たが、外国人判事の任用問題で交渉が挫折した", "陸奥宗光とともに交渉にあたり、領事裁判権の完全撤廃に成功した", "岩倉使節団の副使として交渉にあたった", "日英通商航海条約の調印に成功した"], "answer": 0, "modelAnswer": "", "explanation": "大隈重信は外相として国別交渉を進めたが、大審院への外国人判事任用を認める改正案が明るみに出て世論の激しい反発を招き、1889年に爆弾を投げつけられて負傷し、交渉は中断した。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6620", "field": "近代", "difficulty": 3, "type": "choice", "question": "日清戦争後の列強による中国分割に関して述べた文として誤っているものはどれか。", "choices": ["ドイツは山東半島の膠州湾を租借した", "ロシアは遼東半島の旅順・大連を租借した", "イギリスは九竜半島とその付属島嶼(新界)を租借した", "フランスは広州湾を租借した", "ドイツは山東半島の威海衛を租借した"], "answer": 4, "modelAnswer": "", "explanation": "威海衛を租借したのはイギリスであり、ドイツが租借したのは膠州湾である。したがって「ドイツが威海衛を租借した」とする記述は誤り。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6621", "field": "近代", "difficulty": 3, "type": "choice", "question": "大正期の労働運動・社会運動について述べた文として誤っているものはどれか。", "choices": ["友愛会は後に日本労働総同盟と改称し、労資協調から階級闘争重視の方向に転じた", "全国組織として日本農民組合が結成され、小作争議の増加を背景に活動した", "吉野作造は黎明会を組織し、民本主義を軸に啓蒙活動を行った", "北一輝らにより猶存社が設立され、国家改造運動へとつながった", "治安維持法は米騒動への対応として1918年に制定された"], "answer": 4, "modelAnswer": "", "explanation": "治安維持法は1925年に普通選挙法とともに制定されたものであり、1918年の米騒動への対応として制定されたわけではない。（商学部2024年で問われた論点）", "source": "2024", "faculty": "商学部"},
  {"id": "q6640", "field": "古代", "difficulty": 2, "type": "short", "question": "埼玉県の稲荷山古墳出土鉄剣の銘文に見え、熊本県の江田船山古墳出土鉄刀の銘文にも共通してみえる大王の名は誰か。", "choices": [], "answer": "ワカタケル大王(獲加多支鹵大王)", "modelAnswer": "ワカタケル大王(獲加多支鹵大王)", "explanation": "稲荷山古墳・江田船山古墳から出土した鉄剣・鉄刀の銘文にはともに「獲加多支鹵大王」とあり、『日本書紀』にみえる雄略天皇と同一人物とされるワカタケル大王を指す。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6641", "field": "古代", "difficulty": 3, "type": "choice", "question": "熊本県の江田船山古墳出土鉄刀の銘文に「典曹人」として仕えたと記される人物の名はどれか。", "choices": ["乎獲居臣", "无利弖", "膳臣", "阿倍臣", "大伴金村"], "answer": 1, "modelAnswer": "", "explanation": "江田船山古墳出土鉄刀の銘文には、獲加多支鹵大王の世に典曹人として仕えた无利弖の名が刻まれている。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6642", "field": "古代", "difficulty": 4, "type": "choice", "question": "「東大寺献物帳」にみえる黒作懸佩刀の伝来について述べた文として正しいものはどれか。", "choices": ["首皇子から不比等、文武天皇へと伝えられた", "文武天皇の死に際し藤原不比等に渡り、不比等の死後、当時の皇太子首皇子に献上された", "この刀は聖武天皇が即位後、初めて藤原氏から下賜されたものである", "元明天皇から元正天皇、聖武天皇へと直接伝えられた", "光明皇后が生涯所持し続けた"], "answer": 1, "modelAnswer": "", "explanation": "黒作懸佩刀は日並皇子(草壁皇子)から文武天皇へ伝わり、文武天皇の死に際し太政大臣藤原不比等に渡され、不比等が没した720年に当時「後太上天皇」であった首皇子(のちの聖武天皇)に献上された。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6643", "field": "古代", "difficulty": 3, "type": "choice", "question": "仁明天皇の代である承和年間の出来事を含み、藤原緒嗣の卒伝(死亡記事)などが記された歴史書はどれか。", "choices": ["日本書紀", "続日本紀", "続日本後紀", "日本三代実録", "古事記"], "answer": 2, "modelAnswer": "", "explanation": "『続日本後紀』は仁明天皇の代の出来事を記した六国史の一つで、藤原緒嗣の卒伝もこの中に収められている。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6644", "field": "古代", "difficulty": 3, "type": "choice", "question": "高句麗の好太王(広開土王)碑文のうち、倭国の朝鮮半島進出を倭国側の立場から示す内容として正しいものはどれか。", "choices": ["百残・新羅は旧是れ属民なり。由来朝貢す。而るに倭、辛卯の年よりこのかた、海を渡りて百残を破り、以て臣民と為す", "昔より祖禰躬ら甲冑を擐き、山川を跋渉して寧処に遑あらず", "今諸国の兵士、辺要の地を除くの外、皆停廃に従へ", "倭の国王帥升等、生口百六十人を献じ、請見を願ふ", "倭の女王、大夫難升米等を遣はし、郡に詣り、天子に詣りて朝献せんことを求む"], "answer": 0, "modelAnswer": "", "explanation": "好太王碑文には391年以降、倭が海を渡って百済(百残)・新羅を破り臣民としたとする記事があり、これは倭国の朝鮮半島進出を倭国側の立場から示す代表的史料である。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6645", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "藤原広嗣の乱は、吉備真備・玄昉らの排除を求めた藤原広嗣が九州で挙兵し、鎮圧された事件である。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "740年、大宰少弐であった藤原広嗣は聖武朝で重用されていた吉備真備・玄昉の排除を求めて九州で挙兵したが、朝廷軍に鎮圧された。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6646", "field": "古代", "difficulty": 2, "type": "short", "question": "729年、皇族以外の身分から初めて聖武天皇の皇后となった人物は誰か。", "choices": [], "answer": "光明子(光明皇后)", "modelAnswer": "光明子(光明皇后)", "explanation": "藤原不比等の娘である光明子は、729年の長屋王の変ののち、皇族以外から初めて立后し光明皇后となった。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6647", "field": "古代", "difficulty": 3, "type": "choice", "question": "810年に起きた平城太上天皇の変(薬子の変)について述べた文として誤っているものはどれか。", "choices": ["平城太上天皇は平城京への再遷都を図った", "藤原薬子・藤原仲成の兄妹が太上天皇を後押しした", "嵯峨天皇側は迅速に対応し、太上天皇側の企ては失敗した", "事件を機に嵯峨天皇は蔵人所を設置した", "藤原仲成はこの事件の後、政界で勢力を拡大した"], "answer": 4, "modelAnswer": "", "explanation": "藤原仲成はこの政変の際に射殺されており、事件後に勢力を拡大した事実はない。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6648", "field": "中世", "difficulty": 3, "type": "choice", "question": "1441年に起きた嘉吉の変について述べた文として正しいものはどれか。", "choices": ["将軍足利義教が赤松満祐の邸宅で謀殺された", "この事件をきっかけに応仁の乱が始まった", "事件の首謀者赤松満祐はただちに幕府軍に討たれ抵抗しなかった", "事件後、諸大名は一致して幕府権威の回復に努めた", "将軍足利義政が殺害された事件である"], "answer": 0, "modelAnswer": "", "explanation": "嘉吉の変は1441年、将軍足利義教が赤松満祐の邸宅に招かれた際に謀殺された事件で、赤松満祐は領国播磨に逃れたのち幕府軍に討たれた。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6649", "field": "中世", "difficulty": 3, "type": "choice", "question": "室町時代の徳政一揆について述べた文として誤っているものはどれか。", "choices": ["徳政を求める土一揆はしばしば酒屋・土倉などを襲撃した", "正長の徳政一揆の様子を伝える史料として柳生の徳政碑文が知られる", "徳政一揆は将軍の代替わりを契機として起こることがあった", "幕府は一貫して徳政令の発布を拒否し続けた", "徳政一揆は近江など京都近郊から起こり、やがて京都に波及することがあった"], "answer": 3, "modelAnswer": "", "explanation": "幕府は分一徳政令など徳政令をたびたび発布しており、一貫して拒否し続けたわけではない。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6650", "field": "中世", "difficulty": 3, "type": "choice", "question": "応仁の乱の背景・経過について述べた文として誤っているものはどれか。", "choices": ["将軍足利義政の後継をめぐり、弟の足利義視と子の足利義尚が対立した", "日野富子は足利義尚を将軍後継者として推した", "有力守護家である畠山氏・斯波氏でも家督争いが起きていた", "応仁の乱では東軍と西軍が早期に和睦し、争いは短期間で終結した", "山名持豊(宗全)と細川勝元がそれぞれの陣営を率いた"], "answer": 3, "modelAnswer": "", "explanation": "応仁の乱は1467年から約11年にわたり継続し、東軍・西軍が早期に和睦した事実はない。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6651", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "山城国一揆では、国人らが両畠山氏の軍勢を山城国外に退去させ、自ら国中の掟法を定めた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "1485年の山城国一揆では、国人・土民らが集会し畠山政長・畠山義就両軍を国外に退去させ、その後自治的な国掟を定めて統治を行った。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6652", "field": "中世", "difficulty": 2, "type": "short", "question": "室町幕府の侍所長官(所司)を交代でつとめた赤松・一色・山名・京極の4氏をまとめて何と呼ぶか。", "choices": [], "answer": "四職", "modelAnswer": "四職", "explanation": "侍所の長官は赤松・一色・山名・京極の4氏(四職)から選ばれるのが慣例であった。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6653", "field": "近世", "difficulty": 3, "type": "choice", "question": "1869年、松浦武四郎の提案をもとに明治政府が決定した地名について述べた文として正しいものはどれか。", "choices": ["松浦武四郎は幕府役人としてのみ蝦夷地を訪れ、個人の立場での探査は行わなかった", "松浦武四郎は複数の名称候補を提案し、その中から「北海道」が採用された", "「北海道」の名称は江戸時代からすでに公式に用いられていた", "松浦武四郎はアイヌの人々に対する和人の待遇を一貫して称賛した", "松浦武四郎は主にロシアの依頼を受けて蝦夷地を探査した"], "answer": 1, "modelAnswer": "", "explanation": "松浦武四郎は個人および幕府役人の立場で計6回蝦夷地を訪れ、複数の名称案を政府に提案し、その中から「北海道」の名が採用された。彼はアイヌに対する和人の非道な扱いを厳しく批判する記録も残している。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6654", "field": "近代", "difficulty": 3, "type": "choice", "question": "1879年の琉球処分と、その後の沖縄研究者伊波普猷について述べた文として誤っているものはどれか。", "choices": ["1879年、日本政府は琉球王国を廃し沖縄県を設置した", "伊波普猷は沖縄学の代表作として『古琉球』を著した", "伊波普猷は琉球処分を一種の奴隷解放という性格を持つものと捉えた", "伊波普猷は本土とは異なる沖縄独自の文化的価値を否定した", "伊波普猷は沖縄県立図書館に勤務した経歴を持つ"], "answer": 3, "modelAnswer": "", "explanation": "伊波普猷はむしろ本土とは異なる沖縄の「ユニークネス」の重要性を指摘しており、独自の文化的価値を否定したわけではない。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6655", "field": "近世", "difficulty": 4, "type": "choice", "question": "18世紀に琉球王府の政治家蔡温が起草し、琉球王府が発布した文書「御教条」について述べた文として正しいものはどれか。", "choices": ["御教条は薩摩藩主の権威を否定する内容であった", "御教条は琉球の人々に対し、統治者である薩摩藩への恩義を説く内容を含んでいた", "御教条は琉球王国が中国の冊封を拒否する方針を示した文書である", "御教条は明治政府による沖縄県設置を正当化するために作成された", "御教条は琉球処分後に作成された"], "answer": 1, "modelAnswer": "", "explanation": "「御教条」第1条は、琉球を統治する大名(薩摩藩)の厚恩を強調する内容であり、統治者への恭順を説くものであった。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6656", "field": "近世", "difficulty": 2, "type": "truefalse", "question": "シーボルト事件は、日本地図の国外持ち出しが発覚し、シーボルトが国外追放処分となった事件である。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "1828年、ドイツ人医師シーボルトが帰国に際し国外持ち出し禁止の日本地図(伊能図)などを所持していたことが発覚し、国外追放処分となった。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6657", "field": "近代", "difficulty": 3, "type": "choice", "question": "松方正義の財政政策(松方財政)について述べた文として誤っているものはどれか。", "choices": ["紙幣の一部を消却するデフレーション政策を進めた", "増税とデフレ政策が重なり、激しい不況(松方デフレ)を招いた", "松方財政によって蓄積された正貨をもとに、日本は金本位制を確立した", "松方正義の建議に基づき日本銀行が設立された", "松方財政によって物価が騰貴し、庶民は困窮に陥った"], "answer": 4, "modelAnswer": "", "explanation": "松方財政はデフレーション政策であり物価は下落した。物価騰貴により庶民が困窮したとする記述は事実と逆であり誤り。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6658", "field": "近代", "difficulty": 3, "type": "choice", "question": "1911年に制定された工場法について述べた文として正しいものはどれか。", "choices": ["資本家の強い支持のもとに制定が進められた", "適用対象は常時15人以上の職工を使用する工場に限られた", "制定と同時に即座に施行され、猶予期間は設けられなかった", "女性・年少者の深夜業は例外なく全面的に禁止された", "労働組合の結成を積極的に奨励する内容を含んでいた"], "answer": 1, "modelAnswer": "", "explanation": "工場法は常時15人以上の職工を使用する工場を適用対象とし、資本家の反対もあって施行は1916年まで持ち越された。保護規定にも期限付きで深夜業を認めるなど不十分な内容であった。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6659", "field": "近代", "difficulty": 2, "type": "truefalse", "question": "1918年の米騒動は富山県の主婦らの行動をきっかけに全国に波及し、鎮圧後、責任を取って寺内内閣は総辞職した。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "シベリア出兵を見越した米の買い占めなどにより米価が高騰し、富山県で始まった米騒動は全国に波及した。軍隊により鎮圧されたが、責任を問われた寺内正毅内閣は総辞職した。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6660", "field": "現代", "difficulty": 3, "type": "choice", "question": "第二次世界大戦後の財閥解体について述べた文として誤っているものはどれか。", "choices": ["GHQは1945年11月、三井・三菱・住友・安田の4財閥の解体を命じた", "1947年に独占禁止法が制定され、持株会社やカルテル・トラストが禁止された", "過度経済力集中排除法によって巨大企業の分割が行われることになった", "財閥解体は財閥家族による経営支配の強化を目的として行われた", "財閥は軍国主義の温床になっていたとGHQにみなされた"], "answer": 3, "modelAnswer": "", "explanation": "財閥解体はGHQが財閥家族による経営支配を解体することを目的として行われたものであり、支配の強化を目的としたとする記述は誤り。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6661", "field": "現代", "difficulty": 4, "type": "essay", "question": "1948年にGHQが日本政府に指示した経済安定九原則と、それを実行させるために翌年招かれた人物による一連の施策が招いた結果について、漢字4字のキーワードを含めて30字以内で説明せよ。句読点も1字として数えよ。", "choices": [], "answer": "", "modelAnswer": "ドッジ=ラインの結果、安定恐慌と呼ばれる深刻な不況が生じた。", "explanation": "経済安定九原則の実行のため招かれたドッジは、超均衡予算などのドッジ=ラインを実施し、猛烈なインフレを収束させたが、その反動で「安定恐慌」と呼ばれる深刻な不況が生じ、中小企業の倒産や失業者増加を招いた。（商学部2025年で問われた論点）", "source": "2025", "faculty": "商学部"},
  {"id": "q6680", "field": "古代", "difficulty": 3, "type": "choice", "question": "斉明天皇の時代に日本海方面から北方の蝦夷への遠征を行った人物として正しいものはどれか。", "choices": ["和気清麻呂", "阿倍比羅夫", "坂上田村麻呂", "文室綿麻呂", "紀古佐美"], "answer": 1, "modelAnswer": "", "explanation": "阿倍比羅夫は斉明天皇の時代(658~660年頃)に日本海側から水軍を率いて北方に遠征し、蝦夷や粛慎と接触したことが『日本書紀』に記されている。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6681", "field": "古代", "difficulty": 3, "type": "short", "question": "大化改新後、現在の新潟県域に設置された城柵のうち、渟足柵とともに設けられたもう一つの城柵の名を答えよ。", "choices": [], "answer": "磐舟柵", "modelAnswer": "磐舟柵", "explanation": "大化改新後、越後方面には渟足柵とともに磐舟柵が設置され、北方の蝦夷との接触の拠点となった。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6682", "field": "古代", "difficulty": 3, "type": "choice", "question": "出羽国の成立過程について述べた文として正しいものはどれか。", "choices": ["708年にまず越後国内に出羽郡が建てられ、712年に出羽国として独立した", "出羽国は大化改新の直後に建てられた", "出羽国は陸奥国から分離して成立した", "出羽国建置と同時に秋田城が築かれた", "出羽国は蝦夷との戦争が完全に終結した後に成立した"], "answer": 0, "modelAnswer": "", "explanation": "708年に越後国内に出羽郡が建てられ、712年には越後国から出羽郡を分離・独立させる形で出羽国が建てられ、陸奥国最上郡・置賜郡も出羽国に移管された。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6683", "field": "古代", "difficulty": 3, "type": "choice", "question": "陸奥・出羽の支配拠点として築かれた城柵について述べた文として誤っているものはどれか。", "choices": ["多賀城は太平洋側に築かれ、陸奥国の国府が置かれた", "秋田城は日本海側に築かれ、出羽国の支配拠点となった", "多賀城は蝦夷に対する軍事拠点であるとともに、朝貢する蝦夷への饗宴の場でもあった", "秋田城には陸奥国府が置かれた", "城柵は行政・軍事の中心として機能した"], "answer": 3, "modelAnswer": "", "explanation": "陸奥国府として機能したのは多賀城であり、秋田城は出羽国の支配拠点である。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6684", "field": "古代", "difficulty": 4, "type": "choice", "question": "758年に陸奥国桃生城・出羽国雄勝城の造営が開始された背景について述べた文として正しいものはどれか。", "choices": ["この時期は藤原仲麻呂が政権を握っており、祖父藤原不比等を意識した積極的な政策の一環であった", "この時期は橘諸兄政権下であり、蝦夷との融和策の一環であった", "この時期は蝦夷の反乱が頻発しており、防戦のためやむなく築かれた", "桃生城・雄勝城は平城京防衛のために築かれた", "この造営は聖武天皇の主導によるものであった"], "answer": 0, "modelAnswer": "", "explanation": "桃生城・雄勝城の造営が始まった時期は藤原不比等の死後、藤原仲麻呂が政権を確立した頃にあたり、仲麻呂は祖父不比等を強く意識した政策を進めており、積極的な東北経営もその一環であった。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6685", "field": "古代", "difficulty": 3, "type": "choice", "question": "774年から9世紀初めまで断続した律令国家と蝦夷との戦争(いわゆる東北三十八年戦争)について述べた文として誤っているものはどれか。", "choices": ["774年、蝦夷の反乱と桃生城襲撃を契機に戦争が開始された", "780年には伊治呰麻呂が反乱を起こし、多賀城を焼き払った", "阿弖流為は蝦夷側の指導者として律令国家軍と戦った", "この戦争は805年の徳政相論を経てただちに完全に終息し、以後蝦夷との衝突は一切生じなかった", "戦争の長期化は律令国家の財政や民衆に大きな負担を強いた"], "answer": 3, "modelAnswer": "", "explanation": "805年の徳政相論により対蝦夷戦争打ち切りの方針が示されたが、これは大規模な軍事行動を終了させる政策転換を意味するにとどまり、以後蝦夷との衝突が皆無になったとまでは言い切れない。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6686", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "805年の徳政相論では藤原緒嗣と菅野真道が論争し、緒嗣の主張により対蝦夷戦争(軍事)と平安京造営(造作)の停止が桓武天皇によって採用された。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "805年、桓武天皇の前で行われた徳政相論において、藤原緒嗣は軍事(蝦夷征討)と造作(平安京造営)が民を苦しめていると主張し、菅野真道の反論を退けて緒嗣の意見が採用された。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6687", "field": "中世", "difficulty": 3, "type": "choice", "question": "1232年に制定された御成敗式目に規定された守護の職掌について述べた文として正しいものはどれか。", "choices": ["守護の職掌は大番催促・謀叛人および殺害人の検断(大犯三カ条)に限定するとされた", "守護は国司に代わって一国の徴税権を全面的に掌握するとされた", "守護は荘園・公領の年貢徴収権を持つとされた", "守護は地頭の任免権を持つとされた", "守護は自由に代官を郡郷に配置し、公事を庄保に賦課することが公認された"], "answer": 0, "modelAnswer": "", "explanation": "御成敗式目第3条は、守護の職掌を大番催促・謀叛人と殺害人の検断(大犯三カ条)に限ることを定め、代官を郡郷に分かち補し国務を妨げるような行為は違法とした。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6688", "field": "中世", "difficulty": 3, "type": "choice", "question": "1221年の承久の乱について述べた文として誤っているものはどれか。", "choices": ["後鳥羽上皇は北条義時追討を名目に兵をあげた", "乱後、京都に新たに六波羅探題が設置された", "乱後、後鳥羽上皇の子である仲恭天皇は即位からわずかで廃位された", "乱の後、後鳥羽上皇は隠岐に配流された", "乱の背景には、上皇が皇子を将軍に推す交渉が不調に終わったことがある"], "answer": 2, "modelAnswer": "", "explanation": "仲恭天皇は後鳥羽上皇の孫(順徳天皇の子)であり、子ではない。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6689", "field": "中世", "difficulty": 2, "type": "short", "question": "承久の乱後、初代六波羅探題をつとめ、後に幕府の連署に就任した北条義時の弟は誰か。", "choices": [], "answer": "北条時房", "modelAnswer": "北条時房", "explanation": "北条時房は北条義時の弟で、承久の乱後に初代六波羅探題(北方)をつとめ、後に幕府初の連署に就任した。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6690", "field": "中世", "difficulty": 3, "type": "choice", "question": "御成敗式目制定以後の鎌倉幕府に関する出来事について述べた文として正しいものはどれか。", "choices": ["引付衆の設置は宝治合戦よりも前に行われた", "宝治合戦で北条氏は有力御家人三浦氏を滅ぼした", "宗尊親王の将軍就任は御成敗式目制定より前のことである", "引付衆は御家人同士の所領争いの裁判とは無関係の機関である", "宝治合戦の後、北条時頼は失脚した"], "answer": 1, "modelAnswer": "", "explanation": "1247年の宝治合戦で北条時頼は有力御家人三浦泰村一族を滅ぼした。引付衆の設置は1249年で宝治合戦の後、宗尊親王の将軍就任は1252年でさらにその後のことである。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6691", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸時代の大名家における「奥向き」について述べた文として誤っているものはどれか。", "choices": ["奥向きとは将軍・大名の生活空間であり、政務を行う表向きに対する語である", "大奥に勤める女中が表向きの政治に関与することは幕府の法度で禁じられていた", "大奥を通じた仲介によって大名家の養子縁組や家格上昇が図られることがあった", "女性は奥向きにおいても一切政治的な話題に関与しなかった", "大名家からの要望は表向きのルートのほか、奥向きのルートを通じても幕府に伝えられることがあった"], "answer": 3, "modelAnswer": "", "explanation": "大奥女中が「おもてむきの御用」に関わることは法度で禁止されていたにもかかわらず、実際には大奥を通じた仲介など、女性が政治に関与する場面があったことが史料からうかがえる。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6692", "field": "近世", "difficulty": 2, "type": "choice", "question": "江戸時代に即位した女性天皇として正しいものはどれか。", "choices": ["推古天皇", "持統天皇", "明正天皇", "孝謙天皇", "元明天皇"], "answer": 2, "modelAnswer": "", "explanation": "明正天皇は後水尾天皇の皇女で、江戸時代前期(1629年即位)に即位した女性天皇である。他の選択肢はいずれも江戸時代以前の女性天皇である。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6693", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "薩摩藩主島津重豪は蘭学に傾倒し、藩の借金を事実上帳消しにする形で商人に認めさせるなどの藩政改革を行った。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "島津重豪は蘭学を好んで奨励し、後の藩政改革では調所広郷らにより藩の借金を実質的に踏み倒す形の財政再建策がとられた。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6694", "field": "近世", "difficulty": 3, "type": "choice", "question": "老中水野忠邦が主導した天保の改革について述べた文として誤っているものはどれか。", "choices": ["物価騰貴の抑制を目的として株仲間の解散を命じた", "江戸・大坂周辺の直轄地化を図る上知令を出したが、大名・旗本の反対で撤回された", "人返しの法により農民の江戸流入を防ごうとした", "上知令の失敗などにより幕府権威は失墜し、水野忠邦は失脚した", "株仲間の解散によって商品流通は円滑化し、物価は速やかに沈静化した"], "answer": 4, "modelAnswer": "", "explanation": "株仲間の解散はかえって流通ルートを混乱させるなど、物価騰貴の背景には他の要因もあり、意図した効果は得られなかった。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6695", "field": "近代", "difficulty": 3, "type": "choice", "question": "1874年に政府へ提出された民選議院設立建白書について述べた文として正しいものはどれか。", "choices": ["建白書はイギリス人が創刊した日本語新聞『日新真事誌』に掲載された", "建白書は板垣退助単独の名で提出された", "建白書の提出直後、政府内でこれに反対する意見は皆無であった", "建白書提出を機に加藤弘之が国会開設の推進派として板垣に同調した", "建白書は自由党結成と同時に提出された"], "answer": 0, "modelAnswer": "", "explanation": "民選議院設立建白書は板垣退助ら8名が連署して政府に提出し、イギリス人ブラックが創刊した日本語新聞『日新真事誌』に掲載されて世論の注目を集めた。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6696", "field": "近代", "difficulty": 3, "type": "choice", "question": "民選議院設立建白書に反駁書を送るなど時期尚早論を唱えた学者加藤弘之について述べた文として誤っているものはどれか。", "choices": ["天賦人権論を日本に紹介する著作を著したことがある", "明六社の社員であった", "のちに優勝劣敗を原理とする社会進化論の立場から天賦人権論を否定する立場に転じた", "国会開設そのものに絶対反対の立場をとり続けた", "独逸学協会学校の初代校長を務めた"], "answer": 3, "modelAnswer": "", "explanation": "加藤弘之は国会開設の時期尚早論を唱えたのであって、国会開設そのものに絶対反対だったわけではない。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6697", "field": "近代", "difficulty": 3, "type": "choice", "question": "1875年の大阪会議の結果について述べた文として正しいものはどれか。", "choices": ["立法諮問機関として元老院が設置された", "大久保利通・板垣退助・西郷隆盛の三者が妥協した", "会議の結果、地方官会議は廃止された", "会議の結果、板垣退助は政府への復帰を拒み続けた", "会議を機に大審院に代わり最高裁判所が新設された"], "answer": 0, "modelAnswer": "", "explanation": "大阪会議では大久保利通・木戸孝允・板垣退助が妥協し、立法諮問機関としての元老院、司法機関としての大審院、地方官会議の開催が約束され、木戸・板垣は政府に復帰した。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6698", "field": "近代", "difficulty": 2, "type": "short", "question": "1870年に渡米し、ナショナル・バンク制度に学んで日本政府に金本位制と国立銀行制度の導入を建議した人物は誰か。", "choices": [], "answer": "伊藤博文", "modelAnswer": "伊藤博文", "explanation": "大蔵少輔であった伊藤博文は1870年に財政・金融制度調査のため渡米し、アメリカのナショナル・バンク制度をもとに金本位制の採用と国立銀行制度の導入を建議した。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6699", "field": "近代", "difficulty": 3, "type": "choice", "question": "1927年の金融恐慌について述べた文として誤っているものはどれか。", "choices": ["震災手形の処理法案審議の過程で銀行の経営不安が表面化した", "若槻礼次郎内閣は緊急勅令によって台湾銀行を救済しようとしたが、枢密院の了承を得られず総辞職した", "台湾銀行は内地支店の休業に追い込まれ、取り付け騒ぎが全国の銀行に広がった", "次に成立した田中義一内閣は全国の銀行を2日間休業させ、3週間のモラトリアムを発した", "恐慌は日本銀行からの融資を一切受けずに沈静化した"], "answer": 4, "modelAnswer": "", "explanation": "田中義一内閣は日本銀行から巨額の緊急融資を行わせることで事態を沈静化させており、「融資を一切受けずに」とする記述は誤り。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6700", "field": "現代", "difficulty": 3, "type": "choice", "question": "第二次世界大戦後の政党復活について述べた文として誤っているものはどれか。", "choices": ["1945年10月、GHQの指令で出獄した徳田球一らを中心に日本共産党が合法政党として活動を再開した", "日本社会党・日本自由党・日本進歩党が1945年11月に結成された", "新選挙法の制定により、満20歳以上の成人男女に選挙権が与えられた", "1946年4月の総選挙では女性議員は1人も誕生しなかった", "日本協同党は後に協同民主党を経て国民協同党となった"], "answer": 3, "modelAnswer": "", "explanation": "1946年4月の戦後初の総選挙では女性参政権行使のもと、多数の女性議員が誕生した。したがって「女性議員は1人も誕生しなかった」とする記述は誤り。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"},
  {"id": "q6701", "field": "現代", "difficulty": 4, "type": "essay", "question": "戦後復興期に採用された、資材と資金を石炭・鉄鋼などの重要産業部門に集中する政策の名称を漢字6字で挙げ、その方式が導入された目的を30字以内で説明せよ。句読点も1字として数えよ。", "choices": [], "answer": "", "modelAnswer": "傾斜生産方式。資金と資材を石炭・鉄鋼に集中し生産の好循環を生むため。", "explanation": "傾斜生産方式は、経済安定本部のもとで乏しい資金・資材を石炭・鉄鋼など基幹産業に重点配分し、生産の好循環を生み出して復興を図る政策であった。復興金融金庫からの融資はのちに復金インフレを招いた。（商学部2026年で問われた論点）", "source": "2026", "faculty": "商学部"}
];
